-- Poems batch 89
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('551e84ad-f3ef-4632-9e9a-8b9b8a8a0e4c','接待贈相送諸公','曹勛','宋','宋诗','song-poetry','','[]','曉隨幽徑踏行雲，拄頰南山眼界新。',64,'全唐诗/poet.song.109000.json','["曉隨幽徑踏行雲，拄頰南山眼界新。", "馬上客塵良自笑，山中梅意欲驚春。", "清愁有底能隨酒，世道何方可問津。", "頼有諸公同一笑，得舒軟語話情親。"]'),
('785b950c-12f5-46dc-bfda-fefd269fdcc2','黄侍郎宮祠贈行','曹勛','宋','宋诗','song-poetry','','[]','無雙佳譽久騰芳，暫解繁機下帝旁。',64,'全唐诗/poet.song.109000.json','["無雙佳譽久騰芳，暫解繁機下帝旁。", "舉世不能容直道，清時聊欲款江鄉。", "脩涂按轡三秋雨，別殿陪祠一炷香。", "顧我辱知門下久，語離清淚灑滄浪。"]'),
('d3975f21-54a9-4c09-b443-5c2a5356c211','與曾侍郎','曹勛','宋','宋诗','song-poetry','','[]','里巷風和遞曉騶，高軒見顧識英猷。',64,'全唐诗/poet.song.109000.json','["里巷風和遞曉騶，高軒見顧識英猷。", "揮犀唾玉聞鄉語，對酒看花話舊游。", "殊喜故家青玉案，方承大問翠雲裘。", "願持相業天鈞上，箕潁重爲第一流。"]'),
('24bea301-43ce-4a43-89c4-3eb29787d4c5','與李先生學士','曹勛','宋','宋诗','song-poetry','','[]','先生聲徹大明宮，顧肯馳驅與俗同。',64,'全唐诗/poet.song.109000.json','["先生聲徹大明宮，顧肯馳驅與俗同。", "但得琴書娛白日，何須鞭帽犯朝風。", "未容倦客尋源去，應謂斯人底死窮。", "它日雲林陪杖屨，款承願輩囁嚅翁。"]'),
('f736c34e-9d6b-41ab-b450-8154a0e3c8be','送趙安定弭節三衢','曹勛','宋','宋诗','song-poetry','','[]','茅土真封輔帝畿，天潢近派冠彤墀。',64,'全唐诗/poet.song.109000.json','["茅土真封輔帝畿，天潢近派冠彤墀。", "當機久契拈花笑，示病何勞闔國追。", "北闕暫違文石陛，西風正是菊花時。", "瘦筇短褐他年去，洗雨濛烟訪習池。"]'),
('1239ff8b-ed32-440e-a733-95de39d712b9','送王制置帥成都','曹勛','宋','宋诗','song-poetry','','[]','從來吳蜀勢相親，制閫今勤侍帝臣。',64,'全唐诗/poet.song.109000.json','["從來吳蜀勢相親，制閫今勤侍帝臣。", "可但覆甌稱直道，暫煩分陝濟斯民。", "劍關日下山河重，井絡天開號令新。", "聖主遂寬西顧念，遨頭正及錦江春。"]'),
('a945a793-0d2a-4b59-a36f-0384f5b9c31c','送子威兄歸邵武','曹勛','宋','宋诗','song-poetry','','[]','閩浙相望一寸心，鴒原落寞歎孤音。',64,'全唐诗/poet.song.109000.json','["閩浙相望一寸心，鴒原落寞歎孤音。", "五年情話空相憶，千里閑門肯見尋。", "只擬連牀常對語，豈堪垂老更分襟。", "它時果許鄰幽築，莫倦天台塵土深。"]'),
('776bf4fe-8370-4e40-842f-969a78e49819','送鄭吏部出使二首  其一','曹勛','宋','宋诗','song-poetry','','[]','聖主東南眷念勞，繡衣行部輟名曹。',64,'全唐诗/poet.song.109000.json','["聖主東南眷念勞，繡衣行部輟名曹。", "喜尋物外人多竺，應遇山中相有陶。", "丹筆不摇吟筆健，頹風頓革古風高。", "如何大展安邦手，勿使鯨鯢弄海濤。"]'),
('a9aa7120-728a-4d9e-a422-bd9543594b0c','送鄭吏部出使二首  其二','曹勛','宋','宋诗','song-poetry','','[]','生靈塗炭帝興憐，攬轡公應願著鞭。',64,'全唐诗/poet.song.109000.json','["生靈塗炭帝興憐，攬轡公應願著鞭。", "禹貢山川仍舊貫，漢時戶口失殘編。", "交征夷夏疑非古，積弊公私不記年。", "且乞韓州風信好，二君歸計託樓船。"]'),
('89aa6251-786c-446d-9003-6d2df096500b','送謝景思從辟督府二首  其一','曹勛','宋','宋诗','song-poetry','','[]','乘傳逆知懷抱開，壁門春晚靜塵埃。',64,'全唐诗/poet.song.109000.json','["乘傳逆知懷抱開，壁門春晚靜塵埃。", "萱明子舍雖云樂，檄愈頭風得屢催。", "橫槊便知威黠虜，指蹤端復頼長才。", "維持江左風流在，富貴行看正鼎來。"]'),
('69dd8954-735e-4109-8871-b45f36a0e486','送謝景思從辟督府二首  其二','曹勛','宋','宋诗','song-poetry','','[]','艱壘師行遂坦夷，中興仍待老文辭。',64,'全唐诗/poet.song.109000.json','["艱壘師行遂坦夷，中興仍待老文辭。", "上公固已虛油幕，碩畫旋看贊鼎司。", "氣隔龍荒朝隴蜀，令嚴虎旅肅旌麾。", "風聲鶴唳天威振，會見棋餘折屐時。"]'),
('ecd2e247-be8f-4f58-a708-e709e6f44d89','送子芬年家之官越上','曹勛','宋','宋诗','song-poetry','','[]','清潤丰姿玉不瑕，篇章典重見詞華。',64,'全唐诗/poet.song.109000.json','["清潤丰姿玉不瑕，篇章典重見詞華。", "韜鈐小試諸侯幕，事業共稱丞相家。", "蓬閣晝長宜笑詠，山陰春早已鶑花。", "鳳池自是風流在，行見金門帽带斜。"]'),
('b9d3cea7-1ab5-4074-a8a4-b99bd9ddbf09','送人倅潮陽','曹勛','宋','宋诗','song-poetry','','[]','情文俱至接交親，折節如君未有鄰。',64,'全唐诗/poet.song.109000.json','["情文俱至接交親，折節如君未有鄰。", "垂棒不妨希孟德，榮親當復比安仁。", "碧雲斜日羊山路，黄葉西風鱷水濱。", "嗟我殊鄉遠良友，尚堪病眼看征輪。"]'),
('2483262c-7e34-4914-b4e8-4854d9f3e143','送丁致遠司理','曹勛','宋','宋诗','song-poetry','','[]','苕溪霅水接雲沙，秀氣全鍾化鶴家。',64,'全唐诗/poet.song.109000.json','["苕溪霅水接雲沙，秀氣全鍾化鶴家。", "三語固知油幕近，八吟不覺石渠賒。", "庭親戲綵心應悅，路近乘槎梅已花。", "一意相期升館殿，三年倚玉愧蒹葭。"]'),
('cddef820-e866-45b0-ad4e-d707253573de','送表弟丘彥澤失官之潮','曹勛','宋','宋诗','song-poetry','','[]','此身江海一浮漚，遇坎乘流莫預謀。',64,'全唐诗/poet.song.109000.json','["此身江海一浮漚，遇坎乘流莫預謀。", "萊子奉親真是樂，塞翁失馬定無憂。", "關山照眼長安近，裘褐生香鱷水秋。", "隠忍功名丈夫事，行知富貴自相求。"]'),
('161bae0d-d433-4a54-817d-430bb8b46bf8','送楊子寬還臨安寄錢處和','曹勛','宋','宋诗','song-poetry','','[]','送客天台不上船，東風款段喜揚鞭。',64,'全唐诗/poet.song.109000.json','["送客天台不上船，東風款段喜揚鞭。", "山容閣雪曉猶冷，花色烘雲春正妍。", "壠上麥芒猶綠嫩，枝間梅子漸青圓。", "有懷閣老應詩罷，盡捲珠簾按管絃。"]'),
('b2314b7f-05fc-428f-b03a-64e2ae1fa7b5','送懷英訪廬山','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','台嶽相逢麋鹿墟，識公風骨秀而癯。',64,'全唐诗/poet.song.109000.json','["台嶽相逢麋鹿墟，識公風骨秀而癯。", "山林訪道誠多切，雲水期真進所如。", "爐鼎丹砂知煉己，關河霜霰不妨渠。", "它時應有衡陽雁，莫忘南來一紙書。"]'),
('8b89d5ed-2709-4daa-bff7-5079908eacd0','送張沖舉先生還山','曹勛','宋','宋诗','song-poetry','','[]','道人丰骨出埃塵，玉頰雙紅爛熳春。',64,'全唐诗/poet.song.109000.json','["道人丰骨出埃塵，玉頰雙紅爛熳春。", "金液密傳張果老，黄庭曾授赤明民。", "秋來行李林泉好，雨後雲山意氣新。", "顧我年華已垂盡，餘齡薪水願相親。"]'),
('3cacca31-2ca3-489b-a08d-6867d6368960','送王道錄桐柏住庵二首  其一','曹勛','宋','宋诗','song-poetry','','[]','早覺人間萬事非，便尋幽遠凈征衣。',64,'全唐诗/poet.song.109000.json','["早覺人間萬事非，便尋幽遠凈征衣。", "每嗟老境難辭老，政使歸時未得歸。", "物外無思皆妙道，塵中有患更危機。", "羨君行李翩然去，瓊闕從茲兩子微。"]'),
('e22f4235-773d-496b-b9d4-58610a71bb18','送王道錄桐柏住庵二首  其二','曹勛','宋','宋诗','song-poetry','','[]','見說當年夢甚真，公今高步挹清塵。',64,'全唐诗/poet.song.109000.json','["見說當年夢甚真，公今高步挹清塵。", "經傳桐柏兼三洞，名在明廷接萬神。", "馬過越山資浩氣，花飛剡水正殘春。", "白雲二友皆仙士，晤語多應一笑頻。"]'),
('e89f671e-c328-478e-9133-37dbce1e8936','送張才甫知池陽','曹勛','宋','宋诗','song-poetry','','[]','頻向長亭折柳枝，客中送客動愁思。',64,'全唐诗/poet.song.109000.json','["頻向長亭折柳枝，客中送客動愁思。", "未論蓮社重分袂，第喜牙璋再把麾。", "旁塞兵民須舊德，長淮風月待新詩。", "行看紫詔求耆宿，正是霜天清曉時。"]'),
('b948d039-8d7b-42cf-9b99-b3dc95d17510','送人游福唐','曹勛','宋','宋诗','song-poetry','','[]','蘿月溪雲各未闌，它時薪水肯相安。',64,'全唐诗/poet.song.109000.json','["蘿月溪雲各未闌，它時薪水肯相安。", "家依梵剎鐘磬靜，路近台山松桂寒。", "橫槊勝流公遠詣，觀瀾逸興我難看。", "歸時一棹宜須早，趁取薰風荔子丹。"]'),
('77d935fd-6668-46d2-8066-538788efd290','送別曹封叔','曹勛','宋','宋诗','song-poetry','','[]','華宗丰度藹長雲，一笑相逢契懶真。',64,'全唐诗/poet.song.109000.json','["華宗丰度藹長雲，一笑相逢契懶真。", "豈但金蘭如舊分，固應俞扁是前身。", "久爲輦轂緇塵客，欲趁龍園茗碗春。", "顧我華顛今放跡，水邊林下願相親。"]'),
('4938be7f-7eac-452d-91a9-bfb6bea33819','久別黄虛中忽會又別二詩道意  其一','曹勛','宋','宋诗','song-poetry','','[]','汪汪陂量有家聲，文擅區中世典刑。',64,'全唐诗/poet.song.109000.json','["汪汪陂量有家聲，文擅區中世典刑。", "別去十年頭已白，相逢一日眼猶青。", "君裁短後姑假道，我訪內丹殊不經。", "蘿月風櫺傳古錦，無令簿領困周星。"]'),
('9329cc8b-20f8-4d8e-aa52-6ac20e6aaa78','久別黄虛中忽會又別二詩道意  其二','曹勛','宋','宋诗','song-poetry','','[]','蘋滿烟沙柳滿洲，綠荷風軟轉船頭。',64,'全唐诗/poet.song.109000.json','["蘋滿烟沙柳滿洲，綠荷風軟轉船頭。", "歸篷亟作恁麽去，許事肯令如是休。", "自有文章追洛下，莫緣譽處厭糟丘。", "君能坐致錢流地，行達通明十二旒。"]'),
('e8521b5e-692f-44d8-a664-e75a1d022003','送殿幹譙公暫歸莆田','曹勛','宋','宋诗','song-poetry','','[]','暫輟京塵擾擾間，一鞭行色冒春寒。',64,'全唐诗/poet.song.109000.json','["暫輟京塵擾擾間，一鞭行色冒春寒。", "梅花細雨資能賦，野水遥山好據鞍。", "引道頗聞辭魏闕，覓官况可近長安。", "掀髯西笑歸宜早，應及莆閩荔子丹。"]'),
('bfba9a54-caca-4e49-b4f6-86b37e9337f4','送錢處和知三衢','曹勛','宋','宋诗','song-poetry','','[]','忠孝傳芳在一門，雙旌光動小陽春。',64,'全唐诗/poet.song.109000.json','["忠孝傳芳在一門，雙旌光動小陽春。", "柯山瀫水聊均逸，石室龜峰定可人。", "紫詔密嘗符夙夢，朱轓果見撫斯民。", "故家未有如公者，自致勳名侍帝宸。"]'),
('acaa2bf9-e64f-401d-891e-678f2f2b0d51','和都運龍圖二首  其一','曹勛','宋','宋诗','song-poetry','','[]','一時耆舊盡英游，玉節迎鑾暫少休。',64,'全唐诗/poet.song.109000.json','["一時耆舊盡英游，玉節迎鑾暫少休。", "不以秦人視越瘠，載馳楚尾與吳頭。", "兩淮濃被鍾離政，一水聊縈杜若洲。", "行見鋒車還禁橐，已看仁化浹魚鷗。"]'),
('25d56d05-8ebb-4711-af4f-c089499c920c','和都運龍圖二首  其二','曹勛','宋','宋诗','song-poetry','','[]','老去心情故倦游，直誠自許賦休休。',64,'全唐诗/poet.song.109000.json','["老去心情故倦游，直誠自許賦休休。", "清流固已久絕望，白髮只今空滿頭。", "軟語每思揮玉麈，尋源便欲過瓜洲。", "他年一棹烟江雨，有愧輕輕不下鷗。"]'),
('c8ac76d0-2f30-4c96-9436-600360e7043b','和鄭康道二首  其一','曹勛','宋','宋诗','song-poetry','','[]','絕歎當年故作癡，水邊林下欲清非。',64,'全唐诗/poet.song.109000.json','["絕歎當年故作癡，水邊林下欲清非。", "未應阮籍涂窮慣，自是王通世念微。", "仗節舊聞英槩偉，挂冠惜與壯心違。", "起予徑辦從公物，一䩫芒鞋一衲衣。"]'),
('8bc50862-deb7-4931-9623-080d31bed4db','和鄭康道二首  其二','曹勛','宋','宋诗','song-poetry','','[]','耕隠春江水盡頭，一廛已自鄙通侯。',64,'全唐诗/poet.song.109000.json','["耕隠春江水盡頭，一廛已自鄙通侯。", "好辭遽作春半別，歸意欲兼天際流。", "我尚未栽三徑竹，君能先泛五湖舟。", "要來便作乘風客，莫使烟光有許愁。"]'),
('b1e17c3c-f8cf-4afa-a96c-c14c22400322','和謝景英提幹','曹勛','宋','宋诗','song-poetry','','[]','公家繡戶壓城垣，物采隨時入懶軒。',64,'全唐诗/poet.song.109000.json','["公家繡戶壓城垣，物采隨時入懶軒。", "人倚層樓風滿檻，江涵秋影月當門。", "賸聞薌淥羅襦麗，醉看金荷燭影昏。", "可但頹然信真率，亦思秀句得重論。"]'),
('d503aad8-2361-49f2-b0cd-eac06f42feb8','和穩上座','曹勛','宋','宋诗','song-poetry','','[]','與公緇素兩無成，世路低回窘墨繩。',64,'全唐诗/poet.song.109000.json','["與公緇素兩無成，世路低回窘墨繩。", "弱羽機繒懷畏避，孤根霜雪厭侵凌。", "未須神秀終齊雪，好囑維摩且判憑。", "喜讀師詩破塵坌，了如松雪拂人膺。"]'),
('a879f5a1-d2cf-4fde-b2e7-5adf56d21eec','和楊季廓解元','曹勛','宋','宋诗','song-poetry','','[]','下帷聞說盡英奇，賦就三都墨未醨。',64,'全唐诗/poet.song.109000.json','["下帷聞說盡英奇，賦就三都墨未醨。", "分比楚蘭同講學，文踰荆玉不遐遺。", "豹藏烟霧聊相與，蚌剖珠璣要及時。", "龍虎他年題淡墨，綠衣皂蓋看風姿。"]'),
('f1d2662b-1c9c-4974-a784-ca8d92e5125b','用前韻書田間晚步','曹勛','宋','宋诗','song-poetry','','[]','寓居蕭寺憇衰遲，得酒寧論濁與醨。',64,'全唐诗/poet.song.109000.json','["寓居蕭寺憇衰遲，得酒寧論濁與醨。", "閑裏風光常自喜，暑中人事棄如遺。", "一溪烟水漁鄉後，萬疊蒼山月上時。", "竹杖芒鞋田岸久，稻花細細歲豐姿。"]'),
('778e146d-ba73-40a0-8718-82ef2c9d817c','用前韻贈岸老','曹勛','宋','宋诗','song-poetry','','[]','年來學稼似樊遲，惟有農功每不醨。',64,'全唐诗/poet.song.109000.json','["年來學稼似樊遲，惟有農功每不醨。", "事與本心雖自適，病隨老境豈相遺。", "我方枕簟和雲住，公正風幡撇地時。", "林下相逢笑相領，一枝筇竹水雲姿。"]'),
('383c16a0-2c5f-46f7-b5aa-83f9e62a4958','和曾谹父光孝佳句','曹勛','宋','宋诗','song-poetry','','[]','使君幽討遍禪林，名動三台殿閣清。',64,'全唐诗/poet.song.109000.json','["使君幽討遍禪林，名動三台殿閣清。", "稍賦詩章回好色，坐令草木有佳聲。", "政須膏澤隨軒至，未礙隼旟衝雨行。", "爭寫雄文惟恐後，喜兼和氣滿重城。"]'),
('01426503-6e50-47ba-ab64-db565389eb61','和黄南嘉相賀','曹勛','宋','宋诗','song-poetry','','[]','賊馬憑凌勢怒號，鐵衣夜挂映征袍。',64,'全唐诗/poet.song.109000.json','["賊馬憑凌勢怒號，鐵衣夜挂映征袍。", "謹嚴甲士方超距，森索妖星絕繹騷。", "橫槊賦詩雖昔事，枕戈待旦敢徒勞。", "公詩一洗烟塵氣，媿甚橫行不鼓刀。"]'),
('eaee3b85-8f91-4eae-ab67-4facf5d05644','用錢夢弼韻送歸京口','曹勛','宋','宋诗','song-poetry','','[]','吾儕此道竟須伸，抱負堂堂况不倫。',64,'全唐诗/poet.song.109000.json','["吾儕此道竟須伸，抱負堂堂况不倫。", "每喜高才皆正論，異時公議有廷臣。", "落花流水方愁客，細雨輕寒不著人。", "且力韜鈐加强飯，未須俯首歎湮淪。"]'),
('79e307f8-3776-4475-8fb7-8864c360c4f7','和鄭國器來自江州道中之什','曹勛','宋','宋诗','song-poetry','','[]','聞道山爐一炷香，三餘常得寸心降。',64,'全唐诗/poet.song.109000.json','["聞道山爐一炷香，三餘常得寸心降。", "直須了取詩千首，始可閑期璧一雙。", "梅潤未能排絮帽，日陽只擬上雲窗。", "竚公納錫充前列，毋使遲遲出九江。"]'),
('71466400-08bd-44ef-8beb-117dbdcd44d3','和國器因以奉勉','曹勛','宋','宋诗','song-poetry','','[]','宿雲濃澹弄空明，桃李吹香雨屢經。',64,'全唐诗/poet.song.109000.json','["宿雲濃澹弄空明，桃李吹香雨屢經。", "燕識舊巢猶頡頏，枝駢新綠尚芳馨。", "力田須待年多黍，知病好尋參與苓。", "莫爲無家動鄉思，且籌傑論獻明廷。"]'),
('24ae2e8d-49cf-4506-b9a3-05ea6dc7d621','和鮑判院見寄二首  其一','曹勛','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','挂冠十載水雲鄉，忽奉新詩助發揚。',64,'全唐诗/poet.song.109000.json','["挂冠十載水雲鄉，忽奉新詩助發揚。", "老境不能尋汗漫，聖時欣服值虞唐。", "喜君均佚琳祠樂，愧我初無襪線長。", "它日林泉儻相覓，一蓑烟艇洞庭霜。"]'),
('6d873e18-d95d-4bd1-9c12-251b5614c33d','和鮑判院見寄二首  其二','曹勛','宋','宋诗','song-poetry','','[]','當年壯志作三軍，扳馬曾同幕下賓。',64,'全唐诗/poet.song.109000.json','["當年壯志作三軍，扳馬曾同幕下賓。", "欲試韜鈐毘廟算，便期鷹隼出風塵。", "暮年歲月嗟殘景，一水波濤有故人。", "端謂題輿因卜築，不應佳句尚悲辛。"]'),
('b3298a1c-1a08-4f66-89aa-0f006f5a5afa','次韻李漢老參政重陽前游泉州東湖','曹勛','宋','宋诗','song-poetry','','[]','郊亭十里繞風漪，一鑑光涵萬象微。',64,'全唐诗/poet.song.109000.json','["郊亭十里繞風漪，一鑑光涵萬象微。", "勝址幾年因事廢，遺芳今日識公歸。", "鳳山前直供晨翠，鯨海旁連漲夕暉。", "少並江湖魚釣樂，綠蓑青笠鱖魚肥。"]'),
('3ab00e62-093e-4e6b-aecd-e7e2409be593','用李參政韻并錄寄舟峰師四首  其一','曹勛','宋','宋诗','song-poetry','','[]','峙玉層氷瑩肺肝，秉鈞風節素巖巖。',64,'全唐诗/poet.song.109000.json','["峙玉層氷瑩肺肝，秉鈞風節素巖巖。", "交河諭旨師無戰，榆塞宣恩俗舊銜。", "成算已功休大樹，洞章詠志發幐緘。", "斯篇疾讀林宗意，快甚長風破浪帆。"]'),
('2f3f18b5-0f4a-4430-a11b-a14631cd56e1','用李參政韻并錄寄舟峰師四首  其二','曹勛','宋','宋诗','song-poetry','','[]','世間群盜膾人肝，避地方圖水石巖。',64,'全唐诗/poet.song.109000.json','["世間群盜膾人肝，避地方圖水石巖。", "客有綠林嗟路阻，書無黄耳欲何銜。", "雨推溪柳金方重，春入江梅玉半緘。", "永念陸趨今弗獲，垂雲安得倚天帆。"]'),
('1b054f6b-0e98-4f1e-95cf-561e0f554c6a','用李參政韻并錄寄舟峰師四首  其三','曹勛','宋','宋诗','song-poetry','','[]','昔年壯氣激腸肝，錦带吳鈎鄙隠巖。',64,'全唐诗/poet.song.109000.json','["昔年壯氣激腸肝，錦带吳鈎鄙隠巖。", "喜試輕裘裁白紵，笑追落日試重銜。", "愁隨草色人千里，誰附文期信一緘。", "會待腥膻掃巢穴，舳艫北首掛征帆。"]'),
('fc2335fc-0367-48b6-937a-7ade64cd66fd','用李參政韻并錄寄舟峰師四首  其四','曹勛','宋','宋诗','song-poetry','','[]','海色琉璃照我肝，何疑飛電掣晴巖。',64,'全唐诗/poet.song.109000.json','["海色琉璃照我肝，何疑飛電掣晴巖。", "山留畫鷁風從怒，珠炯翔龍夜亦銜。", "蓮社經徒能摘句，玉川茶興自開緘。", "從來筏喻今饒益，杯渡須知鄙鐵帆。"]'),
('4a1ad1fb-72aa-4ee0-a9c5-102107060112','用徐諫議韻上謝參政','曹勛','宋','宋诗','song-poetry','','[]','名傳蔡國冠儒林，二百年來慶澤深。',128,'全唐诗/poet.song.109000.json','["名傳蔡國冠儒林，二百年來慶澤深。", "同德允爲賢相法，醉經端向古人尋。", "稍提闕里西河意，盡掃桑間濮上音。", "行聽雨濛歌迅召，不應衮繡有遐心。", "力辭大政勳方著，均佚琳宮道益深。", "北闕嘉猷常簡在，東山春色寄幽尋。", "半言夙契三乘偈，一噫何妨萬竅音。", "賤子摳衣陪下士，天游六鑿已無心。"]'),
('d28d13aa-eeac-40c2-b9d0-c0cb8a6b66f5','贈丘執禮','曹勛','宋','宋诗','song-poetry','','[]','北客南來塵土甚，沿沂正欲泳清深。',64,'全唐诗/poet.song.109000.json','["北客南來塵土甚，沿沂正欲泳清深。", "舟行雲駛方求問，鶴怨猿驚不可尋。", "縫掖頗聞臨泮水，滄浪應許聽挐音。", "果容請問期先報，太歲何時合守心。"]'),
('11a68589-6b5a-487d-bd27-4997e1ca0338','秋懷','曹勛','宋','宋诗','song-poetry','','[]','胡騎連年頗內侵，胡塵漠漠翳高深。',64,'全唐诗/poet.song.109000.json','["胡騎連年頗內侵，胡塵漠漠翳高深。", "何當固趙如頗牧，遂佐興宛破邑尋。", "尚想鼓旂延大敵，要須風鶴有餘音。", "秋高馬健予方病，只有丹楓可照心。"]'),
('d951e224-62b8-4633-a617-910c67bbd6b8','約桑守公肅同還剡中','曹勛','宋','宋诗','song-poetry','','[]','生理空疏坐久閑，聊隨雲影下吳山。',64,'全唐诗/poet.song.109000.json','["生理空疏坐久閑，聊隨雲影下吳山。", "驅馳斗粟應憐我，勉强人情亦厚顔。", "濁酒淳漓元不較，梅花的皪欲同攀。", "行行小艇撐寒碧，剡夜無妨共載還。"]'),
('4d128c77-2f9b-4c1f-b38c-ba2af34e8096','張叔廣索近詩輒爲短韻','曹勛','宋','宋诗','song-poetry','','[]','咫尺高齋未一嬉，病身坐苦廢巫醫。',64,'全唐诗/poet.song.109000.json','["咫尺高齋未一嬉，病身坐苦廢巫醫。", "但能料理扶衰藥，豈復狂吟亂道詩。", "秋熱正隨殘暑熾，新凉如與故人期。", "唯應共此江蟾白，萬頃風漪月上時。"]'),
('199fc6d4-8c6e-4bfd-9c2f-c41906fbb80b','休致後效樂天體','曹勛','宋','宋诗','song-poetry','','[]','從來受性豈其天，遇物常隨處處緣。',64,'全唐诗/poet.song.109000.json','["從來受性豈其天，遇物常隨處處緣。", "未病遽爲辭職去，欲歸亟引挂冠年。", "冒寒須放尋梅步，更窘常留買藥錢。", "恩許天台遂幽築，清風一棹送歸船。"]'),
('a342c51f-35bb-4ffd-a693-1317341659ab','和蔡瞻明知府','曹勛','宋','宋诗','song-poetry','','[]','公才祇合在瀛洲，一笑何能欲枕流。',64,'全唐诗/poet.song.109000.json','["公才祇合在瀛洲，一笑何能欲枕流。", "日者簡書成六鑿，天其盤錯到三休。", "欄干靜倚江濤闊，舟楫冷摇煙雨秋。", "大手家風傳相業，高情莫易攪清愁。"]'),
('8b7966a3-0206-4264-84e1-2844dd4aa864','用前韻言歸','曹勛','宋','宋诗','song-poetry','','[]','梅風欲轉白蘋洲，一笑忘懷接勝流。',64,'全唐诗/poet.song.109000.json','["梅風欲轉白蘋洲，一笑忘懷接勝流。", "公已吉祥求止止，我方奔走覓休休。", "故山應有猿鶴怨，壯節但隨蒲柳秋。", "薦讀公詩固三歎，從今可但破牢愁。"]'),
('56fed635-ef65-4a3d-8896-29870d0a8ba5','和張直講','曹勛','宋','宋诗','song-poetry','','[]','老境從遠事事慵，却尋幽剎寄年豐。',64,'全唐诗/poet.song.109000.json','["老境從遠事事慵，却尋幽剎寄年豐。", "本無虛舍能回暑，頼有疏篁可致風。", "臭腐固嘗忘物化，簞瓢寧復較天窮。", "向來習氣端如故，經醉猶能間一中。"]'),
('ae7239d4-f031-4141-b7fd-573ccd9dbdde','和楚守于伯達','曹勛','宋','宋诗','song-poetry','','[]','平生聞說于門貴，遠業傳家見此賢。',64,'全唐诗/poet.song.109000.json','["平生聞說于門貴，遠業傳家見此賢。", "妙譽逐風來不竟，美才製錦諒隨緣。", "一言悟主君須得，百巧成窮我可憐。", "坐想臨平山下路，小舟如葉月如川。"]'),
('2815376a-3cce-4792-9bc8-8a84dd699aa0','和台州衛倅','曹勛','宋','宋诗','song-poetry','','[]','昔日連牆事可嘉，固應屢見雪中花。',64,'全唐诗/poet.song.109000.json','["昔日連牆事可嘉，固應屢見雪中花。", "稍收帢幘山房景，欲學孤山處士家。", "把酒要陪高士醉，臨風未覺此心遐。", "銷閑只與山爲伴，坐數比鄰再及瓜。"]'),
('5b698093-0c85-4ab6-ab85-0bcc418afdee','和黄虛中韻二首  其一','曹勛','宋','宋诗','song-poetry','','[]','昔時意氣控雲霄，老矣方能造治朝。',64,'全唐诗/poet.song.109000.json','["昔時意氣控雲霄，老矣方能造治朝。", "一日暫違文石陛，十年空採越山樵。", "歌傳楚些聊供醉，鬢點吳霜未肯銷。", "三歎公詩話京洛，起予鄉思欲扶摇。"]'),
('c456c55c-4e46-40c7-bd32-9073b5c012d9','和黄虛中韻二首  其二','曹勛','宋','宋诗','song-poetry','','[]','喜見丰姿眼倍明，從來事事勝公榮。',64,'全唐诗/poet.song.109000.json','["喜見丰姿眼倍明，從來事事勝公榮。", "相望震澤三江水，便隔秦關萬里情。", "連茹搢紳遊北闕，如公文采似東京。", "舉觴喜共留春住，爲讀新詩一座傾。"]'),
('1babd492-377c-4f1a-a68b-943899a2c384','和元介之','曹勛','宋','宋诗','song-poetry','','[]','五年相別改形容，又向潮陽識颶風。',64,'全唐诗/poet.song.109000.json','["五年相別改形容，又向潮陽識颶風。", "蕭散喜君真有道，驅馳如我久無功。", "一鳴遂墮塵埃裏，九死餘生患難中。", "弔影自憐仍自放，鈍根不復就磨礱。"]'),
('ebb0b7de-9ad2-4d94-8fc3-d9b095b6682e','和王有道二首  其一','曹勛','宋','宋诗','song-poetry','','[]','客裏羈情厭九遷，相逢頼有故人賢。',64,'全唐诗/poet.song.109000.json','["客裏羈情厭九遷，相逢頼有故人賢。", "見貽勞苦平生句，如誦中和樂職篇。", "江左風流從昔著，日邊事業向來傳。", "祇應好語盈編簡，併待秋風送錦箋。"]'),
('bb352d80-37fb-41bc-8ef8-a341e5c71e02','和王有道二首  其二','曹勛','宋','宋诗','song-poetry','','[]','泉南幕府峻華遷，不涉銓曹已自賢。',64,'全唐诗/poet.song.109000.json','["泉南幕府峻華遷，不涉銓曹已自賢。", "悟物頗聞纔半偈，受知顧豈待三篇。", "青連山頂行行去，香度蓮腮細細傳。", "郊外高情想夷曠，詩成無惜襞雲箋。"]'),
('5291cb8e-384b-4e4f-b7fb-760dc23c1a62','和英書記二首  其一','曹勛','宋','宋诗','song-poetry','','[]','本期雅奉水雲心，况有伽陀冠二林。',64,'全唐诗/poet.song.109000.json','["本期雅奉水雲心，况有伽陀冠二林。", "海蚌得來珠莫剖，荆山鑿處玉難尋。", "翛翛真隠漸方丈，曳曳閑雲渺故岑。", "回首瑞峰空在望，只容俯首聽挐音。"]'),
('b878e4e4-85cb-4fc8-9480-f9cefe75404d','和英書記二首  其二','曹勛','宋','宋诗','song-poetry','','[]','向來衰病倦年華，坐卧頹然靜不譁。',64,'全唐诗/poet.song.109000.json','["向來衰病倦年華，坐卧頹然靜不譁。", "只擬閑時忘往事，了無好語繼餘霞。", "屢哦物表雲箋句，一掃空中睡眼花。", "每到思豐如奉誨，結茅喜近梵王家。"]'),
('3baf4940-14a3-49b9-810f-65fc9e1608dd','和陳朝議見寄二首  其一','曹勛','宋','宋诗','song-poetry','','[]','念公事業未能歸，莫厭京塵化客衣。',64,'全唐诗/poet.song.109000.json','["念公事業未能歸，莫厭京塵化客衣。", "游子固聞懷楚玉，垂堂應每倚荆扉。", "仲舒正爾宜投策，丘嫂從渠不下機。", "他日秋風鵰鶚便，雍容車騎更光暉。"]'),
('e4ab2dce-0db4-454b-a50e-84668525052b','和陳朝議見寄二首  其二','曹勛','宋','宋诗','song-poetry','','[]','老我驅馳未得歸，山中空掛薜蘿衣。',64,'全唐诗/poet.song.109000.json','["老我驅馳未得歸，山中空掛薜蘿衣。", "三台勝地松連菊，五畝幽居竹映扉。", "黄卷青燈真我事，鱸魚白酒亦天機。", "騷人往往秋多感，莫向登臨歎落暉。"]'),
('230b2cbc-8ed5-4ef4-aa27-3070ab29cba8','和葉徵君見寄二首  其一','曹勛','宋','宋诗','song-poetry','','[]','誠心接物定吾曹，藹藹風期意甚高。',64,'全唐诗/poet.song.109000.json','["誠心接物定吾曹，藹藹風期意甚高。", "每謂交梨同火棗，何殊兔角與龜毛。", "道真不契君宜問，來日無多我豈逃。", "但喜夔龍今迅召，東風連日雨如膏。"]'),
('c5fa2f79-a723-4f4f-829f-e3b06d6054cb','和葉徵君見寄二首  其二','曹勛','宋','宋诗','song-poetry','','[]','庵扉深向白雲隈，塵外朋游首重回。',64,'全唐诗/poet.song.109000.json','["庵扉深向白雲隈，塵外朋游首重回。", "三疊琴心融內景，一窗宴坐藴真胎。", "雨催芝朮依微綠，花發菖蒲積漸開。", "寄語道人端有待，莫留水榭與風臺。"]'),
('ecc66316-cb75-4acd-894b-8e5d630a1572','和李判院見寄','曹勛','宋','宋诗','song-poetry','','[]','光景飛馳疾去波，別來秋色換春和。',64,'全唐诗/poet.song.109000.json','["光景飛馳疾去波，別來秋色換春和。", "真鉛未有三花驗，歲籥虛嗟十載過。", "詩句驚人增感發，水雲留處恐蹉跎。", "荆山鑿透應多玉，分與貧儒奈老何。"]'),
('b8c76f67-5bb4-49d1-bb1e-bae27321172c','和人見寄','曹勛','宋','宋诗','song-poetry','','[]','客裏相逢樂可涯，坐來三見換年華。',64,'全唐诗/poet.song.109000.json','["客裏相逢樂可涯，坐來三見換年華。", "喜君舞綵庭趨鯉，愧我驚鴻跡在沙。", "白眼故應聊溷俗，青氈當亦謹傳家。", "他時竚看趨三接，大對行應罄五車。"]'),
('1e3c6e5e-1c93-4a81-b196-0eb342590c46','和高路分見贈二首  其一','曹勛','宋','宋诗','song-poetry','','[]','行年以禮古猶今，况已華顛雪滿簪。',64,'全唐诗/poet.song.109000.json','["行年以禮古猶今，况已華顛雪滿簪。", "五子政須俱治産，兩疏寧復較揮金。", "稍攄雲水安閑計，得展江湖漫浪心。", "一笑相逢慰岑寂，更煩擊節發清吟。"]'),
('25b7c504-912a-459f-b7d3-e721f37120d9','和高路分見贈二首  其二','曹勛','宋','宋诗','song-poetry','','[]','照世名流玉與清，公家勳業有繁纓。',64,'全唐诗/poet.song.109000.json','["照世名流玉與清，公家勳業有繁纓。", "格言追古如陶令，妙句鏘金謝子卿。", "卜築靚深均里閈，山林佳絕得天成。", "兩篇奇語難修報，褒借飄飄愧此生。"]'),
('6d25392d-22c6-4640-a148-8390032d1f2e','和虛中見贈二首  其一','曹勛','宋','宋诗','song-poetry','','[]','珊瑚明月墮微茫，春入燈花暖夜缸。',64,'全唐诗/poet.song.109000.json','["珊瑚明月墮微茫，春入燈花暖夜缸。", "但閲璵璠來棐几，頗慚心跡倦芸窗。", "雲間舊是賢者隠，江夏久無清譽雙。", "拭目須君上霄漢，且將韻語伴澄江。"]'),
('6309f0b8-2b10-4c83-a91d-87b768ce3b15','和虛中見贈二首  其二','曹勛','宋','宋诗','song-poetry','','[]','銷沈壯氣已無餘，尚有牀頭數卷書。',64,'全唐诗/poet.song.109000.json','["銷沈壯氣已無餘，尚有牀頭數卷書。", "再命豈宜居舊物，三乘只合樂真如。", "脩門喜見平生友，窮巷何堪長者車。", "顧我久尋方外侶，按摩頗欲獻呵噓。"]'),
('5544b747-6d62-478d-83da-f2d0b274a399','和虛中所惠佳什','曹勛','宋','宋诗','song-poetry','','[]','君家妙譽自無雙，每肯區區問禮忙。',64,'全唐诗/poet.song.109000.json','["君家妙譽自無雙，每肯區區問禮忙。", "頷下老髯仍不白，顔間喜氣已微黄。", "力扶雅道新章句，藹有雄文古戰場。", "一夕詩來增浩歎，更和秋雨聽浪浪。"]'),
('991bf934-f37c-4ea5-a3b4-ad573546d067','和癯翁見貽','曹勛','宋','宋诗','song-poetry','','[]','會面殊稀各一方，真成笑語隔炎凉。',64,'全唐诗/poet.song.109000.json','["會面殊稀各一方，真成笑語隔炎凉。", "不知九月露華白，但見一庭花蘂黄。", "客路倦懷常落莫，故園歸夢幾微茫。", "何時到得嬉堂上，賸看黄山煙水鄉。"]'),
('a9d7b798-f045-47b5-b835-a948ae34a954','和張凝神見貽','曹勛','宋','宋诗','song-poetry','','[]','奉引歸來春晚時，扁舟便欲訪天隨。',64,'全唐诗/poet.song.109000.json','["奉引歸來春晚時，扁舟便欲訪天隨。", "都忘舊學塵埃滿，頓覺新年氣宇衰。", "遽有恩榮騰紫詔，了無功業立彤墀。", "先生妙句煩褒借，一夕光涵月不虧。"]'),
('e27f50e6-7261-4a33-9fe6-3294781d13fe','和陳御带見貽','曹勛','宋','宋诗','song-poetry','','[]','漢室文章遠業成，斗南英氣爲時生。',64,'全唐诗/poet.song.109000.json','["漢室文章遠業成，斗南英氣爲時生。", "新兼带插嚴天仗，夙展韜鈐衛帝營。", "四塞羌戎知號令，五軍貔虎畏威名。", "中興方倚軍容振，功業行看衮繡榮。"]'),
('e7294ab1-8db4-466e-8c0d-827357c6408d','和陳南仲郎中見貽','曹勛','宋','宋诗','song-poetry','','[]','潁川先生氣佳哉，軟語款細懷抱開。',64,'全唐诗/poet.song.109000.json','["潁川先生氣佳哉，軟語款細懷抱開。", "萬言倚馬有餘味，一室掃地無纖埃。", "懸知得句先鉢韻，便覺北南瞻斗魁。", "向來小駐奔電馬，始今須遂良史才。"]'),
('d8808b38-869e-4a36-b817-9b66e2179921','和蘇養直見貽二首  其一','曹勛','宋','宋诗','song-poetry','','[]','投閑久去大明宮，鐘鼎山林興已同。',64,'全唐诗/poet.song.109000.json','["投閑久去大明宮，鐘鼎山林興已同。", "但得眠雲仍釣水，不妨抹月與批風。", "頗能植杖閑爲圃，尚欲臨文學送窮。", "煩子遠來忘趼足，問言今作白頭翁。"]'),
('e854a06c-afd5-4baf-a100-da3f6360a7d0','和蘇養直見貽二首  其二','曹勛','宋','宋诗','song-poetry','','[]','羅浮真隠下珠宮，一粒丹砂魏武同。',64,'全唐诗/poet.song.109000.json','["羅浮真隠下珠宮，一粒丹砂魏武同。", "豈但脩齡還稚齒，因知韻語盡仙風。", "潛真已信人非遠，拔宅懸知理可窮。", "分我刀圭他日事，紅塵先拜紫髯翁。"]'),
('fcb92fa5-11b2-454f-a474-3348b12b7d67','和王應夫見貽六首  其一','曹勛','宋','宋诗','song-poetry','','[]','冥心艱苦走南隅，每讀清言意已攄。',64,'全唐诗/poet.song.109000.json','["冥心艱苦走南隅，每讀清言意已攄。", "竹簡固嘗窺遠業，山陰何止識遺書。", "雲間未省三年別，海上今欣一笑初。", "乘興此來傳句法，頗容求益董梧鋤。"]'),
('bb9b5c0f-f93e-491c-8d19-9855a0b0aed1','和王應夫見貽六首  其二','曹勛','宋','宋诗','song-poetry','','[]','平生政不悟三隅，漸老涂窮志莫攄。',64,'全唐诗/poet.song.109000.json','["平生政不悟三隅，漸老涂窮志莫攄。", "行路又迎新曆日，寓懷頼有舊圖書。", "逢時意可情猶在，多病心闌事昧初。", "流落此生何處是，欲從老圃學犁鋤。"]'),
('975fc612-9281-4adc-b2f1-a0f4518b18ec','和王應夫見貽六首  其三','曹勛','宋','宋诗','song-poetry','','[]','聯事當年在海隅，再遵南尾笑言攄。',64,'全唐诗/poet.song.109000.json','["聯事當年在海隅，再遵南尾笑言攄。", "尚懷擁鼻胡牀語，每寄論心尺素書。", "松籟舞風鷹隼後，蒲團附火雪霜初。", "應憐別久愈無味，茅塞如今擬荷鋤。"]'),
('e8db021a-00a9-4457-b033-ebb8a5eff8b6','和王應夫見貽六首  其四','曹勛','宋','宋诗','song-poetry','','[]','大方今始識無隅，明月珊瑚袖手攄。',64,'全唐诗/poet.song.109000.json','["大方今始識無隅，明月珊瑚袖手攄。", "愧甚許提圯上履，喜於親授活人書。", "風神峙玉藏純白，議論昂霄到古初。", "內顧斐然知不稱，祇宜歸隠自扶鋤。"]'),
('980830e1-f1da-4e5d-a575-73098deb3632','和王應夫見貽六首  其五','曹勛','宋','宋诗','song-poetry','','[]','開緘韻語起廉隅，坐使心胸百想攄。',64,'全唐诗/poet.song.109000.json','["開緘韻語起廉隅，坐使心胸百想攄。", "公比士元方展驥，我如毛穎不中書。", "燭摇冷暈人方寂，犬吠寒雲月上初。", "北首故關山萬疊，幾時艱棘一誅鋤。"]'),
('36b93d47-649b-4c37-b666-1a9ac235fcdd','和王應夫見貽六首  其六','曹勛','宋','宋诗','song-poetry','','[]','曉程寒水散城隅，款段徐行得自攄。',64,'全唐诗/poet.song.109000.json','["曉程寒水散城隅，款段徐行得自攄。", "天外好山宜日襯，風前老柳半蟲書。", "賡詩已玷清新後，扣戶仍煩剝啄初。", "忙似老農無住著，看人倉庾亟持鋤。"]'),
('2b6c9307-1b32-4e16-af64-41380501b253','用前韻贈張正仲朝散二首  其一','曹勛','宋','宋诗','song-poetry','','[]','郎官出宰鎮方隅，聊試牛刀意未攄。',64,'全唐诗/poet.song.109000.json','["郎官出宰鎮方隅，聊試牛刀意未攄。", "不特持平爭結友，要知博物有成書。", "不驚雉羽桑陰靜，一洗蠻烟霽景初。", "恨識羽山眉宇晚，徒聞嘉惠及耕鋤。"]'),
('75757f21-4be0-4030-a95b-aae6f2b83f9a','用前韻贈張正仲朝散二首  其二','曹勛','宋','宋诗','song-poetry','','[]','朅來仰止德之隅，頗欲徜徉遂所攄。',64,'全唐诗/poet.song.109000.json','["朅來仰止德之隅，頗欲徜徉遂所攄。", "倚杖未忘千里恨，飛鴻爲作一行書。", "喜君燕寢凝香暇，念我哀涂稅駕初。", "湖海不除豪舉想，尚容訪古問槐鋤。"]'),
('3a57f18b-3b95-4382-bd71-3dd0e7bd17cb','和曾竑父見招','曹勛','宋','宋诗','song-poetry','','[]','使君邀我避炎蒸，好句先馳識故情。',64,'全唐诗/poet.song.109000.json','["使君邀我避炎蒸，好句先馳識故情。", "長日流金雖可畏，小槽釀玉得同傾。", "耡荒喜已親三徑，作吏誰能更一行。", "且與詩翁頻嘯詠，箇中佳處絕將迎。"]'),
('fd1e81b4-a897-4e45-b8c5-a1da35ced63b','和李判院宿松隠見貽','曹勛','宋','宋诗','song-poetry','','[]','未論琢句比玄暉，餘事猶思學退之。',64,'全唐诗/poet.song.109000.json','["未論琢句比玄暉，餘事猶思學退之。", "數畝園荒松菊在，一生心有水雲知。", "時平豈暇尋三窟，事際何能出六奇。", "幸有松篁隠幽築，所欣鶴馭到時時。"]'),
('bb03a30a-be42-49a5-95f1-16e1bd3be5e2','和錢大參題松隠明秀堂韻','曹勛','宋','宋诗','song-poetry','','[]','溪聲山色助清豪，小葺蘅茅望玉霄。',64,'全唐诗/poet.song.109000.json','["溪聲山色助清豪，小葺蘅茅望玉霄。", "蓮社粗能追惠遠，虎頭寧復愧班超。", "有池清淺方儲水，厥木扶疏豈待高。", "甚辱品題嗟老矣，而今不夢紫宸朝。"]'),
('42110675-854f-4139-9bd1-3af07c43d07e','和賀參政與應宣教詩應居與墳廬相近','曹勛','宋','宋诗','song-poetry','','[]','庵外山高水不窮，庵中道德與時隆。',64,'全唐诗/poet.song.109000.json','["庵外山高水不窮，庵中道德與時隆。", "豈圖寶所千峰靜，得奉清言一笑同。", "幽築禪扉俱不遠，水光蘿月冷相通。", "它年更約稽山老，共棹西溪十里風。"]'),
('6067e65e-4fc6-44e5-a826-bdc801fbb02c','和謝參政卜宅','曹勛','宋','宋诗','song-poetry','','[]','數篇隃寄梵王宮，玉立高寒並兩峯。',64,'全唐诗/poet.song.109000.json','["數篇隃寄梵王宮，玉立高寒並兩峯。", "亹亹詩章煩護惜，時時情話憶過從。", "雪殘蒼嶺野雲暗，花著疏梅春意濃。", "它日庵居定相奉，半山松竹更誰容。"]'),
('74ac473e-aced-4538-98b8-a4e5f22a2c40','和曾守祈雪二首  其一','曹勛','宋','宋诗','song-poetry','','[]','怪來六幕了無風，虛室光摇表裏同。',64,'全唐诗/poet.song.109000.json','["怪來六幕了無風，虛室光摇表裏同。", "端木已飛花委積，老蟾應借色朦朧。", "忍寒須放兒輩喜，清賞莫令樽酒空。", "想得明朝呼舞處，森嚴冠珮大廷中。"]'),
('6fdd7157-593c-40ef-8e84-7544307a0dfd','和曾守祈雪二首  其二','曹勛','宋','宋诗','song-poetry','','[]','天其或使不輕飛，有待隨軒故作遲。',64,'全唐诗/poet.song.109000.json','["天其或使不輕飛，有待隨軒故作遲。", "風靜圓虛纔半夜，雪隨精意若前期。", "影藏寂寂沙頭鷺，寒入青青壠首岐。", "千里歡謠歸太守，邦人固已播聲詩。"]'),
('6727139a-9d78-4943-9a5c-9157f4e85bcd','和曾守洪倅喜雪','曹勛','宋','宋诗','song-poetry','','[]','不知時雪覆雲沙，但怪虛窗木影斜。',64,'全唐诗/poet.song.109000.json','["不知時雪覆雲沙，但怪虛窗木影斜。", "入竹不妨聽窸窣，映空寧復問津涯。", "盃深喜近圍爐火，香冷誰尋小樹花。", "語到蓬仙煩寄我，固應黄竹屬詩家。"]'),
('3c710eda-7ffa-4641-b80b-b07ca694f442','和曾守出後房麗人','曹勛','宋','宋诗','song-poetry','','[]','方慚虛薄預時流，仍見娉婷恰上頭。',64,'全唐诗/poet.song.109000.json','["方慚虛薄預時流，仍見娉婷恰上頭。", "檀口細能哦赤壁，羊醅喜爲沃清愁。", "當軒妙有眉宇秀，列屋尚誰庭院幽。", "頗恨夜深人已醉，翔然翠袂挽無由。"]'),
('f306c217-b8f3-41ce-8ae9-6db2b39b634f','和曾守東郊賞梅兼送范子芬','曹勛','宋','宋诗','song-poetry','','[]','溪曲山橫動曉光，天開玉雪照崇岡。',64,'全唐诗/poet.song.109000.json','["溪曲山橫動曉光，天開玉雪照崇岡。", "不妨花陌依微雨，爲洗春風澹薄粧。", "送別休歌河滿子，相思留待返魂香。", "坐中客已無腸斷，何况離聲更抑揚。"]'),
('9003a0ef-d5ee-40f8-a0d9-699a813aa6c7','和張正仲朝散','曹勛','宋','宋诗','song-poetry','','[]','萬里關河雪正霜，自憐跣履苦奔忙。',64,'全唐诗/poet.song.109000.json','["萬里關河雪正霜，自憐跣履苦奔忙。", "宦情久欲休言責，世態何能學坐忘。", "頼有新詩排困躓，未忘濁酒發清狂。", "得公韻語袪煩甚，亟揖筠風續報章。"]'),
('e89c85d3-0ac2-4632-bac5-515cc2a56a83','和鮑仲山賦靈巖寺','曹勛','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','十年塵土換華顛，一踏山根覺渙然。',64,'全唐诗/poet.song.109000.json','["十年塵土換華顛，一踏山根覺渙然。", "下界長江朝勝地，上方大士隠非煙。", "覽輝已見翔威鳳，倚仗何堪照細泉。", "暫得詮心適佳處，試拋馬箠問枯禪。"]'),
('a4113b5a-cfbe-4031-891c-cc1b7c98cc75','和石及甫惠蔓菁子','曹勛','宋','宋诗','song-poetry','','[]','初疑堅固出毫端，漸認芳香實滿盤。',64,'全唐诗/poet.song.109000.json','["初疑堅固出毫端，漸認芳香實滿盤。", "功已充盈過膏沐，擷應璀璨掬寒酸。", "煩君玉粒炊圓碧，助我神庭並渥丹。", "復似嬰兒當有漸，爲增杞菊副朝餐。"]'),
('caab0dbf-2b64-4b3d-b774-c63245ae5415','和人題倚江亭','曹勛','宋','宋诗','song-poetry','','[]','老去求閑計已疎，若尋多事即荆舒。',64,'全唐诗/poet.song.109000.json','["老去求閑計已疎，若尋多事即荆舒。", "孤高簡澹爲三益，淳白清凉共一虛。", "有意烟雲供眼界，無心鳥雀下庭除。", "茲亭未足爲依泊，自是山中有舊廬。"]'),
('97cede48-7c0f-4652-b74b-a60b87ea2fc7','再和呈李提舉','曹勛','宋','宋诗','song-poetry','','[]','僑寓江城意豈疎，得親仙李似南舒。',64,'全唐诗/poet.song.109000.json','["僑寓江城意豈疎，得親仙李似南舒。", "高門带珮昭寰宇，一代勳庸切太虛。", "相業自應求的子，老成宜復被親除。", "中興文物須名世，會見金珂下直廬。"]'),
('3bf5f8c4-9fa0-40a6-b4b9-cf2e145217ce','和人荔子','曹勛','宋','宋诗','song-poetry','','[]','冥冥細雨不霑梅，喜熟筠籠荔子來。',64,'全唐诗/poet.song.109000.json','["冥冥細雨不霑梅，喜熟筠籠荔子來。", "滿眼驪山當日意，十年閩嶺此時杯。", "色香豈謂撩禪悅，甘旨隃知並老萊。", "伏讀佳章輙賡唱，敢將瓦礫擬瓊瑰。"]'),
('bb1cf76d-9561-4589-b8a5-911c08a318f7','和紹興次子所寄詩','曹勛','宋','宋诗','song-poetry','','[]','連旬零雨暑猶强，未信人間八月凉。',64,'全唐诗/poet.song.109000.json','["連旬零雨暑猶强，未信人間八月凉。", "甕裏麴生初泛蟻，壺中桂子並尋芳。", "斑衣未遂蘭玉集，吾子少留雲水鄉。", "門戶喜猶家法在，詩情輙莫似王陽。"]'),
('65df64e4-6bbc-4872-b519-bb0c82928a05','和次子積雨損紅木犀','曹勛','宋','宋诗','song-poetry','','[]','應向西瑶立赤墀，鮮雲仍带綠烟宜。',64,'全唐诗/poet.song.109000.json','["應向西瑶立赤墀，鮮雲仍带綠烟宜。", "要先籬菊三秋艷，不放蟾華一點窺。", "頗訝夙宵凉雨疾，頓思晨發曉光披。", "騷人豪舉經年意，絕歎丰姿積漸吹。"]'),
('fbef60f6-e4d2-44ce-9df7-ea583d99baf5','和人惠詩二首  其一','曹勛','宋','宋诗','song-poetry','','[]','憂患心知振古稀，北征讀盡少陵詩。',64,'全唐诗/poet.song.109000.json','["憂患心知振古稀，北征讀盡少陵詩。", "孰能狡兔謀三穴，且願鷦鷯寄一枝。", "出隴麥苗憂客念，摇風柳色動春辭。", "與公共作詩魔役，不害閑中故作癡。"]'),
('f0f5056f-eeee-4e55-b610-5e0c0feab61a','和人惠詩二首  其二','曹勛','宋','宋诗','song-poetry','','[]','從來五技已成窮，顧我方今五技中。',64,'全唐诗/poet.song.109000.json','["從來五技已成窮，顧我方今五技中。", "治絮不能防暴冷，擁爐聊復借微烘。", "懷鄉固與我同志，浮膽懸知酒有功。", "待約盃盤尋一醉，醉來寧復問凶豐。"]'),
('41332ef5-9589-45e9-96c2-b354b91465ef','再答前韻二首  其一','曹勛','宋','宋诗','song-poetry','','[]','不裘而暖得橫披，絕叫西崑不復詩。',64,'全唐诗/poet.song.109000.json','["不裘而暖得橫披，絕叫西崑不復詩。", "聳入山容成紫障，暖回玉糝綴繁枝。", "從知公有青雲士，聊欲文成黄絹辭。", "但得錦囊風月在，胸中佳處未妨癡。"]'),
('cbb677f0-6487-4e7b-b1d4-82e4f36eb435','再答前韻二首  其二','曹勛','宋','宋诗','song-poetry','','[]','客居索寞厭天窮，撫事無能笑語中。',64,'全唐诗/poet.song.109000.json','["客居索寞厭天窮，撫事無能笑語中。", "破睡好茶盈碗白，曝簷晴日半簾烘。", "向來切己連丁禍，政以臨民獲罔功。", "頼有破除餘習在，后山端欲扣南豊。"]'),
('aa6b9e62-03f5-4044-a2be-95c9e38387eb','老景逢春每多留賞子美所謂老去願春遲子忱雅知其况以佳句見貽信筆爲答','曹勛','宋','宋诗','song-poetry','','[]','吾儔春味等閑情，識我幽花種繞亭。',64,'全唐诗/poet.song.109000.json','["吾儔春味等閑情，識我幽花種繞亭。", "雲带竹光天外碧，風回松吹夢中醒。", "樽罍湛綠邀芳景，紅翠收香拂夜屏。", "歸傍清池留未足，更看涵泳一天星。"]'),
('ed6ab189-0e1a-4249-b22a-2bf1570d35ca','答趙周卿','曹勛','宋','宋诗','song-poetry','','[]','柴扃小隠二林間，德有鄰兮跡遂安。',64,'全唐诗/poet.song.109000.json','["柴扃小隠二林間，德有鄰兮跡遂安。", "天派發源公雋秀，客情催老我蹣跚。", "松留日脚秋烟薄，塔響風鑾夜月寒。", "頗喜笑談皆自在，兵戈聚首蓋良難。"]'),
('316f7795-ee2a-488f-b011-f5aaf6769754','和英上人見寄','曹勛','宋','宋诗','song-poetry','','[]','華鯨吼雨曉聲長，詩罷蕭閑百步廊。',64,'全唐诗/poet.song.109000.json','["華鯨吼雨曉聲長，詩罷蕭閑百步廊。", "倚暖花梢清有思，傲霜菊蘂冷猶香。", "好閑懶瓚聊煨芋，不病維摩尚倚牀。", "滿眼雲山應自足，笑渠門外馬蹄忙。"]'),
('33f11725-d813-4363-9c82-b82597b3bdf3','奉答國器見貽二首  其一','曹勛','宋','宋诗','song-poetry','','[]','連朝好語見勤渠，得失從來要一如。',64,'全唐诗/poet.song.109000.json','["連朝好語見勤渠，得失從來要一如。", "公但忘情分定事，天教更讀未看書。", "柳藏窈窕金千縷，月在西南玉一梳。", "倚熟何妨駐行李，神仙亦復喜樓居。"]'),
('f4efce88-3dd0-4fea-b013-92b4c88c0a14','奉答國器見貽二首  其二','曹勛','宋','宋诗','song-poetry','','[]','光焰方期萬丈長，壯心肯以醉爲鄉。',64,'全唐诗/poet.song.109000.json','["光焰方期萬丈長，壯心肯以醉爲鄉。", "功名莫與平泉李，志業須還鐵硯桑。", "待價自應聊隠默，逢年安得更韜藏。", "翩翩賸讀春風句，兩目增明膽亦張。"]'),
('3ff24539-c7d2-4593-a1c8-2e30613b2b6c','雙溪雲老寄示佳句及新茶用來韻爲謝','曹勛','宋','宋诗','song-poetry','','[]','老去光陰不問春，只思麋鹿與爲羣。',64,'全唐诗/poet.song.109000.json','["老去光陰不問春，只思麋鹿與爲羣。", "每求書附風前雁，便想山深日暮雲。", "鉛槧塵勞應念我，詩章棋局久思君。", "新茶仍副清新句，碌碌粗官愧少文。"]'),
('f3cac0f4-cf88-4e6c-9456-bf1a6e83a587','王元龍惠新製輒依末後耘田韻敘謝','曹勛','宋','宋诗','song-poetry','','[]','雕章琢句茂家聲，如閲龍跳讀快晴。',64,'全唐诗/poet.song.109000.json','["雕章琢句茂家聲，如閲龍跳讀快晴。", "秀韻凌虛天外立，春熙及物坐中生。", "只應翳鳳游八極，但覺儀韶聞九成。", "願看浯溪擅文學，要收功業付耆英。"]'),
('89463b56-cc15-4d70-bb5a-0293a14788fb','新歲雪示兒輩二首  其一','曹勛','宋','宋诗','song-poetry','','[]','改歲晴和兩月慳，雨聲兼閏濕長安。',64,'全唐诗/poet.song.109000.json','["改歲晴和兩月慳，雨聲兼閏濕長安。", "江梅已挾春風嫩，朔雪猶飛臘月寒。", "老境亟尋篝火暖，此懷不放酒瓶乾。", "珠幢玉蘂明心目，寫入清吟異日看。"]'),
('981d5b51-4bb6-4a7a-b62d-dfecd00892f4','新歲雪示兒輩二首  其二','曹勛','宋','宋诗','song-poetry','','[]','政恐東臯穡事慳，曉霞擁日作平安。',64,'全唐诗/poet.song.109000.json','["政恐東臯穡事慳，曉霞擁日作平安。", "禽聲便與和風暖，梅影潛摇碧砌寒。", "幽谷定遷鶑囀巧，芳郊滋喜燕泥乾。", "吾君勤儉寬宵旰，富入倉箱億兆看。"]'),
('6286bebe-7b27-4ef4-ae80-ca13368e297d','老拙觀諸公及兒輩和篇差以自慰再和前韻','曹勛','宋','宋诗','song-poetry','','[]','濃陰冞月作春慳，茲夕栖巢鵲不安。',64,'全唐诗/poet.song.109000.json','["濃陰冞月作春慳，茲夕栖巢鵲不安。", "淅瀝潛回連夜雨，繽紛遽作勒花寒。", "色迷梅徑香非遠，聲抑琴絲潤未乾。", "西北高樓臨縹緲，海山羣玉得重看。"]'),
('ba12e45a-3dd2-406e-a223-a425111d8632','鄭吏部有詩謂未當作壽穴和其韻','曹勛','宋','宋诗','song-poetry','','[]','子真高韻屢裁詩，不得同行暫語離。',64,'全唐诗/poet.song.109000.json','["子真高韻屢裁詩，不得同行暫語離。", "春色正如重醖酒，好花尚有最繁枝。", "老翁只喜先安穴，壽數何能更問眉。", "冒熱歸來便如夢，何堪塵土混幽思。"]'),
('077a0a57-a659-4065-9cb0-fd405a35cbdb','謝楊監丞雪中送羊羔酒','曹勛','宋','宋诗','song-poetry','','[]','朝回六出勢飛浮，歷亂初看積瓦溝。',64,'全唐诗/poet.song.109000.json','["朝回六出勢飛浮，歷亂初看積瓦溝。", "漫以郢人歌白雪，曲煩從事到青州。", "因知洗吻羊肪滑，可但傾腸鼠腹休。", "紙帳熏爐今已矣，解嘲得免繼前修。"]'),
('5d34c8ed-7109-4fa6-a310-fce92216ef3f','謝錢處和惠燕坐搘頤蓮','曹勛','宋','宋诗','song-poetry','','[]','不倚蒲團有妙機，搘頤真可助癡兒。',64,'全唐诗/poet.song.109000.json','["不倚蒲團有妙機，搘頤真可助癡兒。", "輟君拄頰看山用，拯我垂頭欲睡時。", "燕坐巧能留蝶夢，吟髭聊復寄蓮枝。", "從今寧有靈龜歎，一枕跏趺總不知。"]'),
('55a0e7c0-03bb-47a9-97b3-46d9ee9b1dac','臘日謝仰上人惠蘭','曹勛','宋','宋诗','song-poetry','','[]','未覺光風轉朔雲，深窗乍見意增新。',64,'全唐诗/poet.song.109000.json','["未覺光風轉朔雲，深窗乍見意增新。", "欲先楚客傳清些，未放江梅占早春。", "自許幽香傳窈窕，更煩白足下嶙峋。", "爲君抖擻煩襟看，要是都無一點塵。"]'),
('ab415a7f-16cf-4073-99a3-acb79de7259e','謝衛太尉送新酒','曹勛','宋','宋诗','song-poetry','','[]','君家冰玉傳素風，甕頭色與冰玉同。',64,'全唐诗/poet.song.109000.json','["君家冰玉傳素風，甕頭色與冰玉同。", "薰人氣和喜屢接，入琖色輕看若空。", "梅花破蕚香澹澹，江天欲雪雲濛濛。", "坐客已醉復贊歎，頭不岑岑常憶公。"]'),
('1690caf4-2219-49e1-b1cf-574f084d4789','酬許察院','曹勛','宋','宋诗','song-poetry','','[]','十載天涯客路身，不知何處是通津。',64,'全唐诗/poet.song.109000.json','["十載天涯客路身，不知何處是通津。", "華顛久已從公道，青眼遥思有故人。", "壯節未隨塵土變，窮愁專與歲時新。", "鄒枚正此游梁倦，引手毋令浪苦辛。"]'),
('da92ec02-b3db-4bce-8b31-1c65c3dab1c3','再酬丁尉','曹勛','宋','宋诗','song-poetry','','[]','九臯仙緒豈凡門，肯顧衰翁笑語溫。',64,'全唐诗/poet.song.109000.json','["九臯仙緒豈凡門，肯顧衰翁笑語溫。", "槐里少留傳好句，楓宸固已奏嘉言。", "瀰瀰野水山連碧，嫋嫋新凉月挂昏。", "妙筆摛華想高興，政須檀板與清樽。"]'),
('b4e3ada8-978b-44c7-883d-b5e864b004c9','寄宋德可觀察','曹勛','宋','宋诗','song-poetry','','[]','北歸一笑脫胡沙，淮海相逢五歲華。',64,'全唐诗/poet.song.109000.json','["北歸一笑脫胡沙，淮海相逢五歲華。", "寄語欲憑滄海月，昔游空想赤城霞。", "遥知漢殿宜鳴玉，不謂青門尚種瓜。", "雖是道人心似鐵，餘情應得賦梅花。"]'),
('8b84aa3a-3968-45e9-ac19-9833a58dfadc','病中寄曾使君湖上','曹勛','宋','宋诗','song-poetry','','[]','露曉紅幢綠蓋明，使君千騎會耆英。',64,'全唐诗/poet.song.109000.json','["露曉紅幢綠蓋明，使君千騎會耆英。", "笙歌遞奏連雲上，荷芰傳香拂面清。", "遐想雅歡均四坐，欲尋幽夢下重城。", "負薪獨恨窮閻卧，不得臨流預濯纓。"]'),
('73491342-4441-439d-9418-17a80abc28e1','用前韻酬陳判官','曹勛','宋','宋诗','song-poetry','','[]','刺桐花發照人明，三看薰風舞絳英。',64,'全唐诗/poet.song.109000.json','["刺桐花發照人明，三看薰風舞絳英。", "海近魚肥隨米賤，山高溪凈照人清。", "久聞射策先黄甲，何意棲鸞尚赤城。", "顧我婆娑老林下，看君事業映簪纓。"]'),
('62aa36cd-a47d-494a-9e14-f07d04c45280','寄儲子椿','曹勛','宋','宋诗','song-poetry','','[]','卓犖姑溪有隠君，當年遠識達楓宸。',64,'全唐诗/poet.song.109000.json','["卓犖姑溪有隠君，當年遠識達楓宸。", "鑑明塵土無留跡，水凈妍媸久自真。", "聞道燕居求性理，固應有暇對閑人。", "一廛已約同藏海，他日茅齋定卜鄰。"]'),
('ca06ac31-77bf-42a6-967c-883134c9ed13','寄陳居士','曹勛','宋','宋诗','song-poetry','','[]','君住西山我住東，杖藜時復得相從。',64,'全唐诗/poet.song.109000.json','["君住西山我住東，杖藜時復得相從。", "欣欣未見飄飄舉，楚楚先經面面松。", "仙事既無妻子累，丹罏自有鬼神供。", "來春麥壠青中過，待碾新茶約段公。"]'),
('22f06a1a-ba8f-4c7e-bb38-9f3889937560','寄山中友','曹勛','宋','宋诗','song-poetry','','[]','同朝不復舊交游，留滯行都歲兩周。',64,'全唐诗/poet.song.109000.json','["同朝不復舊交游，留滯行都歲兩周。", "落景殘霞曛夕靄，斷雲橫雨霽高秋。", "因仍久作歸歟計，蹭蹬端如賈客留。", "慚愧君恩何以報，此身江海任虛舟。"]'),
('0ca54c83-088f-4f97-aa6f-01f8e9806015','新建秘書省呈李秘監','曹勛','宋','宋诗','song-poetry','','[]','道山賢範久摧藏，聖德重興接耿光。',64,'全唐诗/poet.song.109000.json','["道山賢範久摧藏，聖德重興接耿光。", "招隠稍來周俊造，紬書行見漢文章。", "挂簷玉榜昭新渥，插架芸籤識舊香。", "喜見諸儒在天祿，嘉謨應欲贊時康。"]'),
('2b80a31b-dfc9-4ad5-b3bb-74eec51b3775','懷歸呈同官','曹勛','宋','宋诗','song-poetry','','[]','老去光陰易變遷，佳時常在淚痕邊。',64,'全唐诗/poet.song.109000.json','["老去光陰易變遷，佳時常在淚痕邊。", "一寒休待綈袍惠，二頃須資負郭田。", "邀客預留醅下酒，憑欄閑數渡頭船。", "此身更待烟蘿去，放盡天游只醉眠。"]'),
('74bdefe0-c96f-4697-83c2-60d06c6ece6a','小園午集坐間呈處和瞻明諸友','曹勛','宋','宋诗','song-poetry','','[]','共向花時笑語頻，不須七七倩花神。',64,'全唐诗/poet.song.109000.json','["共向花時笑語頻，不須七七倩花神。", "中郎棋戰投機捷，閣老詩壇著語新。", "暖景遲遲鶑喚友，落英寂寂草成茵。", "牡丹芍藥開非晚，更約同游浩蕩春。"]'),
('fd2e6d10-bc0d-45cc-a3ad-1b8d2c6829dc','再乞休致未遂得二詩呈之奇鄉友  其一','曹勛','宋','宋诗','song-poetry','','[]','晚歲歸心豈易收，挂冠已去復淹留。',64,'全唐诗/poet.song.109000.json','["晚歲歸心豈易收，挂冠已去復淹留。", "東方曼倩多奇節，司馬相如故倦游。", "牀上詩書供一笑，山中松桂入清愁。", "兒童怪我經春病，此意還能掩得不。"]'),
('ec813709-f445-4ce3-9be9-c9452e4a57a7','再乞休致未遂得二詩呈之奇鄉友  其二','曹勛','宋','宋诗','song-poetry','','[]','錄錄雖能早致身，中年東海與西秦。',64,'全唐诗/poet.song.109000.json','["錄錄雖能早致身，中年東海與西秦。", "只宜桐柏山中老，不是麒麟閣上人。", "故病未休新病起，黑頭應笑白頭新。", "天公早賜還山詔，懷抱紛紛倦俗塵。"]'),
('0808ef09-e806-4653-9103-a3b8c9369acc','懷趙希元','曹勛','宋','宋诗','song-poetry','','[]','久懷宣殿浮山老，句滿東南著老成。',64,'全唐诗/poet.song.109000.json','["久懷宣殿浮山老，句滿東南著老成。", "一笑忘言尋小隠，十年去國得雙清。", "別來體力兼人健，喜甚詩書滿意評。", "天子中興求讜論，故應啟沃慰平生。"]'),
('007b2eb5-2d7a-4adc-9318-6c64314191d0','戲簡錢處和','曹勛','宋','宋诗','song-poetry','','[]','聞道維摩棐几前，花隨寶女下雲天。',64,'全唐诗/poet.song.109000.json','["聞道維摩棐几前，花隨寶女下雲天。", "合歡带緩新粧薄，燕子樓深晚色鮮。", "想得瓊枝宜夜夜，只應璧月共娟娟。", "何時遂預平生友，與出湘雲伴錦筵。"]'),
('30d8c8fb-1561-433c-8422-d224114dc2f3','榮侍郎暫寓張園小詩寄懷','曹勛','宋','宋诗','song-poetry','','[]','家來三樂益芬芳，不愛華堂借草堂。',64,'全唐诗/poet.song.109000.json','["家來三樂益芬芳，不愛華堂借草堂。", "每聽鳴騶傳陋巷，便知寶勒下明光。", "炊烟茶潤兼旁舍，蘿月松風同一岡。", "錦瑟似聞方醉卧，西樓橫玉助新凉。"]'),
('8b0f0160-b126-40a6-9f54-f24ed7a9b437','僕至赤城英侍者見訪好語瀾翻喜以成詩','曹勛','宋','宋诗','song-poetry','','[]','閑中忙事厭營營，款段揚鞭訪赤城。',64,'全唐诗/poet.song.109000.json','["閑中忙事厭營營，款段揚鞭訪赤城。", "問法未經雙澗路，彌天先見萬年英。", "繁陰成幄暑風薄，好草傳香朝雨晴。", "杖屨何妨留一宿，松間語舊有餘清。"]'),
('474ad502-2d9e-4403-9933-50cb99ef7ba0','妙喜遷化悲而成詩','曹勛','宋','宋诗','song-poetry','','[]','戎燼多艱道不傳，師能橫豎說無邊。',64,'全唐诗/poet.song.109000.json','["戎燼多艱道不傳，師能橫豎說無邊。", "清湘去後人思殺，破衲歸來帝所憐。", "雙桱遽埋無盡藏，諸方應舞野狐禪。", "傷心明月堂中影，只作霜華處處圓。"]'),
('8a3b49e2-6d47-4908-8d16-93635be6341c','余比出疆以茶遺館伴乃云茶皆中等此間於高麗界上置茶凡二十八九緡可得一胯皆上品也予力辯所自來謂所遺皆御前絕品他日相與烹試果居其次傷爲猾夷所誚因得一詩','曹勛','宋','宋诗','song-poetry','','[]','年來建茗甚紛紜，官焙私園總混真。',64,'全唐诗/poet.song.109000.json','["年來建茗甚紛紜，官焙私園總混真。", "圓璧方圭青箬嫩，絳苞黄角綵題均。", "未論潔白衷腸事，只貢膏油首面新。", "世乏君謨與桑苧，翻令衡鑑入殊鄰。"]'),
('35394646-5850-4c34-93f3-21efd3255bf3','用秦公贈李次仲韻呈次仲三首  其一','曹勛','宋','宋诗','song-poetry','','[]','命本先須植日華，抽添氣液了無差。',64,'全唐诗/poet.song.109000.json','["命本先須植日華，抽添氣液了無差。", "融融瑪瑙升神室，曲曲琅玕煥綵霞。", "樞轄工夫儲太漠，至人妙理寓甘瓜。", "陽源昭徹參同處，試與三家作一家。"]'),
('8e3f30d9-1f4a-4c40-bfc6-50339508df5c','用秦公贈李次仲韻呈次仲三首  其二','曹勛','宋','宋诗','song-poetry','','[]','欲求玄牝藴清華，莫放朝昏子午差。',64,'全唐诗/poet.song.109000.json','["欲求玄牝藴清華，莫放朝昏子午差。", "收得五華滋湛露，自應雙鶴下青霞。", "頗聞北海終棲火，莫向東陵只種瓜。", "它日黄庭留黍米，遨遊海嶽未須家。"]'),
('eabb722c-cb32-41b6-89e8-af7beb8c45fa','用秦公贈李次仲韻呈次仲三首  其三','曹勛','宋','宋诗','song-poetry','','[]','靈明獨耀駐年華，九任玄歸有等差。',64,'全唐诗/poet.song.109000.json','["靈明獨耀駐年華，九任玄歸有等差。", "帝一澄明藏水火，崑丘凝結粲雲霞。", "金精盛處須尋兔，火棗成時要似瓜。", "識得神仙木中子，丹腴願及小生家。"]'),
('485a8566-55ef-4447-9ddb-1f7218708148','陪宣撫置酒南樓','曹勛','宋','宋诗','song-poetry','','[]','遠業嘗輕萬戶侯，今陪笑語庾公樓。',64,'全唐诗/poet.song.109000.json','["遠業嘗輕萬戶侯，今陪笑語庾公樓。", "聲空冀北一曲妙，木落淮南千里秋。", "酒興勇隨高意上，月華影入大江流。", "主人爲客留清境，銷盡牢愁與客愁。"]'),
('0619af3b-5702-4530-b6d5-aee9f8fa3c55','游惠山','曹勛','宋','宋诗','song-poetry','','[]','舊約溪山拄瘦筇，踏雲漸聽短長鐘。',64,'全唐诗/poet.song.109000.json','["舊約溪山拄瘦筇，踏雲漸聽短長鐘。", "山腰古佛閟金殿，石眼細泉噴玉龍。", "欲濯泠泠終日水，且臨楚楚一庭松。", "知公弭節期游勝，看取詩來阮仲容。"]'),
('aa0c29bc-1e45-42a5-b3c9-3bb8668caec3','過鄭吏部水閣','曹勛','宋','宋诗','song-poetry','','[]','九夏銷煩日正長，沉沉虛閣枕橫塘。',64,'全唐诗/poet.song.109000.json','["九夏銷煩日正長，沉沉虛閣枕橫塘。", "更無塵土侵衣裓，只有荷花度晚香。", "一道清泉供枕潄，千章古木進風凉。", "相從時得游佳處，何必持盃玉色光。"]'),
('1e476991-f07c-4717-9d79-21ca5d107c42','過處和賞荼䕷','曹勛','宋','宋诗','song-poetry','','[]','泛舟憑檻在蓬瀛，一醉心期任此生。',64,'全唐诗/poet.song.109000.json','["泛舟憑檻在蓬瀛，一醉心期任此生。", "滿腹本來同偃鼠，吸川遂欲比長鯨。", "歸來尚带荼䕷露，夢想猶聞珮玉聲。", "醉後狂歌能恕否，如今五日未全醒。"]'),
('807ffeb7-6561-45fe-969b-5fcd886d330e','處和有詩欲過小圃','曹勛','宋','宋诗','song-poetry','','[]','小園花木暖成圍，况復軒窗倚翠微。',64,'全唐诗/poet.song.109000.json','["小園花木暖成圍，况復軒窗倚翠微。", "一檻海棠雲錦展，四邊山色曉烟飛。", "春風爛熳何妨醉，濁酒淋漓任滿衣。", "甚喜鳴珂肯相訪，濟川暫艤綠苔磯。"]'),
('4fe06df8-26c3-4f9a-be3f-01f7c95fe448','思歸天台','曹勛','宋','宋诗','song-poetry','','[]','山中小築枕溪流，却踏紅塵笑拙謀。',64,'全唐诗/poet.song.109000.json','["山中小築枕溪流，却踏紅塵笑拙謀。", "鬢點吳霜今已老，兒皆楚語祇堪愁。", "猿驚鶴怨事偶爾，燕語鶑啼春罷休。", "每與兒曹話歸計，一簾清夢繞滄洲。"]'),
('1c210463-fe1d-4875-b935-e55138475f82','閑居泉州','曹勛','宋','宋诗','song-poetry','','[]','平世功名不可期，羝羊自恨觸藩籬。',64,'全唐诗/poet.song.109000.json','["平世功名不可期，羝羊自恨觸藩籬。", "勞生漫弭衆人謗，雖死肯辜天下知。", "勸進偶能回漠北，輸忠猶憶佐邊陲。", "秋風一夜翻庭綠，曉看髭髯半作絲。"]'),
('34837365-5c76-43d7-8e2d-2be30ffeb3c7','黄灣書事時虜人犯淮','曹勛','宋','宋诗','song-poetry','','[]','海邊鼓角動星辰，我復驅貧近海濱。',64,'全唐诗/poet.song.109000.json','["海邊鼓角動星辰，我復驅貧近海濱。", "强對溪山方袖手，不堪梅柳已驚春。", "新元北客愁邊淚，故國西郊日暮塵。", "誰與高寒伴幽獨，雪聲清夢入霜筠。"]'),
('c5ea0595-dd5e-4d5b-9f82-a9fab402c618','出關','曹勛','宋','宋诗','song-poetry','','[]','筍輿清曉出都門，便喜松聲到處聞。',64,'全唐诗/poet.song.109000.json','["筍輿清曉出都門，便喜松聲到處聞。", "可但佳游今止止，試尋舊友只紛紛。", "卑棲故傳吳楚語，高意自同鸞鶴羣。", "且樂退身無罣礙，滿襟塵土逐春雲。"]'),
('1827bd52-a0b5-43ac-a43e-59062ac3bc96','天台宰祈雨有感','曹勛','宋','宋诗','song-poetry','','[]','炎風踰月熾穹蒼，稼穡如雲已變黄。',64,'全唐诗/poet.song.109000.json','["炎風踰月熾穹蒼，稼穡如雲已變黄。", "令尹爲民躬血懇，神龍奮雨破驕陽。", "高低禾穎芃芃秀，壠畝風回細細香。", "自爾屢豐應課最，西成先可賀倉箱。"]'),
('f9b5e375-f1e0-4bea-a4ca-67a46894511b','次子自越來見省','曹勛','宋','宋诗','song-poetry','','[]','江分吳越寄寒溫，頼有飛鴻旦夕聞。',64,'全唐诗/poet.song.109000.json','["江分吳越寄寒溫，頼有飛鴻旦夕聞。", "作別半年常入夢，相望百里歎離羣。", "庭萱雪已侵寒綠，梅萼春回耿暮雲。", "喜汝暫歸俱慰悅，老懷無復更紛紛。"]'),
('521c6b99-97f6-4073-ad6f-4442f907855c','無錫得次子詩促歸','曹勛','宋','宋诗','song-poetry','','[]','老大心情不外求，得閑歡喜且閑休。',64,'全唐诗/poet.song.109000.json','["老大心情不外求，得閑歡喜且閑休。", "每思塵土年華老，欲接神仙汗漫游。", "三月不知春爛熳，五旬却值雨飛浮。", "催歸又誦吾兒句，便且呼童上小舟。"]'),
('79dfba5b-6269-4b23-b1b9-b0e46cdf1aa1','山中','曹勛','宋','宋诗','song-poetry','','[]','告老吾君得挂冠，交親猶肯問平安。',64,'全唐诗/poet.song.109000.json','["告老吾君得挂冠，交親猶肯問平安。", "連天秋色雁已過，滿檻竹聲風逗寒。", "對客杯盤心共醉，催人節物歲將闌。", "但知適意山林去，不覺山頭行路難。"]'),
('a4ad6a53-abf4-4d02-b5d5-146b144c3f24','松隠坐上寄錢大參','曹勛','宋','宋诗','song-poetry','','[]','閑裏光陰不記名，曲勤宏度訪公榮。',64,'全唐诗/poet.song.109000.json','["閑裏光陰不記名，曲勤宏度訪公榮。", "五雲洒翰情文厚，九節浮香琖色輕。", "寶箑含風清致爽，綵絲縈臂眼增明。", "團欒每得佳時醉，却恐宣麻下帝城。"]'),
('57fabc0e-a554-456d-9b79-3298d9d5e01c','戊子正月廿一日雪及半尺','曹勛','宋','宋诗','song-poetry','','[]','晚訝爭鳴白項鴉，梅風隨夜冷窗紗。',64,'全唐诗/poet.song.109000.json','["晚訝爭鳴白項鴉，梅風隨夜冷窗紗。", "忽驚寒透多年被，不儗潜飛六出花。", "歷亂已應藏月桂，糢糊無處認山茶。", "朝來多怪尋芳客，都向東風賣酒家。"]'),
('ae81015e-8f8f-4af1-9e14-c4ac94d3ab0f','初見梅有作','曹勛','宋','宋诗','song-poetry','','[]','至後微和入燒痕，烟稍寄我嶺頭新。',64,'全唐诗/poet.song.109000.json','["至後微和入燒痕，烟稍寄我嶺頭新。", "尚無紅糝離離意，已覺清姿苒苒春。", "未暇儗爲烏有賦，絕勝遂詠墜樓人。", "夜寒翠袖臨明月，且影橫斜上醉巾。"]'),
('e980c64d-3775-476d-99e5-3d011d417deb','清明書事','曹勛','宋','宋诗','song-poetry','','[]','老來不復較三餘，只養恬愉守故居。',64,'全唐诗/poet.song.109000.json','["老來不復較三餘，只養恬愉守故居。", "新火又逢寒食節，故人誰寄一行書。", "隨人只得身康健，寓物須煩酒破除。", "賸讀佳章正憑檻，海棠花上雨疏疏。"]'),
('235b5244-3100-4b78-9992-4a3a03ce303c','寒食有感','曹勛','宋','宋诗','song-poetry','','[]','輦下相知把酒稀，更逢寒食淚霑衣。',64,'全唐诗/poet.song.109000.json','["輦下相知把酒稀，更逢寒食淚霑衣。", "五漿道路何嘗饋，三徑荒蕪未得歸。", "春事沉沈寒慘慘，暮烟漠漠雨微微。", "杏花零落春還半，空看簾間燕子飛。"]'),
('62128507-39df-4f3b-a553-3a602ab16cef','春晚即事','曹勛','宋','宋诗','song-poetry','','[]','化國舒長日正遲，漫天風柳綠成姿。',64,'全唐诗/poet.song.109000.json','["化國舒長日正遲，漫天風柳綠成姿。", "高低蝴蝶尚春色，零落荼䕷猶晚枝。", "倦思有餘時種竹，老懷無著强賡詩。", "人人一覺是非夢，但得百年猶此時。"]'),
('95143253-c153-40f4-92c4-418f9b4ea2c1','晚春書事','曹勛','宋','宋诗','song-poetry','','[]','東風苒苒又將歸，甚叵飛花不戀枝。',64,'全唐诗/poet.song.109000.json','["東風苒苒又將歸，甚叵飛花不戀枝。", "半夜雨驚殘夢破，一春愁是落花時。", "暖梢裊裊青歸柳，輕浪痕痕綠滿池。", "惟有小欄藏秀色，數枝芍藥殿春遲。"]'),
('034c1ad2-5d56-4bf6-9850-31da5371cf50','風雨驚春','曹勛','宋','宋诗','song-poetry','','[]','一年春事急如流，每被顛風斷送休。',64,'全唐诗/poet.song.109000.json','["一年春事急如流，每被顛風斷送休。", "錦瑟華筵常漫度，杏園景物只供愁。", "須知勝踐何曾闕，自是青春不少留。", "遍倚欄干望歸路，落花飛絮思悠悠。"]'),
('2304f9ca-5071-4e66-8de6-c9755b936547','連雨有感','曹勛','宋','宋诗','song-poetry','','[]','連雨霏霏作曉陰，倚欄不復見遥岑。',64,'全唐诗/poet.song.109000.json','["連雨霏霏作曉陰，倚欄不復見遥岑。", "已疏日上三竿報，只聽風隨十日霖。", "枝上綻梅肥自墜，庭中新綠色逾深。", "田苗漲水橫斜卧，甚憫爲農種植心。"]'),
('f52847ab-add0-4fbd-a3e1-8a725177fc56','扇車','曹勛','宋','宋诗','song-poetry','','[]','良工巧製鮑魚形，短架圓機扇比名。',64,'全唐诗/poet.song.109000.json','["良工巧製鮑魚形，短架圓機扇比名。", "十幅懷箱塵不到，一輪因力羽猶輕。", "輾回劇暑軒楹去，載得長風枕簟清。", "失喜門邊須茗客，隔籬悞作碾時聲。"]'),
('6b5f29b9-972b-452e-bb84-52042dec6755','初冬日懷先壟','曹勛','宋','宋诗','song-poetry','','[]','中原金鼓未全衰，拜掃逢時淚滿衣。',64,'全唐诗/poet.song.109000.json','["中原金鼓未全衰，拜掃逢時淚滿衣。", "丘壠蕭條應蔓草，松楸寂歷想斜暉。", "殘骸漫向天南住，鄉思空隨雁北飛。", "海上傷心一巵酒，夢魂先已酹重闈。"]'),
('b06af7a6-f998-4b4b-9390-e90eaf9ffc3a','閑過小圃督治冬蔬','曹勛','宋','宋诗','song-poetry','','[]','山園乘興便忘歸，習靜關情萬事非。',64,'全唐诗/poet.song.109000.json','["山園乘興便忘歸，習靜關情萬事非。", "落葉翻江垂露網，小梅藏白倚苔磯。", "等看朔雪連雲密，數得棲鴉幾陣飛。", "台岳久慚猿鶴怨，水雲三合寸心違。"]'),
('19b7efb3-30e3-4461-b8e9-b9ad1b2e5134','辛卯題壁','曹勛','宋','宋诗','song-poetry','','[]','中原陷賊百城沒，龍馭天旋守一江。',64,'全唐诗/poet.song.109000.json','["中原陷賊百城沒，龍馭天旋守一江。", "恢復未逾衣带水，功名慚有碧油幢。", "痛無雁信來沙漠，愁覺梅風到夜窗。", "朔吹攪雲心慷慨，拊牀未易寸心降。"]'),
('0c788b41-dc6d-4437-855d-f2569cee0511','病起有感','曹勛','宋','宋诗','song-poetry','','[]','老去心情在一廛，是中憂樂稱華顛。',64,'全唐诗/poet.song.109000.json','["老去心情在一廛，是中憂樂稱華顛。", "因知不悞三三句，空近偷安九九年。", "生死去來渾付夢，火風煎迫諒非堅。", "第知一裰安排了，任我朝昏且信緣。"]'),
('e8953e94-9b37-41de-adf7-df793542c1f4','漫成','曹勛','宋','宋诗','song-poetry','','[]','年來老懶絕緘縢，陋巷甘貧得未曾。',64,'全唐诗/poet.song.109000.json','["年來老懶絕緘縢，陋巷甘貧得未曾。", "秋枕厭聞中夕雨，夜窗且對短檠燈。", "念隨壯志銷沈盡，愁與寒更爛熳增。", "却憶當年水雲侶，枯禪閑倚一枝藤。"]'),
('936db27a-97fb-4c51-ab68-0dd533b70684','台城雜詩七首  其一','曹勛','宋','宋诗','song-poetry','','[]','卜築城隅久罷休，數椽忽得水西頭。',64,'全唐诗/poet.song.109000.json','["卜築城隅久罷休，數椽忽得水西頭。", "四圍竹色繚寒碧，一徑杉風留素秋。", "門外水天分棐几，天邊桂子入簾鈎。", "指蹤盡得神仙客，更乞佳名爲榜不。"]'),
('af1b23bd-9b6f-47df-bed0-28f2d9d290a4','台城雜詩七首  其二','曹勛','宋','宋诗','song-poetry','','[]','老境光陰怯雨霜，怕寒窒隙似猜防。',64,'全唐诗/poet.song.109000.json','["老境光陰怯雨霜，怕寒窒隙似猜防。", "養生飽悟風中燭，卜宅閑尋肘後方。", "明世漁樵終混迹，故山猿鶴怨循牆。", "天台肯約它年隠，半嶺松風殷夜牀。"]'),
('79a0c3dc-7da6-43d6-9816-aba22c61101e','台城雜詩七首  其三','曹勛','宋','宋诗','song-poetry','','[]','長歌山水五風霜，翠竹青松是巨防。',64,'全唐诗/poet.song.109000.json','["長歌山水五風霜，翠竹青松是巨防。", "每謂肉身求浄觀，猶勝飯袋繞諸方。", "因風老葉閑粘網，久雨新苔巧占牆。", "何以待賓餘舊貫，一香一飯一胡牀。"]'),
('2461b58b-1be9-4e8e-b9f8-765e44004370','台城雜詩七首  其四','曹勛','宋','宋诗','song-poetry','','[]','向來小築久鋤荒，更覺閑中日月長。',64,'全唐诗/poet.song.109000.json','["向來小築久鋤荒，更覺閑中日月長。", "山脚孤烟迷市井，岡頭斜照下牛羊。", "乘槎未喜閑侵漢，騎鶴何求再上揚。", "簡寂新詩清有素，雨隨擊節助浪浪。"]'),
('7c8959a5-7f85-4dfa-abd0-168c8c36b0ec','台城雜詩七首  其五','曹勛','宋','宋诗','song-poetry','','[]','歸涂只欲自治荒，久習田間興益長。',64,'全唐诗/poet.song.109000.json','["歸涂只欲自治荒，久習田間興益長。", "插稻方能騎秧馬，觸藩遽復歎羝羊。", "乍爲事奪愧俯仰，却得公來時舉揚。", "更待凉風下天末，醉看墨妙寫淋浪。"]'),
('28c53008-6b8b-4205-998a-52c44c18027f','台城雜詩七首  其六','曹勛','宋','宋诗','song-poetry','','[]','雨後秋風十日陰，羅衣初覺曉寒侵。',64,'全唐诗/poet.song.109000.json','["雨後秋風十日陰，羅衣初覺曉寒侵。", "清愁强欲親歡伯，瘦骨何能舉聚針。", "碧玉麗詞殘照晚，青樓秀色暮雲深。", "中郎好句傳茅屋，端比逃虛喜足音。"]'),
('438ccc1f-05af-4fd9-b7e7-4b30ef6eccad','台城雜詩七首  其七','曹勛','宋','宋诗','song-poetry','','[]','金柔火老轉清商，已近蟾華冉冉光。',64,'全唐诗/poet.song.109000.json','["金柔火老轉清商，已近蟾華冉冉光。", "尚有微雲遺暑濕，不妨森木作新凉。", "壺中自有洞天闊，物外每同春日長。", "願得身藏箕斗內，白蘋紅蓼水雲鄉。"]'),
('5e970186-0a60-4aa8-815c-66e971a17a12','和孫倅見貽八首  其一','曹勛','宋','宋诗','song-poetry','','[]','十篇妙唱賁幽光，秀韻凌虛桂影凉。',64,'全唐诗/poet.song.109000.json','["十篇妙唱賁幽光，秀韻凌虛桂影凉。", "玉牒秩宗徽譽著，銀鈎揮翰麝煤香。", "風兼遠水痕成理，月入霜筠影自長。", "銅雀春深知有以，典刑終合問孫郎。"]'),
('b88f81fc-385f-4fef-9a94-8adae9c108c8','和孫倅見貽八首  其二','曹勛','宋','宋诗','song-poetry','','[]','春光過似不春光，自念曾無作法凉。',64,'全唐诗/poet.song.109000.json','["春光過似不春光，自念曾無作法凉。", "鞍馬固先均臭味，薰蕕安得更芬香。", "畫脂敢謂名堪惜，食欖今知味更長。", "珍重好辭皆發藥，頗慚宮徵顧周郎。"]'),
('85392d04-f8c4-49b3-887c-67544e86d2d7','和孫倅見貽八首  其三','曹勛','宋','宋诗','song-poetry','','[]','爝火寧知日月光，遽聞騎火犯伊凉。',64,'全唐诗/poet.song.109000.json','["爝火寧知日月光，遽聞騎火犯伊凉。", "周宣懋建中興政，上帝潜符至治香。", "天欲卦爻重彖象，民知瓜瓞本綿長。", "商孫駕馭方經武，行見蒙衝繫夜郎。"]'),
('cad9e894-1894-4572-bad3-fda9b33b6904','和孫倅見貽八首  其四','曹勛','宋','宋诗','song-poetry','','[]','世道艱虞太白光，風棲雨食鐵衣凉。',64,'全唐诗/poet.song.109000.json','["世道艱虞太白光，風棲雨食鐵衣凉。", "誰歌漢月空相識，漫有山花先自香。", "塞上許時兵未息，水邊它日話尤長。", "想當清夜圓蟾白，曾欲題詩問庾郎。"]'),
('658d3112-47eb-4a7a-9f39-73a44632ef1a','和孫倅見貽八首  其五','曹勛','宋','宋诗','song-poetry','','[]','强栽松竹養煙光，官舍公餘喜晚凉。',64,'全唐诗/poet.song.109000.json','["强栽松竹養煙光，官舍公餘喜晚凉。", "習靜關情惟挾策，愛閑修供只焚香。", "自憐怯事如欣泰，止合摳衣扣子長。", "斷斷此生今已矣，擬尋艇子學漁郎。"]'),
('7538fd5c-82dd-487e-8b84-dd228221ef95','和孫倅見貽八首  其六','曹勛','宋','宋诗','song-poetry','','[]','遽頒翰墨發幽光，內顧鯫生德甚凉。',64,'全唐诗/poet.song.109000.json','["遽頒翰墨發幽光，內顧鯫生德甚凉。", "已幸貳車臨海國，因知汗簡發天香。", "花梢擢綠蜂初靜，梅實桃青晝已長。", "會見紫泥傳詔札，中興事業屬清郎。"]'),
('df5c2103-4a23-465e-8ecd-dd929709627d','和孫倅見貽八首  其七','曹勛','宋','宋诗','song-poetry','','[]','海色天容浸冷光，秋回山谷進風凉。',64,'全唐诗/poet.song.109000.json','["海色天容浸冷光，秋回山谷進風凉。", "不須悟性三關語，自有澄心一炷香。", "倦客棲遲歸意遠，暮林摇落晚山長。", "從來習氣聞風悅，慚愧如今陛楯郎。"]'),
('0b8ed6ca-9c44-4728-9b60-810d600104c6','和孫倅見貽八首  其八','曹勛','宋','宋诗','song-poetry','','[]','韻語初疑擲夜光，頓驅熱惱作清凉。',64,'全唐诗/poet.song.109000.json','["韻語初疑擲夜光，頓驅熱惱作清凉。", "紫髯英槩雲仍著，藏室文華錦繡香。", "客况詎能論酒惡，高懷當不較龜長。", "與公避地均休戚，天使詩人識漫郎。"]'),
('0f9b0668-0e17-4d19-8ed1-78b50592a2e9','謝賜宸翰扇','曹勛','宋','宋诗','song-poetry','','[]','恩從清暑殿中傳，鳳翥龍盤墨色鮮。',32,'全唐诗/poet.song.109000.json','["恩從清暑殿中傳，鳳翥龍盤墨色鮮。", "何物老臣容拜賜，御風挾月下中天。"]'),
('6973ef44-4c70-456a-a21d-b03287d72a69','上元前四日宣召賞梅','曹勛','宋','宋诗','song-poetry','','[]','冉冉東風春乍回，睿思宣入禁中來。',32,'全唐诗/poet.song.109000.json','["冉冉東風春乍回，睿思宣入禁中來。", "忽參鼻觀清香徹，殊喜一庭都是梅。"]'),
('88627732-6800-4989-bdf0-87b45f23a5ef','德壽春帖子八首  其一','曹勛','宋','宋诗','song-poetry','','[]','曉來簾幕捲東風，尚有春寒下綺櫳。',32,'全唐诗/poet.song.109000.json','["曉來簾幕捲東風，尚有春寒下綺櫳。", "德滿人間和氣浹，卯山宮殿瑞雲中。"]'),
('8a72022c-c51e-480e-9434-88e43710915e','德壽春帖子八首  其二','曹勛','宋','宋诗','song-poetry','','[]','弄黄宮柳未齊勻，便覺風和淑景新。',32,'全唐诗/poet.song.109000.json','["弄黄宮柳未齊勻，便覺風和淑景新。", "自是東君朝最貴，欣欣春事足頤神。"]'),
