('3db80828-7470-4c99-b894-fcc94057fc20','存目  其一','宋庠','宋','宋诗','song-poetry','','[]','詩題：莊獻太后哀輓應制二首首句（全詩）：其一：寶慈垂母訓，一紀御淨除。',121,'全唐诗/poet.song.11000.json','["詩題：莊獻太后哀輓應制二首首句（全詩）：其一：寶慈垂母訓，一紀御淨除。", "地有占沙舊，天仍補石餘。", "軒星淪夕緯，翟輅去宸居。", "異日金縢啟，方知復辟書其二：肝仄身無撣，寒暄疾有加。", "災生織女□，魂斷濯龍車。", "廞翣浮辰旭，邊簫咽螟霞。", "唯留長樂注，刊美在皇家。"]'),
('1e2465af-5b2a-482c-be96-5cabf3c7b48f','存目  其二','宋庠','宋','宋诗','song-poetry','','[]','詩題：莊惠太后挽歌應制二首首句（全詩）：其一：媯幄柔明訓，堯闈保護賢。',122,'全唐诗/poet.song.11000.json','["詩題：莊惠太后挽歌應制二首首句（全詩）：其一：媯幄柔明訓，堯闈保護賢。", "別居長樂寢，讓給水衡錢。", "謹疾方加膳，收神亟去仙。", "宸襟增服紀，追報煥終天。", "其二：昔帝推嬪則，吾君頼母慈。", "陪陵漢家葬，異室箇宮祠。", "露暗星軒隠，天愁月御移。", "翟車參享路，無復廟中期。"]'),
('75131500-fe87-4d6a-ae59-59c3f216bbf4','存目  其三','宋庠','宋','宋诗','song-poetry','','[]','詩題：送梵才大師歸天台首句（全詩）：玉宇重來訪舊游。',26,'全唐诗/poet.song.11000.json','["詩題：送梵才大師歸天台首句（全詩）：玉宇重來訪舊游。"]'),
('1b3deeb6-6635-47b3-81f4-7bb416c0c568','存目  其四','宋庠','宋','宋诗','song-poetry','','[]','詩題：予自到嶺外居嵐瘴中未嘗不以先死對治人人見其浩然若有所得者今歲在海外遇寒食困發家書想望松楸不能自理偶成此詩示兒子首句（全詩）：春日自明霽按：末句作詩示阿張，',92,'全唐诗/poet.song.11000.json','["詩題：予自到嶺外居嵐瘴中未嘗不以先死對治人人見其浩然若有所得者今歲在海外遇寒食困發家書想望松楸不能自理偶成此詩示兒子首句（全詩）：春日自明霽按：末句作詩示阿張，有注云：阿張，孟堅小字。"]'),
('e9769df1-e0f0-4107-b5ab-fdf7cf322a70','存目  其五','宋庠','宋','宋诗','song-poetry','','[]','詩題：四月昌州奏聖祖殿下生芝草一本四莖及面有紅光如悅懌之狀首句（全詩）：昌之遠地凝和氣。',44,'全唐诗/poet.song.11000.json','["詩題：四月昌州奏聖祖殿下生芝草一本四莖及面有紅光如悅懌之狀首句（全詩）：昌之遠地凝和氣。"]'),
('da6dfdbb-9b78-4138-add6-85e9018bde05','春集東園賦得萼字','王洙','宋','宋诗','song-poetry','','[]','燕退朝事希，鳴騶出雲閣。',72,'全唐诗/poet.song.11000.json','["燕退朝事希，鳴騶出雲閣。", "近遊速朋彥，名園接闉郭。", "幽芳尚閒整，新樾已清漠。", "歡談一坐傾，遞飲百分涸。", "我亦醒而狂，遵溪縱行樂。", "晚駕方惜歸，正巾墜香萼。"]'),
('93c89c91-6e3b-46cc-b02c-75c0235cceb9','贈狄國寅','王洙','宋','宋诗','song-poetry','','[]','每讀梁公傳，青編日屢開。',48,'全唐诗/poet.song.11000.json','["每讀梁公傳，青編日屢開。", "神交慕英烈，自喜見雲來。", "一命須朝祿，連章薦楚材。", "凡昇黄綬秩，世代乃身媒。"]'),
('723df29c-328e-4a6b-89ed-3999008c06da','戲改杜贈鄭廣文詩','王洙','宋','宋诗','song-poetry','','[]','景純過官舍，走馬不曾下。',24,'全唐诗/poet.song.11000.json','["景純過官舍，走馬不曾下。", "驀地趁朝歸，便遭官長駡。"]'),
('2de0734a-1b96-4c7a-9291-bb63455a92c3','重建峴山羊侯祠歌','王洙','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','襄陽南出大路奔，小山曰峴名特尊。',384,'全唐诗/poet.song.11000.json','["襄陽南出大路奔，小山曰峴名特尊。", "山形卑墮不峻極，屹若巨首臨江濆。", "大山半空不成霍，絕水闕左非其亹。", "砠巔贔屭戴危石，箕踞曼衍羅芳蓀。", "漢流長騖濱其足，東望瀰迆皆平原。", "槎頭下瞰罟罶集，蔡洲近眺田園蕃。", "何物茲山匪秀出，得使今古聞聽喧。", "自昔羊公好登覽，山名直爲賢者存。", "鹿門望楚鎮區境，鳳林冠蓋延山樊。", "丹巖翠壁互幽勝，日月虧蔽煙嵐屯。", "公胡遺彼而樂此，談者未始聊診論。", "吾謂聖達意超豁，高覽便欲周乾坤。", "孔登泰山小天下，阮升廣武歎豎昏。", "會稽探穴禹書出，之罘望海雲濤翻。", "此中風景亦虛遠，極目見盡江山源。", "東吳未定勞機策，置酒嘯詠紓憂煩。", "數顧潤甫恤躬後，誓將百歲游清魂。", "對公盛德與山永，正唯湛輩如公言。", "今茲去公僅千載，凜然英氣猶軒軒。", "我來追古一長息，舊迹廢毀成悲吞。", "民豪占山童其木，嘉植不得容本根。", "利取薪蘇積稛絭，粥之陶瓬供燒燔。", "羊公無廟忽不祀，但縱淫鬼歆牲蘩。", "中庭有碑即墮淚，至今觀者懷仁恩。"]'),
('2d9ba40a-8641-49d3-895d-3c594d00321f','來燕堂聯句','王洙','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.11000.json','["無正文。"]'),
('35cf4e19-c5bf-4a23-9ef0-7ef20f229fb3','句','王洙','宋','宋诗','song-poetry','','[]','槐杪青蟲縋夕陽。',8,'全唐诗/poet.song.11000.json','["槐杪青蟲縋夕陽。"]'),
('a09868c2-bd5d-4953-9073-db0dc2c6f019','存目','王洙','宋','宋诗','song-poetry','','[]','詩題：贈日本國僧首句：滄波泛瓶錫。',17,'全唐诗/poet.song.11000.json','["詩題：贈日本國僧首句：滄波泛瓶錫。"]'),
('35ecfe6e-167b-462d-86b7-3a993e11cec8','佳城篇','狄遵度','宋','宋诗','song-poetry','','[]','佳城鬰鬰頹寒煙，孤雛乳兔號荒阡。',64,'全唐诗/poet.song.11000.json','["佳城鬰鬰頹寒煙，孤雛乳兔號荒阡。", "夜卧北斗寒挂枕，木落霜拱雁連天。", "浮雲西去伴落日，行客東盡隨長川。", "乾坤未死吾尚在，肯與蟪蛄論大年。"]'),
('36013cb5-6613-4a06-baa2-8767f0cfebf6','和渙之深秋月夜書事','狄遵度','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭葉下凉颼颼，凍天頑白凝不流。',64,'全唐诗/poet.song.11000.json','["洞庭葉下凉颼颼，凍天頑白凝不流。", "圓月擬缺不忍缺，輕露欲浮終未浮。", "憶吹朱籟鳳軿上，更采紫芝雲嶠陬。", "玉樓天半幾千尺，珠樹玲瓏懸上頭。"]'),
('56605dbb-7d76-4576-bb02-5b0a9a994cb8','雨','狄遵度','宋','宋诗','song-poetry','','[]','高林風怒雨聲黑，小閣燈背人語闌。',64,'全唐诗/poet.song.11000.json','["高林風怒雨聲黑，小閣燈背人語闌。", "誰知雲外月高照，定是葉間鶑最寒。", "時覺急飄愁未已，似聞徐滴喜初翻。", "驪駒北首榆關路，天晴煙樹沙磧寬。"]'),
('87354bc1-f184-4053-883c-b7f1f24ba6d8','登樓三首  其一','狄遵度','宋','宋诗','song-poetry','','[]','道之不行乘桴浮，赴河蹈海成今遊。',32,'全唐诗/poet.song.11000.json','["道之不行乘桴浮，赴河蹈海成今遊。", "春歸應到嶺北樹，日出先照天南樓。"]'),
('fb281eaf-096c-47c0-bcf4-60da63cc8d53','登樓三首  其二','狄遵度','宋','宋诗','song-poetry','','[]','羣山南走失所往，百川東逝茲其窮。',32,'全唐诗/poet.song.11000.json','["羣山南走失所往，百川東逝茲其窮。", "天低水國疑將壓，人過月塘愁欲空。"]'),
('87d3597d-fd90-4216-8748-33ad2dbb202e','登樓三首  其三','狄遵度','宋','宋诗','song-poetry','','[]','莎青石細淺見底，天空雲淡無一毫。',32,'全唐诗/poet.song.11000.json','["莎青石細淺見底，天空雲淡無一毫。", "波間圓月照不動，海上清風來最高。"]'),
('dea3b8e8-cf00-4fa2-b496-7a865a444424','詠芭蕉','狄遵度','宋','宋诗','song-poetry','','[]','植蕉低簷前，雙叢對含雨。',60,'全唐诗/poet.song.11000.json','["植蕉低簷前，雙叢對含雨。", "葉間求丹心，一日視百腑。", "胸中數寸赤，不惜爲君吐。", "心盡腹亦空，況復霜雪苦。", "非無後凋意，柔脆不足禦。"]'),
('d61b1dda-f669-4c6f-b21c-381bf1792228','看白雲愛而成詩','狄遵度','宋','宋诗','song-poetry','','[]','秋風吹白雲，觸處自何谷。',84,'全唐诗/poet.song.11000.json','["秋風吹白雲，觸處自何谷。", "初猶半洞門，欻出遍巖腹。", "零落依水湄，片段掛枯木。", "餘影透微白，滅跡混空綠。", "煙蘿自蘙密，島溆徒縈曲。", "安知蒼梧野，下覆猿鳥哭。", "誰能久徘徊，返顧視黄鵠。"]'),
('58aec669-43a8-4c21-abff-51278be850e8','謁孔先生','狄遵度','宋','宋诗','song-poetry','','[]','月出高樹枝，影動酒樽處。',72,'全唐诗/poet.song.11000.json','["月出高樹枝，影動酒樽處。", "樹深月色薄，稍以燈火助。", "主人喜我過，斟酌亦云屢。", "於時幸無累，所談非近務。", "凉風自遠至，清景淡吾慮。", "方期西山秋，歷覽陪杖屨。"]'),
('b17ecc26-714d-44f1-b851-8ff10dec974d','送鈐轄館使王公','程戡','宋','宋诗','song-poetry','','[]','歸騎翩翩去路賒，鬰蔥佳氣望天涯。',64,'全唐诗/poet.song.11000.json','["歸騎翩翩去路賒，鬰蔥佳氣望天涯。", "艱危劍閣三千里，惠愛刀州十萬家。", "龍尾道邊瞻日彩，鹿頭關外別春華。", "金明扈從宸遊處，休憶連年泛浣花。"]'),
('360465d1-83bc-4088-94aa-ee3513cfc674','送鈐轄館使王公','靳宗','宋','宋诗','song-poetry','','[]','再任坤維報政成，紫泥恩詔下神京。',64,'全唐诗/poet.song.11000.json','["再任坤維報政成，紫泥恩詔下神京。", "摇鞭有客添歸興，折柳何人不愴情。", "杜宇江山經鳥道，海棠池館憶龜城。", "尊前執手難收淚，投分從來比弟兄。"]'),
('fe013be7-036a-4703-8328-7bab80057dde','留題新建五雲亭','章岷','宋','宋诗','song-poetry','','[]','卧龍東嶺冠雲霞，亭面谿流對若耶。',64,'全唐诗/poet.song.11000.json','["卧龍東嶺冠雲霞，亭面谿流對若耶。", "秋霽獨先初夜月，春陰見盡滿城花。", "疏篁遶檻棲寒雀，喬木依簷泊暮鴉。", "紅燭未殘賓已醉，倚風歌管到人家。"]'),
('da48b6c1-16e6-41d6-be44-9bcb248427de','春日獨登蓬萊閣','章岷','宋','宋诗','song-poetry','','[]','郡閣高檐半納雲，危欄徙倚惜芳辰。',64,'全唐诗/poet.song.11000.json','["郡閣高檐半納雲，危欄徙倚惜芳辰。", "澄潮疊嶂新經雨，啼鳥開花各爲春。", "案有牋毫難賦景，席無歌管懶邀賓。", "自憐莫厭登臨數，即是葵丘代戍人。"]'),
('e73f9dba-a0e4-4975-ada1-894c913295ec','釣臺','章岷','宋','宋诗','song-poetry','','[]','乘興訪遺基，扁舟宿煙渚。',72,'全唐诗/poet.song.11000.json','["乘興訪遺基，扁舟宿煙渚。", "水凈寫天形，山空答人語。", "風篁自成韵，霜葉紛如雨。", "寒亭暮響清，饑猿夜啼苦。", "疑將洞府接，似與人寰阻。", "不羨重城中，喧喧聽笳鼓。"]'),
('c0e66258-eca1-45de-946b-fe8f8aa42181','陪范公登承天寺竹閣','章岷','宋','宋诗','song-poetry','','[]','古寺依山起，幽軒對竹開。',48,'全唐诗/poet.song.11000.json','["古寺依山起，幽軒對竹開。", "翠陰當晝合，凉氣逼人來。", "夜影疏排月，秋鞭瘦竹苔。", "雙旌容託乘，此地舉茶杯。"]'),
('330e557e-45f4-485f-89d8-67cc0adc0915','送梵才大師歸天台','章岷','宋','宋诗','song-poetry','','[]','故山蘿蔓鎖雲扉，幾夕扁舟已夢歸。',64,'全唐诗/poet.song.11000.json','["故山蘿蔓鎖雲扉，幾夕扁舟已夢歸。", "蓮社招賢移歲月，芝巖編句滿珠璣。", "金刀擁雪新彫鬢，香祴欺蘭舊賜衣。", "後夜吳門對霜月，懷師餘意在琴徽。"]'),
('58b9771c-ac21-4ad2-a695-1658e2ea680b','如歸亭','章岷','宋','宋诗','song-poetry','','[]','邑境人歌令尹賢，構亭裁址俯清漣。',64,'全唐诗/poet.song.11000.json','["邑境人歌令尹賢，構亭裁址俯清漣。", "風高送目帆侵日，秋霽凭闌水接天。", "越茗似雲邀客試，吳蓴如線佐庖鮮。", "政餘授館多投轄，費盡公田種秫錢。"]'),
('95b79ecb-e0c4-449e-9e54-e4378ed32218','六月吟','龔宗元','宋','宋诗','song-poetry','','[]','曦輪獵野枯杉松，火焚泰華雲如峰。',128,'全唐诗/poet.song.11000.json','["曦輪獵野枯杉松，火焚泰華雲如峰。", "天地爐中赤煙起，江湖喣沫烹魚龍。", "生獰渴獸脣焦斷，峻翮無聲落晴漢。", "饑民逃生不逃熱，血迸背皮流若汗。", "玉宇清宮徹羅綺，渴嚼冰壺森貝齒。", "炎風隔斷真珠簾，池口金龍吐寒水。", "象牀珍簟凝流波，瓊樓待月微酣歌。", "王孫晝夜縱娛樂，不知苦熱還如何。"]'),
('fd94fd61-ea17-443b-a075-47da5d0d02a1','夜宴','龔宗元','宋','宋诗','song-poetry','','[]','兔魄侵階夜三刻，蜀錦堆香花院窄。',80,'全唐诗/poet.song.11000.json','["兔魄侵階夜三刻，蜀錦堆香花院窄。", "風動簾旌玳瑁寒，露垂蟲網珍珠白。", "美人匝席羅弦管，綺幄雲屏爐麝暖。", "只恐金壺漏水空，不怕鸞觴琥珀滿。", "勸君莫負秉燭遊，曾見古人傷晝短。"]'),
('d50398e9-b8c2-4702-83dc-eced24e04ad2','贈處士林逋','龔宗元','宋','宋诗','song-poetry','','[]','高蹈遺塵蛻，含華傲素園。',48,'全唐诗/poet.song.11000.json','["高蹈遺塵蛻，含華傲素園。", "璜溪頻下釣，蕙帳不驚猿。", "養浩時清嘯，忘機只寓言。", "幾回生蝶翅，明月在西軒。"]'),
('af955774-4d19-401f-8de5-d5cfa20e36ef','送陳君子之四明','龔宗元','宋','宋诗','song-poetry','','[]','短亭祖帳接平川，柳拂回波繫畫船。',64,'全唐诗/poet.song.11000.json','["短亭祖帳接平川，柳拂回波繫畫船。", "漸向落暉分繡袖，忍聽離曲怨鵾弦。", "雲連稽嶺應懷古，路近花源好訪仙。", "那更憑高望天際，江堤煙重草綿綿。"]'),
('1dd996dd-4b65-4dd9-9a70-702bad90fa23','擣砧詞','龔宗元','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','星河耿耿寒煙浮，白龍銜月臨霜樓。',128,'全唐诗/poet.song.11000.json','["星河耿耿寒煙浮，白龍銜月臨霜樓。", "誰家砧弄細腰杵，一聲擣破江城秋。", "雙桐老翠墮金井，高低冷逐西風緊。", "靜如秋籟暗穿雲，天半驚鴻斷斜影。", "哀音散落愁人耳，何處離情先喚起。", "長信宮中葉滿階，洞庭湖上波平水。", "萬里征夫眠未成，摇風擣月何丁丁。", "楚關秦嶺有歸客，一枕夜長無限情。"]'),
('b68e31f1-7748-45dd-897b-ae400193b758','送僧歸護國寺','張肅','宋','宋诗','song-poetry','','[]','去謁吾君遇太平，太平明主重南能。',64,'全唐诗/poet.song.11000.json','["去謁吾君遇太平，太平明主重南能。", "不關名利真開士，却返林泉伴野僧。", "御賜白金爲長物，身歸青嶂策枯藤。", "只應待到天台日，齋炷檀烟定有燈。"]'),
('dd5f9291-a335-4d92-9153-92036d937cce','題釣臺','邵炳','宋','宋诗','song-poetry','','[]','光武休戈詔子陵，高臺時暫別煙汀。',32,'全唐诗/poet.song.11000.json','["光武休戈詔子陵，高臺時暫別煙汀。", "當時四海皆臣妾，獨有先生占客星。"]'),
('53b2c5b2-bf7c-45f8-ba48-a896ee27ba03','酬通判楊殿丞名霖巖洞','邵炳','宋','宋诗','song-poetry','','[]','雲峰千仞對吾廬，洞古名新郡守書。',32,'全唐诗/poet.song.11000.json','["雲峰千仞對吾廬，洞古名新郡守書。", "須信神靈知受賜，先興霖雨遠隨車。"]'),
('a61de63a-4220-4322-b5b3-2fc32ab7da76','蓮花峰','林杞','宋','宋诗','song-poetry','','[]','天開八葉蓮花峰，神龜引子巢其中。',32,'全唐诗/poet.song.11000.json','["天開八葉蓮花峰，神龜引子巢其中。", "千年皮骨老化石，玉色不與凡工同。"]'),
('fa71a55b-68ba-4300-9466-01a9862c4b56','遊碧落洞','王陶','宋','宋诗','song-poetry','','[]','尋幽碧落外，此境真洞天。',48,'全唐诗/poet.song.11000.json','["尋幽碧落外，此境真洞天。", "乳竇穿碧澗，葆樹蒙塞煙。", "迹與氛𡏖絕，身亡名利纏。", "日暮嬾回首，遲拍洪崖肩。"]'),
('d51f7e3e-6859-49a0-9c33-f6f2d6c91f0a','北牖洞','孫抗','宋','宋诗','song-poetry','','[]','舊駐東方騎，因題北牖名。',48,'全唐诗/poet.song.11000.json','["舊駐東方騎，因題北牖名。", "來須風作御，去認斗爲城。", "日氣晚方到，雲收寒易生。", "予心匪游衍，拱北振華纓。"]'),
('413ebc0a-35cf-4540-ac55-7252ae1e16d0','白雀洞','孫抗','宋','宋诗','song-poetry','','[]','禽貴羽毛潔，地憐巖壑幽。',48,'全唐诗/poet.song.11000.json','["禽貴羽毛潔，地憐巖壑幽。", "名非華陰凍，景似秀林秋。", "不睹音塵繼，空驚歲月遒。", "何如潁川鳳，千古冠緹油。"]'),
('986c9686-b27c-4230-b319-265cd0a94e7b','南華洞','孫抗','宋','宋诗','song-poetry','','[]','峭徑入蒼烟，他山盡一拳。',48,'全唐诗/poet.song.11000.json','["峭徑入蒼烟，他山盡一拳。", "上盤朱鳥翼，中寓漆園仙。", "清可携壺賞，凉堪拂石眠。", "九疑生接境，曾此按薰弦。"]'),
('1ce274f0-d12c-4964-82f3-6d985d260422','朝陽洞','孫抗','宋','宋诗','song-poetry','','[]','險絕信天開，春蘿蔭古苔。',48,'全唐诗/poet.song.11000.json','["險絕信天開，春蘿蔭古苔。", "不愁雲影閉，先得日光來。", "片石充棋局，凉坡遞酒杯。", "東風偏著意，草木爛成堆。"]'),
('158f51c5-2434-4664-ab1f-74461918a8a2','嘉蓮洞','孫抗','宋','宋诗','song-poetry','','[]','地應連海眼，終古蓄寒泉。',48,'全唐诗/poet.song.11000.json','["地應連海眼，終古蓄寒泉。", "四列青蒼壁，雙開菡萏蓮。", "已嗟真賞去，猶訝昔香傳。", "未媿東林下，霜葩社衆賢。"]'),
('49447564-f2b8-49e9-bda7-6daaa8c9ad3c','夕陽洞','孫抗','宋','宋诗','song-poetry','','[]','塵寰雖未遠，顥氣覺偏滋。',48,'全唐诗/poet.song.11000.json','["塵寰雖未遠，顥氣覺偏滋。", "日落鳥歸去，秋高風勁時。", "吟餘下天籟，坐久凜冰肌。", "信是棲幽境，凉蟾照履綦。"]'),
('9e27d343-078b-489d-b2d1-5cd3e3df93a6','棲霞洞','孫抗','宋','宋诗','song-poetry','','[]','寬踰城闕峻瑶魁，萬壑吟風四壁苔。',32,'全唐诗/poet.song.11000.json','["寬踰城闕峻瑶魁，萬壑吟風四壁苔。", "不獨雲霞可招隠，溪流常送落花來。"]'),
('5a0f27eb-8db1-4ccb-89d7-79e6858f1559','峴山','孫抗','宋','宋诗','song-poetry','','[]','天下名山數南國，峴首首推襄漢域。',320,'全唐诗/poet.song.11000.json','["天下名山數南國，峴首首推襄漢域。", "前年假節使湖外，道出銅鞮一攀陟。", "檀溪西下烟雨繁，夢澤南迴雲霧織。", "絕壁頹巖畫障開，陽林雜蘤天光逼。", "飄然不減京臺樂，城闕弦歌野耕植。", "借問人心誰見思，雲來遠庇羊公德。", "乃知仁愛與山俱，奚用沈碑衒金刻。", "追詢耆舊訪祠宇，遲拜丹青紀聰直。", "佛藍神館鬰相望，獨此寂寥遺肸飾。", "欒公燕國戚藩佐，朱邑桐鄉嗇夫職。", "居民立社中詔嘉，撫舊勸來區淑慝。", "指期還臺首章奏，立使閟宮膋血食。", "半途得郡旋治中，迴睇鳳林空太息。", "仙郎作鎮未朞月，起廢補亡罄心力。", "凡予所欲塵黈聰，文符一一條其極。", "庚桑畏壘既禋薦，魯國靈光亦顛踣。", "由晉至今更幾秋，隼畫干旟熊伏軾。", "但矜□□□形勝，誰祀賢人思物色。", "公當□□乃□□，只□徊翔預倫□。", "漢波平遠山巍然，共仰羊王譽充□。"]'),
('65b541f9-3458-4452-a89e-ac7394a21880','和孔司封題蓬萊閣','趙諴','宋','宋诗','song-poetry','','[]','龍卧山形滴翠微，翬飛閣勢搆空危。',64,'全唐诗/poet.song.11000.json','["龍卧山形滴翠微，翬飛閣勢搆空危。", "六鼇不是湖中蟄，一島疑從海上移。", "屏障牋毫吟詠處，神仙羅綺燕遊時。", "自慚爲吏非香案，又躡雲梯從使麾。"]'),
('00f8e5d0-9ec2-4e12-a202-130cae54dc0f','遊雲門寺','趙諴','宋','宋诗','song-poetry','','[]','竟夕雨聲寒，黎明日氣暄。',48,'全唐诗/poet.song.11000.json','["竟夕雨聲寒，黎明日氣暄。", "峰巒添積潤，谿澗漲新痕。", "鐘鼓連三寺，杉松共一邨。", "不須遊賞徧，麗句滿清軒。"]'),
('08db09b0-daa5-4fd7-bb5d-a58777fdcdfb','遊天衣寺','趙諴','宋','宋诗','song-poetry','','[]','世稱幽景屬金仙，若是精藍豈妄傳。',64,'全唐诗/poet.song.11000.json','["世稱幽景屬金仙，若是精藍豈妄傳。", "澗湧雙泉雷出地，山圍四面管窺天。", "唐僧手澤神毫健，梁帝宸恩寶器妍。", "今日喜償平昔志，更逢閩客此安禪。"]'),
('625a6dd1-609d-42e4-81de-4bebac1238df','遊戒珠寺','趙諴','宋','宋诗','song-poetry','','[]','欲遊城郭應難遍，每訪湖山亦自勞。',32,'全唐诗/poet.song.11000.json','["欲遊城郭應難遍，每訪湖山亦自勞。", "坐致眼前無限景，僧房寄處蕺峰高。"]'),
('d83feeb5-66a2-4ac2-8756-e7ca6c9cbd74','毘藍巖','盛奇','宋','宋诗','song-poetry','','[]','別開洞壑翠微齊，蘿薜雲深路轉迷。',32,'全唐诗/poet.song.11000.json','["別開洞壑翠微齊，蘿薜雲深路轉迷。", "一榻繁陰炎掃午，六秋巖畔足幽棲。"]'),
('01a39193-386b-4e63-84e5-f497f04c6841','和范公同章推官登承天寺竹閣','阮逸','宋','宋诗','song-poetry','','[]','竹石寒相倚，雲窗曉共開。',48,'全唐诗/poet.song.11000.json','["竹石寒相倚，雲窗曉共開。", "閑身方外去，幽意靜中來。", "墜響風隨籜，移陰日上苔。", "遲留秋更夜，待月露盈杯。"]'),
('9c96121b-58f7-4a6b-9c8c-45b97773a314','句','阮逸','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','易立泰山石，難枯上林柳。',12,'全唐诗/poet.song.11000.json','["易立泰山石，難枯上林柳。"]'),
('79b36b1d-d8ed-4781-b22e-e294cad3e054','存目','阮逸','宋','宋诗','song-poetry','','[]','詩題：題竹閣首句：僧閣倚寒竹。',15,'全唐诗/poet.song.11000.json','["詩題：題竹閣首句：僧閣倚寒竹。"]'),
('9b0765de-4b62-46d9-bfe7-00ff1d3cf629','寺中聞射因成','丘濬','宋','宋诗','song-poetry','','[]','殿宇時聞燕雀喧，虛庭盡日少人行。',32,'全唐诗/poet.song.11000.json','["殿宇時聞燕雀喧，虛庭盡日少人行。", "孤吟獨坐情何限，時喜風傳中鵠聲。"]'),
('305583cb-4b46-4461-a98e-c19ffbd3daab','儀真太守召看牡丹','丘濬','宋','宋诗','song-poetry','','[]','何事化工情愈重，偏教此卉大妖妍。',64,'全唐诗/poet.song.11000.json','["何事化工情愈重，偏教此卉大妖妍。", "王孫欲種無餘地，顔巷安貧欠買錢。", "曉檻競開香世界，夜闌誰結醉因緣。", "須知村落桑耘處，田叟饑耕婦不眠。"]'),
('3fd7c6a0-9c44-4768-ba46-51cb5f0c369c','贈五羊太守','丘濬','宋','宋诗','song-poetry','','[]','碧睛蠻婢頭蒙布，黑面胡兒耳带環。',32,'全唐诗/poet.song.11000.json','["碧睛蠻婢頭蒙布，黑面胡兒耳带環。", "幾處樓臺皆枕水，四周城郭半圍山。"]'),
('e58dd21d-da37-4d4d-86b2-d1c5a8b7287d','秩滿寄茅山道友','丘濬','宋','宋诗','song-poetry','','[]','鳴鳳相邀覽德輝，松蘿從此與心違。',64,'全唐诗/poet.song.11000.json','["鳴鳳相邀覽德輝，松蘿從此與心違。", "孤峰萬仞月正照，古屋數間人未歸。", "欲助唐虞開有道，深慚巢許勸忘機。", "明朝又引輕帆去，紫朮年年空自肥。"]'),
('44cf9c7b-dd3c-489e-9f67-9a2f2ba6e3d8','題聖果寺介亭詩','丘濬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','金商肅肅淬龍淵，白曉揮開東北天。',384,'全唐诗/poet.song.11000.json','["金商肅肅淬龍淵，白曉揮開東北天。", "天孫引下翡翠煙，層層堆列參井邊。", "便於裸壤蟠危巔，城雉岧嶢暗接連。", "地祇欲誇融結權，蘚花斸破蟄蟲遷。", "皮刳骨露判混元，一支一節相貫穿。", "洞庭波浪徹底乾，驅來不用暴秦鞭。", "大者臲尯下騰騫，尊卑序立鴻雁聯。", "欲覲曜寶禮法專，貘豹甝虎競差肩。", "稟命踧蹜未敢前，精神張王腰攣拳。", "霸臣納土窮海堧，怪狀埋沒幾百年。", "中和有美既爭先，磷磷丹漆排雕椽。", "太守擇之繼曩賢，念此嵌空清且堅。", "遽於峭絕創墀軒，名之以介非徒然。", "介是長男變初世，六二爻辭藴深祕。", "重門待暴乃其卦，未兆未萌堪畏避。", "公性中正仍盡瘁，悔吝何憂憂道義。", "道義興行皇綱備，乃是擇之之本志。", "平湖巨浸六幕寬，此時非獨圖宴憙。", "暑月芙蓉秋月濤，截斷風光千百里。", "鵬雲沆瀣南北透，離朱瞪目曠傾耳。", "料公豈戀葦苕地，才業施爲自茲始。", "或借前筯或赤箠，式遏蠻戎順文軌。", "炎上潤下火兼水，無燥無烈無圮毀。", "張衡巧製塵灰纍，八虬困睡金丸止。"]'),
('f93a7c77-b65a-4dc8-8fea-24f181230766','詠錢塘','丘濬','宋','宋诗','song-poetry','','[]','南屏高瞰府城西，畫舸千艘共醉迷。',64,'全唐诗/poet.song.11000.json','["南屏高瞰府城西，畫舸千艘共醉迷。", "四柱臺邊煙是幕，百花橋畔葑連隄。", "龍檀咽路迎輿隼，綺繡登山汙粉題。", "暮色沈沈郛郭閉，寶燈輝映梵天低。"]'),
('89b38bf0-419f-4464-8226-08cd75546ca3','登西湖北樓  其一','丘濬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','尋遊心緒忍闌珊，高處重登始是觀。',64,'全唐诗/poet.song.11000.json','["尋遊心緒忍闌珊，高處重登始是觀。", "晚吹劃開三面碧，晨曦收住一天寒。", "南屏洞戶蘿陰合，東極鼇峰雪浪漫。", "遠近聲形窮不得，離朱師曠漫凭欄。"]'),
('8a277349-9249-4a65-8509-65b6b76813e5','登西湖北樓  其二','丘濬','宋','宋诗','song-poetry','','["\u897f\u6e56"]','澄霽無涯混一區，似開塵網到華胥。',64,'全唐诗/poet.song.11000.json','["澄霽無涯混一區，似開塵網到華胥。", "圖抨水墨煙昏處，國占清凉月上初。", "雲夢澤寬城邑遠，華嚴川好酒胥疏。", "祇期擺脫名韁了，來約真仙傍此居。"]'),
('0177fc70-62c4-400a-85c8-9d2e8bbe014d','句  其一','丘濬','宋','宋诗','song-poetry','','[]','春雲片片揭新綿。',8,'全唐诗/poet.song.11000.json','["春雲片片揭新綿。"]'),
('d56a59a8-68c6-494b-a143-645e46c10948','句  其二','丘濬','宋','宋诗','song-poetry','','[]','醜却天下美人面，正得世間君子心。',16,'全唐诗/poet.song.11000.json','["醜却天下美人面，正得世間君子心。"]'),
('b04e0c6a-1452-469c-a8b4-88191c133ac1','句  其三','丘濬','宋','宋诗','song-poetry','','[]','階上腥臊堆蜆子，口中濃血吐檳榔。',16,'全唐诗/poet.song.11000.json','["階上腥臊堆蜆子，口中濃血吐檳榔。"]'),
('fb303165-2fee-402b-9b99-1ea74170ad0f','句  其四','丘濬','宋','宋诗','song-poetry','','[]','風腥蠻市合，日上瘴雲紅。',12,'全唐诗/poet.song.11000.json','["風腥蠻市合，日上瘴雲紅。"]'),
('da56736f-83d9-4119-bcb6-f03057bd32c8','句  其五','丘濬','宋','宋诗','song-poetry','','[]','郭京楊式劉無忌，皆在東南卧白雲。',16,'全唐诗/poet.song.11000.json','["郭京楊式劉無忌，皆在東南卧白雲。"]'),
('cfbd8bf6-1133-4030-ac9f-9afc5e83bc21','行次鳳州','李之才','宋','宋诗','song-poetry','','[]','去年三月洛城遊，今日尋春到鳳州。',32,'全唐诗/poet.song.11000.json','["去年三月洛城遊，今日尋春到鳳州。", "欲托雙魚附歸信，嘉陵江水不東流。"]'),
('a6a22113-d275-4df9-a1d4-146161eedb6a','奉答懃師山中見寄','李之才','宋','宋诗','song-poetry','','[]','羨子幽棲地，空山十月天。',48,'全唐诗/poet.song.11000.json','["羨子幽棲地，空山十月天。", "清簷朝飯後，寒壁夜深禪。", "霜樹留殘果，冰崖斷舊泉。", "劉雷好爲社，邑客有誰賢。"]'),
('5de95e90-1d0c-41d3-94a1-ab6ecee94f41','和運司園亭 西園','孫甫','宋','宋诗','song-poetry','','[]','外臺富園池，茲焉甲西南。',48,'全唐诗/poet.song.11000.json','["外臺富園池，茲焉甲西南。", "異花間棠梅，良木森楩楠。", "飄飄壺中仙，亹亹物外談。", "聯毫賦詩題，刻石留翠龕。"]'),
('24e389f6-4ff9-47c3-b9b1-ac73861f9aa8','和運司園亭 玉谿堂','孫甫','宋','宋诗','song-poetry','','[]','華堂殿方池，雅名題玉谿。',48,'全唐诗/poet.song.11000.json','["華堂殿方池，雅名題玉谿。", "南榮翠樾陰，北望花島低。", "時聞細泉鳴，間或幽鳥啼。", "深宜世外人，冥坐窺天倪。"]'),
('12430721-4f41-465c-b4cf-89a1ade02b7d','和運司園亭 雪峰樓','孫甫','宋','宋诗','song-poetry','','[]','金穀計浩穰，山水志契闊。',48,'全唐诗/poet.song.11000.json','["金穀計浩穰，山水志契闊。", "晴空倚危樓，快對西山雪。", "胸中浩氣充，物外囂塵絕。", "無事坐清吟，遠岫窗中列。"]'),
('7b204449-3ee5-4227-9be3-7b146c430684','和運司園亭 海棠軒','孫甫','宋','宋诗','song-poetry','','[]','高軒瞰方池，澄波隔瑣窗。',48,'全唐诗/poet.song.11000.json','["高軒瞰方池，澄波隔瑣窗。", "中島植奇花，鮮逾濯錦江。", "水府集羣仙，紅雲罩翠幢。", "畫圖入禁庭，榮耀知無雙。"]'),
('0f89a6a8-44b4-4e87-bdea-394a6a2857c4','和運司園亭 月臺','孫甫','宋','宋诗','song-poetry','','[]','俗流嗜喧卑，世才務高潔。',48,'全唐诗/poet.song.11000.json','["俗流嗜喧卑，世才務高潔。", "築臺僅踰尋，清夜延明月。", "四垂天幕低，千里蟾光發。", "美人□□才，裁賦何清絕。"]'),
('210da96a-8b49-42bf-9303-ac50fa51dad4','和運司園亭 翠錦亭','孫甫','宋','宋诗','song-poetry','','[]','森森棟梁材，駢空翥鸞鳳。',48,'全唐诗/poet.song.11000.json','["森森棟梁材，駢空翥鸞鳳。", "危亭搆其間，曾不礙梁棟。", "檐陰織翠紋，砌溜諧清弄。", "攤飯宜晝眠，一枕華胥夢。"]'),
('5ca340eb-4646-4885-b875-ca26e2f5425d','和運司園亭 潺玉亭','孫甫','宋','宋诗','song-poetry','','[]','回環引細泉，泉聲漱檐底。',48,'全唐诗/poet.song.11000.json','["回環引細泉，泉聲漱檐底。", "美哉知者心，清通樂流水。", "琤琮戛鳴球，淅瀝泛綠綺。", "塵慮無由得，何須洗雙耳。"]'),
('5d88227d-d64e-4d0d-b783-8eb27b496c81','和運司園亭 茅菴','孫甫','宋','宋诗','song-poetry','','[]','結茅作禪菴，不卑亦不廣。',48,'全唐诗/poet.song.11000.json','["結茅作禪菴，不卑亦不廣。", "地占官府雄，盤基才袤丈。", "几席供燕閒，松筠助蕭爽。", "座有逍遥公，虛中息塵想。"]'),
('ca7cb246-e0d8-4612-9011-86397c25df5f','和運司園亭 水閣','孫甫','宋','宋诗','song-poetry','','[]','小閣聯雪峰，憑欄憙幽玩。',48,'全唐诗/poet.song.11000.json','["小閣聯雪峰，憑欄憙幽玩。", "紅接海棠洲，綠對篔簹岸。", "有時開罇罍，波影侵几案。", "何須架長虹，然後沖霄漢。"]'),
('986c6f90-7b88-43fb-9646-d313ca8b845d','和運司園亭 小亭','孫甫','宋','宋诗','song-poetry','','[]','蕭森玉谿南，小亭屹相向。',48,'全唐诗/poet.song.11000.json','["蕭森玉谿南，小亭屹相向。", "使華雙軺車，禪境二方丈。", "固將物理齊，室隘志自廣。", "松竹周四簷，足以備幽賞。"]'),
('9cf8431c-60f5-4bae-bf06-580e746f91ef','句','孫甫','宋','宋诗','song-poetry','','[]','衰病自憐無酒趣，塵容猶頼有詩情。',16,'全唐诗/poet.song.11000.json','["衰病自憐無酒趣，塵容猶頼有詩情。"]'),
('72374072-630a-46be-8685-897bc9fc99e7','順祀詩','宋祁','宋','宋诗','song-poetry','','[]','孰順其祀，明明天子。',248,'全唐诗/poet.song.11000.json','["孰順其祀，明明天子。", "天子謙讓，詔羣臣其議。", "惟章獻、章懿，遂祔先帝。", "宜索而典，而古而今。", "順考攸宜，慰我孝心。", "羣臣稽首，不遠厥成。", "伊先猷是程，伊大孝是經。", "匪祥符孰從，則莫我京。", "三代廟寢，止一帝后。", "漢制已遷，儒臣罔究。", "禮缺不稱，因樸趨陋。", "親靡祔尊，神挈斯祐。", "帝曰俞哉，予奉二慈。", "匪曰無典，實成訓是依。", "促灼爾龜，爰蕝爾儀。", "琢金追玉，昭款信辭。", "不敢先後，惟以順躋。", "孟冬十月，大饗其時。", "朕不憚勤，于庭遣之。", "吉日辛酉，帝自文德。", "至于大慶，奉寶授冊。", "永懷劬勞，孝貫天極。", "虞賓在位，百官承式。", "顯顯太歲，惟冊寶是將。"]'),
('e34c147f-3ccd-4484-8494-30b9cfb85471','上許州呂相公嗣崧許康詩二首 嗣崧詩 其一','宋祁','宋','宋诗','song-poetry','','[]','彼嶽惟崧，天作其神。',50,'全唐诗/poet.song.11000.json','["彼嶽惟崧，天作其神。", "嗣生我公，我公斤斤。", "嘉猷矢陳，柄國之均。", "帝親命之，纂成前人。", "不顯其道，惟申是保。"]'),
('74ab31f8-dd45-4246-ac10-9741ae252179','上許州呂相公嗣崧許康詩二首 嗣崧詩 其二','宋祁','宋','宋诗','song-poetry','','[]','公邁厥德，祗祗翼翼。',50,'全唐诗/poet.song.11000.json','["公邁厥德，祗祗翼翼。", "柔嘉而直，模我彝倫。", "揉我方國，施于夷貊。", "百度是毗，庶績允熙。", "罔敢不恪，惟公是若。"]'),
('de8547f6-9022-4302-83dd-a71ce804a122','上許州呂相公嗣崧許康詩二首 嗣崧詩 其三','宋祁','宋','宋诗','song-poetry','','[]','帝詔執事，徹申土疆，衍沃腴良。',50,'全唐诗/poet.song.11000.json','["帝詔執事，徹申土疆，衍沃腴良。", "賦輿溱溱，莫樂于申。", "昔在四岳，佑堯象禹，爲國心膂。", "受民作邦，于今以光。"]'),
('301813f9-3063-450e-81a4-221cfc7321a8','上許州呂相公嗣崧許康詩二首 嗣崧詩 其四','宋祁','宋','宋诗','song-poetry','','[]','帝告于公，紹胥爾宇。',51,'全唐诗/poet.song.11000.json','["帝告于公，紹胥爾宇。", "憲是文武，如申如甫，爲周之輔。", "誕錫爾祉，惟申甫是似。", "乘車錯衡，淑施英英，式遄其榮。"]'),
('ed117120-50ab-4dd7-b2ba-824fbb374de2','上許州呂相公嗣崧許康詩二首 嗣崧詩 其五','宋祁','宋','宋诗','song-poetry','','[]','公拜稽首，敢揚王休。',53,'全唐诗/poet.song.11000.json','["公拜稽首，敢揚王休。", "祈天之久，爲天子萬壽。", "彼嶽磐磐，松柏丸丸，公福祿實蕃。", "有崇而岡，有大而陵，公壽考是承。"]'),
('bc7ea29e-3811-4c4b-8682-068703b1f116','上許州呂相公嗣崧許康詩二首 許康詩 其一','宋祁','宋','宋诗','song-poetry','','[]','許麗而康，岳孫奠之。',60,'全唐诗/poet.song.11000.json','["許麗而康，岳孫奠之。", "曰公之屏，實維似之。", "公徒增增，朱綅綠縢。", "不戁不驚，鉤膺鏤錫。", "稱娖顔行，噦焉綏章。", "總我列侯，式時南疆。"]'),
('98210ce1-e8f3-4b97-b218-05a91e2d05f8','上許州呂相公嗣崧許康詩二首 許康詩 其二','宋祁','宋','宋诗','song-poetry','','[]','公之相攸，孔樂于許。',60,'全唐诗/poet.song.11000.json','["公之相攸，孔樂于許。", "其原膴膴，其川訏訏。", "有芃禾麻，有京稷黍。", "藪焉麋麕，渚焉魴鱮。", "有李有桃，有柘有檀。", "樹我之園，令居則安。"]'),
('4061235d-983c-4d26-b585-5d8d39f08b22','上許州呂相公嗣崧許康詩二首 許康詩 其三','宋祁','宋','宋诗','song-poetry','','[]','公視于庭，師兵翼翼，孔武有力。',60,'全唐诗/poet.song.11000.json','["公視于庭，師兵翼翼，孔武有力。", "公適于府，陪卿髦士，罔不就緒。", "公宴于堂，嘉賓我從。", "琴瑟鼓鐘，或揳或摐。", "靜好鏗鏘，萬舞有容。"]'),
('e4160126-f894-4b2d-a9cb-dda49544c443','上許州呂相公嗣崧許康詩二首 許康詩 其四','宋祁','宋','宋诗','song-poetry','','[]','左拂其殽，炰鼈燔羔，給鮮于庖。',60,'全唐诗/poet.song.11000.json','["左拂其殽，炰鼈燔羔，給鮮于庖。", "右烹其蔌，筍菭蒲葅，柔嘉惟馥。", "旨酒且多，其飲溫克。", "攝爾攸儀，侑公宴嬉。", "俾胖而樂，俾艾而耆。"]'),
('3ff05311-720c-468b-a167-dbd621f0fae9','上許州呂相公嗣崧許康詩二首 許康詩 其五','宋祁','宋','宋诗','song-poetry','','[]','明明天子，股肱一體。',63,'全唐诗/poet.song.11000.json','["明明天子，股肱一體。", "于蕃于宣，邦人咸喜。", "主芣之山，浚{氵冀}之渠。", "弗童而材，弗竭而漁。", "皇惠斯人，俾公焉依。", "公報其成，帝曰還歸。"]'),
('1f1a4751-d231-4d6c-80b5-38fbf98ebc7e','夜直省舍','宋祁','宋','宋诗','song-poetry','','[]','省舍諸吏休，前軒成獨步。',84,'全唐诗/poet.song.11000.json','["省舍諸吏休，前軒成獨步。", "月色凈牟首，星痕隠溫樹。", "稍聽班馬鳴，猶見昏鴉度。", "索居易興感，幽抱邈誰晤。", "自問遊落姿，胡攖文墨務。", "企歡無剩娛，即事有盈慮。", "遠寄江海心，冷風儻能御。"]'),
('889c8e5a-13df-481b-ac69-8366bd37ffa0','省舍晚景','宋祁','宋','宋诗','song-poetry','','[]','日稷城陰生，塵露稍云歇。',60,'全唐诗/poet.song.11000.json','["日稷城陰生，塵露稍云歇。", "密樹抱烟沈，高禽映天沒。", "外物既不擾，清機亦徐發。", "何意羲皇風，吹我襟袖末。", "少駐北堂陲，娟娟待明月。"]'),
('878c8d6f-066f-4bc8-9c30-00f23a42503e','正言田學士況書言上庠祭酒廳北軒予所種竹滋茂','宋祁','宋','宋诗','song-poetry','','[]','昔承上庠乏，蒔竹北堂軒。',120,'全唐诗/poet.song.11000.json','["昔承上庠乏，蒔竹北堂軒。", "飭吏勤浸灌，冉冉榮孤根。", "日晏到官下，對賞忘塵喧。", "海月影宵戺，天風籟晨顛。", "去年主人斥，負謗爲淮藩。", "後來異好尚，欲諉不敢宣。", "何幸覯時哲，乃加封殖恩。", "千里走書驛，語竹遥相存。", "不才好冷局，異日期歸旋。", "千萬屏剪伐，勿令孤願言。"]'),
('a4897636-824c-4290-928a-3659034f530d','仲夏愆雨穉苗告悴輒按先帝詔書繪龍請雨兼禱霍山淮瀆二祠戊寅蕆祀己卯獲雨謹成喜雨詩呈官屬','宋祁','宋','宋诗','song-poetry','','[]','盛夏挾驕陽，于以搆炎熯。',288,'全唐诗/poet.song.11000.json','["盛夏挾驕陽，于以搆炎熯。", "歊塵坌天蓋，烈御煽雲漢。", "稻穎茁然秀，涸流不勝灌。", "田畯卹歲功，釋耒共愁歎。", "太守忝農使，閉閣重慚惋。", "曾是謬政綱，曾是濫囚犴。", "一食三失匕，冀亦思過半。", "馳祝訴羣望，願以身塞譴。", "先帝隠民癠，致和格靈變。", "圖龍著繪法，令甲布州縣。", "愚計不知出，奉行安敢慢。", "外日築層壇，丙夜封舒雁。", "奉匜再三跪，信辭靡虛薦。", "幸勿爲龍羞，敢不報神眷。", "翼日耿弗寐，徂野視宵奠。", "幽血粲靜蠲，執事便傳讚。", "薄誠蒙昭享，距躍私自忭。", "回車未及稅，雲油默焉徧。", "窮海遂涔涔，籠山茲漫漫。", "旱麓衆卉蘇，焦原暍氛散。", "寸苗蔚如揠，新波鱗欲渙。", "何意一溉窘，有望千箱衍。", "揆予乏嘉績，聖詔仰成憲。", "恤祀神罔恫，昏作人胥勸。"]'),
('c6a957f7-35d6-4bb0-a6e2-644ea93d9179','長葛道中作寄侍讀梅給事','宋祁','宋','宋诗','song-poetry','','[]','仲春告言歸，道次古長葛。',159,'全唐诗/poet.song.11000.json','["仲春告言歸，道次古長葛。", "水窮既舍舟，僕具始脂轄。", "南登高原望，天宇莽庨豁。", "溱{氵冀}澹無波，芣騩森相軋。", "春鳩日夜鳴，陽膏淺深達。", "田畯挈壺漿，稚子勤襫襏。", "驅牛灑先稑，趣車載輸秸。", "郊柘色欣欣，梢溝流活活。", "縣官恩澤美，農節未嘗奪。", "賢牧謹詔書，民隠罔遺察。", "射蠲贅聚勞，賦檢誅求猾。", "我亦占一廛，聞茲慰饑渴。", "矢詩雖不多，要附許風末。"]'),
('d92f1c78-6c6f-4d46-99b6-db9113de4a5e','去郡作','宋祁','宋','宋诗','song-poetry','','[]','解龜淮陽區，浮鷁暮春月。',108,'全唐诗/poet.song.11000.json','["解龜淮陽區，浮鷁暮春月。", "州民擁前道，重爲使君別。", "尊酒却略跪，絲管參差發。", "共謂君此行，寵命煥朝節。", "進伏丹泥戺，勉之奮芳烈。", "使君慚且嗟，處躬素衷拙。", "雖爾荷賜環，安敢冀榮轍。", "頓首謝上畢，行當避時傑。", "願移邦人愛，孤根保勿伐。"]'),
('f7ff4a19-1621-4072-b47c-c2a9783d19c3','壽州十詠 熙熙閣','宋祁','宋','宋诗','song-poetry','','[]','東譙已自高，復此構層宇。',48,'全唐诗/poet.song.11000.json','["東譙已自高，復此構層宇。", "誰謂淮南遠，風物美無度。", "飛岑納晝碧，流月遺宵素。", "揆予乏仙氣，樓居庶可慕。"]'),
('1777a952-0eef-439f-8aab-e3b24c924935','壽州十詠 白蓮堂','宋祁','宋','宋诗','song-poetry','','[]','堂皇敞而華，簷牙照池水。',48,'全唐诗/poet.song.11000.json','["堂皇敞而華，簷牙照池水。", "鈿葉矗新團，玉莩粲繁蘤。", "游鱗竟潑潑，幽石仍齒齒。", "寄言採秋芳，何必涉江涘。"]'),
('a2bddf77-42d3-4e82-8398-26c2491c1287','壽州十詠 春暉亭','宋祁','宋','宋诗','song-poetry','','[]','涉園憇何處，道左蔭華榱。',48,'全唐诗/poet.song.11000.json','["涉園憇何處，道左蔭華榱。", "幽尋乏朋往，勝晤徒自知。", "文禽弄不歇，惠風至無期。", "含情重徙倚，物色到霞霏。"]'),
('f47d56e2-93a6-42d4-a2a1-45f52ccb1947','壽州十詠 式燕亭','宋祁','宋','宋诗','song-poetry','','[]','使君班春還，于焉衎吾屬。',48,'全唐诗/poet.song.11000.json','["使君班春還，于焉衎吾屬。", "四阿住翬棘，聊以便凉燠。", "棟表飛雲逝，題端邀月宿。", "無德與斯人，式宴良自恧。"]'),
('5c351ea2-a35a-4e53-9135-631e3493faa8','壽州十詠 秋香亭','宋祁','宋','宋诗','song-poetry','','[]','蘭菊被秋坂，危宇冠層巔。',48,'全唐诗/poet.song.11000.json','["蘭菊被秋坂，危宇冠層巔。", "雜樹自隠日，脩條爭刺天。", "石斜苔附秀，樛窮蔓倒懸。", "擷英欲誰遺，佇立徒娟娟。"]'),
('69aa8486-1e90-4049-aad4-5a71bb939d9a','壽州十詠 狎鷗亭','宋祁','宋','宋诗','song-poetry','','[]','昔人有機心，鷗鳥舞不下。',48,'全唐诗/poet.song.11000.json','["昔人有機心，鷗鳥舞不下。", "太守心異昔，寒灰與時化。", "爾既不我猜，余亦無爾詐。", "隨波以全軀，于茲伴多暇。"]'),
('2a89b49f-187b-4c89-a498-e7301523def0','壽州十詠 齊雲亭','宋祁','宋','宋诗','song-poetry','','[]','肇允締層宇，岧岧少城隈。',48,'全唐诗/poet.song.11000.json','["肇允締層宇，岧岧少城隈。", "憑軒肄師孑，中坐合賓罍。", "白日披霞上，蒼山障霧回。", "眷言西北道，吾師安在哉。"]'),
('2bcadff9-0479-43ef-838a-401912e5475e','壽州十詠 望仙亭','宋祁','宋','宋诗','song-poetry','','[]','嘗聞淮南王，雞犬從此去。',48,'全唐诗/poet.song.11000.json','["嘗聞淮南王，雞犬從此去。", "至今山頭石，馬跡尚有處。", "使臣辭從官，終日絕塵慮。", "望望雲漢間，想見賓天馭。"]'),
('0d96306d-5354-44bd-bd49-33f54bbf5c9e','壽州十詠 清漣亭','宋祁','宋','宋诗','song-poetry','','[]','煙篠環曲隄，飛軒俯幽渚。',48,'全唐诗/poet.song.11000.json','["煙篠環曲隄，飛軒俯幽渚。", "水容靜可鑒，倒見城頭樹。", "青蒲矗爾秀，白鳥瞥然去。", "勝晤與時新，遂歌奚能敘。"]'),
('193d7a95-7b3f-4d61-abe4-4b65a0195127','草木雜詠五首 楠','宋祁','宋','宋诗','song-poetry','','[]','童童挺十尋，一蓋摩空綠。',36,'全唐诗/poet.song.11000.json','["童童挺十尋，一蓋摩空綠。", "斜月礙枝回，凉烟附葉宿。", "拙斧無妄加，要經匠者目。"]'),
('30343b1f-172c-44d9-9fc2-5162e19ccb20','草木雜詠五首 藤','宋祁','宋','宋诗','song-poetry','','[]','虺蔓相結蟠，虬梢互回屈。',36,'全唐诗/poet.song.11000.json','["虺蔓相結蟠，虬梢互回屈。", "紛若未契繩，繁如已綸綍。", "峭格外團陰，尤堪庇炎日。"]'),
('1ab876f6-d99e-47f1-ac74-b6832408306d','草木雜詠五首 櫞','宋祁','宋','宋诗','song-poetry','','[]','紺實紛纍纍，柔柯緩若若。',36,'全唐诗/poet.song.11000.json','["紺實紛纍纍，柔柯緩若若。", "葉以代新陳，花仍開續落。", "味雖不常御，香能破酲惡。"]'),
('d83b399d-6149-479b-b726-8ea46063baea','草木雜詠五首 海椶','宋祁','宋','宋诗','song-poetry','','[]','哆熾風葉張，囷皴雨皮厚。',36,'全唐诗/poet.song.11000.json','["哆熾風葉張，囷皴雨皮厚。", "叢橑列蓋端，攢旄注旗首。", "物以希見珍，材緣怪志醜。"]'),
('d615bd40-3841-46f8-8211-16e871b3ba32','草木雜詠五首 枇杷','宋祁','宋','宋诗','song-poetry','','[]','有果産西裔，作花凌蚤寒。',36,'全唐诗/poet.song.11000.json','["有果産西裔，作花凌蚤寒。", "樹繁碧玉葉，柯疊黄金丸。", "上都不可寄，咀味獨長歎。"]'),
('18859d94-b54b-441c-811d-a8e2d9d5833e','塞垣','宋祁','宋','宋诗','song-poetry','','[]','塞垣八月暮，百卉已凄然。',84,'全唐诗/poet.song.11000.json','["塞垣八月暮，百卉已凄然。", "沙驚甌脫路，霧暗單于天。", "衛霍始開府，辛趙數屯邊。", "鏖霜奔金戟，攢月駛飛鋋。", "彫弧六鈞勁，犀札七重穿。", "一戰薄澣海，再討窮祁連。", "露布報天子，稱觴壽萬年。"]'),
('73565b67-bf91-4798-92bc-73f200c80967','春集東園詩賦得筍字','宋祁','宋','宋诗','song-poetry','','[]','茂氣遍春逵，結客並游軫。',72,'全唐诗/poet.song.11000.json','["茂氣遍春逵，結客並游軫。", "勝踐屬園墟，歡言駐騶引。", "跼情適野豁，遠目向天盡。", "林馥樹纔花，町疏篁未筍。", "飲來無留釂，嘲往有餘囅。", "耳熱謝時人，戚戚良可憫。"]'),
('db3c0e69-54e3-45b5-95c5-b1f57b9b498f','七不堪詩七首  其一','宋祁','宋','宋诗','song-poetry','','[]','一不堪，性嗜日高寢。',34,'全唐诗/poet.song.11000.json','["一不堪，性嗜日高寢。", "疊鼓震餘夢，星毛欹倦枕。", "冠劍朝已盈，當關視門闖。"]'),
('5156d174-6472-4ad8-afd3-4a53f6fc7da6','七不堪詩七首  其二','宋祁','宋','宋诗','song-poetry','','[]','二不堪，草野樂垂釣。',34,'全唐诗/poet.song.11000.json','["二不堪，草野樂垂釣。", "潑潑錦鱗游，潑潑翠竿掉。", "夕負槁桐還，行吟面煙徼。"]'),
('73d22a15-1371-481f-ba65-98a6372e7f52','七不堪詩七首  其三','宋祁','宋','宋诗','song-poetry','','[]','三不堪，坐痹不得摇。',34,'全唐诗/poet.song.11000.json','["三不堪，坐痹不得摇。", "湯沐乏薰濯，蟣蝨喜爬搔。", "俯惕板在手，回慚綬結腰。"]'),
('da7ffcef-2546-445c-8730-fcab4c21b775','七不堪詩七首  其四','宋祁','宋','宋诗','song-poetry','','[]','四不堪，不喜謝書疏。',34,'全唐诗/poet.song.11000.json','["四不堪，不喜謝書疏。", "正無刀筆能，拙作餐飯句。", "自勉信非長，愆酬亦逢怒。"]'),
('36092d4f-4e01-4022-8ce5-2b2060943687','七不堪詩七首  其五','宋祁','宋','宋诗','song-poetry','','[]','五不堪，未始臨喪弔。',34,'全唐诗/poet.song.11000.json','["五不堪，未始臨喪弔。", "倍重秦失號，禮譏老聾笑。", "勉順當世情，爲哀損真妙。"]'),
('8e4684b3-54ca-4bfc-b166-57cbbb0baf49','七不堪詩七首  其六','宋祁','宋','宋诗','song-poetry','','[]','六不堪，不樂俗人共。',34,'全唐诗/poet.song.11000.json','["六不堪，不樂俗人共。", "聒聒沸蟈集，紛紛臭孥衆。", "怒遷多市色，禮煩方聚訟。"]'),
('938b124f-ed02-4533-ae8d-836e81e61fa9','七不堪詩七首  其七','宋祁','宋','宋诗','song-poetry','','[]','七不堪，束紳對文案。',34,'全唐诗/poet.song.11000.json','["七不堪，束紳對文案。", "吏若鳬鴨趨，文驚朱墨抏。", "自襮安所能，深心託蕭散。"]'),
('02491b4f-dc54-4d3a-b3cb-edd9b18c87a9','庫部閔員外還都','宋祁','宋','宋诗','song-poetry','','[]','望郎東南秀，奯然悟真理。',72,'全唐诗/poet.song.11000.json','["望郎東南秀，奯然悟真理。", "身雖宰官身，子即諸佛子。", "畫諾閣鈴下，塵慮未嘗滓。", "成金不復礦，見月詎存指。", "東道整朝珂，西亭摻離襼。", "無用樂山林，山林即朝市。"]'),
('1c2a6ea6-aadc-446e-aca7-1778a5567644','葵','宋祁','宋','宋诗','song-poetry','','[]','剉蘗染新蘤，插鈿成密房。',36,'全唐诗/poet.song.11000.json','["剉蘗染新蘤，插鈿成密房。", "仙人文玉字，宮女道家妝。", "聞說蕊間露，能令肌骨香。"]'),
('4761b3d4-a393-408d-8fb1-999abfdb9193','和登山城望京邑','宋祁','宋','宋诗','song-poetry','','[]','子牟懷魏闕，陳咸思帝城。',144,'全唐诗/poet.song.11000.json','["子牟懷魏闕，陳咸思帝城。", "他鄉豈不美，吾土樂所生。", "況復撫凋節，憑高懷上京。", "山川不可見，葱鬰凝神縣。", "紫氣抱關迴，玉斗侵城轉。", "負羽長楊獵，撞鐘平樂宴。", "高冠照華蟬，英俊皆比肩。", "朝奏主父牘，夜召賈生賢。", "五侯交薦幣，諸公亟爲言。", "我生流離極，十年悲去國。", "葉願洛陽飛，魚寧武昌食。", "當棄關下符，一對危言策。"]'),
('b962c251-02ac-47b2-b2f7-ec8073af448b','送平陸知縣尹象先','宋祁','宋','宋诗','song-poetry','','[]','之子被尉薦，走馬赴關西。',120,'全唐诗/poet.song.11000.json','["之子被尉薦，走馬赴關西。", "西人待賢相，撫育庶有宜。", "羌羶汙右鄙，秦隴含創痍。", "健將貪屯聚，砦柵猶鱗差。", "四年結不解，糧餉先自疲。", "兵分勢已弱，賊入縱橫馳。", "營陣訖不立，安得張吾師。", "比來守禦計，尚復紛相訾。", "子今位苦下，何由能奮奇。", "悉力字羸瘼，姑守簿書期。"]'),
('f1b380d3-55d0-494b-9459-b9f2d12c6b4e','次陝郊','宋祁','宋','宋诗','song-poetry','','[]','驚風吹客夢，西落劍南天。',108,'全唐诗/poet.song.11000.json','["驚風吹客夢，西落劍南天。", "自問何爲爾，官牒見嬰纏。", "遽傳非久舍，黎明徒御喧。", "俯輪千仞底，仰轡百尋巔。", "憑高一以眺，野氣正蒼然。", "崖奔仆僵樹，湍躁啼荒泉。", "羈禽易去木，奔麕不擇阡。", "撫物重增嘆，去邦邈以綿。", "何爲久行役，坐使歡心捐。"]'),
('14a05e3f-6a03-4295-bcb3-3c95fd0ca3b4','提刑使者還嘉州','宋祁','宋','宋诗','song-poetry','','[]','使者艤行舟，是行及凄序。',84,'全唐诗/poet.song.11000.json','["使者艤行舟，是行及凄序。", "祖帳俯平沙，從騎羅前渚。", "一進酒惟醴，再進魴及鱮。", "遠客已少悰，況將暌宴語。", "勁風自薄林，寒流稍分浦。", "訟矢久已閒，農坻矧就緒。", "歲晏亟言旋，無爲負延佇。"]'),
('53ee7f15-f62e-4d99-815d-1e7f2077dc1b','提刑勸農使者還嘉州','宋祁','宋','宋诗','song-poetry','','[]','案部聊北征，肅舲復東下。',144,'全唐诗/poet.song.11000.json','["案部聊北征，肅舲復東下。", "江溜澹泱泱，檣烏紛雅雅。", "離醑不餘杯，征棹亟沿洄。", "遠岫隨時見，幽花無候開。", "清氛霽平陸，林艿信重複。", "僰路繚山顔，駹田耨巖腹。", "屬此屢豐期，仍當省斂時。", "擊壤係途樂，餘糧尋畝棲。", "嘉陽信嘉處，時與賞心遇。", "霽樹抱空輪，寒濤下翔鷺。", "還轅眷仲秋，秋序日方遒。", "歸諾果無負，遲子臨江樓。"]'),
('e07d03c1-ef71-49d1-ac8f-743be9399795','雜詠三首  其一','宋祁','宋','宋诗','song-poetry','','[]','有客款我廬，念我衰暮齒。',108,'全唐诗/poet.song.11000.json','["有客款我廬，念我衰暮齒。", "自言上真書，有藥名不死。", "黄金乃能化，白髮安足治。", "謂我刀圭餘，已足度年紀。", "驅還扶桑面，黄昏付蒙氾。", "主人詭謝客，吾生本塵滓。", "少來誦詩書，不識怪神理。", "驚聞河漢言，浩然弗知涘。", "今也病未能，異日從吾子。"]'),
('9003aefd-89a0-4c97-8a93-7fcd1506c8f7','雜詠三首  其二','宋祁','宋','宋诗','song-poetry','','[]','金爐焚蕙荃，香播蕙已灰。',48,'全唐诗/poet.song.11000.json','["金爐焚蕙荃，香播蕙已灰。", "郁馥誠可貴，無乃爲蕙災。", "上瓦編翠烟，下礎挺沈質。", "所用不必同，相濟成宮室。"]'),
('7e0b6d46-0598-4be2-8739-772ff4b65eb7','雜詠三首  其三','宋祁','宋','宋诗','song-poetry','','[]','樂羊振歸旅，光艷充國都。',72,'全唐诗/poet.song.11000.json','["樂羊振歸旅，光艷充國都。", "矜心激盛氣，奮若長虹舒。", "君王勞軍罷，爲出一篋書。", "避席再拜跪，功非臣所圖。", "不待一盈篋，寸書已有餘。", "成功在主君，斯語不可誣。"]'),
('d7cbfabb-3cef-4a2a-8042-d67ce7574e73','玉玫瑰','宋祁','宋','宋诗','song-poetry','','[]','瑶楮鏤空濛，冰紈捲重疊。',36,'全唐诗/poet.song.11000.json','["瑶楮鏤空濛，冰紈捲重疊。", "寒光欲衝斗，迴秀難藏葉。", "誰碎辟邪香，氤氳飛作蝶。"]'),
('5fddce41-c91d-42d7-8797-9970197bf4d0','劉伯誠見惠僕所作中山雜詠石刻','宋祁','宋','宋诗','song-poetry','','[]','衣冠昔奔波，晉社亦中徙。',228,'全唐诗/poet.song.11000.json','["衣冠昔奔波，晉社亦中徙。", "水府擁宮闕，六姓傳劍璽。", "名卿入理窟，黔首多兵死。", "真人剗墉障，六合如平砥。", "三山屹不化，城郭無形似。", "冥冥桑麻村，殘鋒出耘耔。", "前朝絕遺老，故事稽野史。", "我頃爲中山，蠲租案田水。", "刳木枕波濤，礲刀伐荆杞。", "叢祠及荒壠，幽處無不履。", "車停客登席，酒盡詩在紙。", "游深造遐邃，語苦出奇詭。", "投囊凡幾時，蓬塵失料理。", "劉侯見之笑，謂此那可毀。", "濡毫請揮灑，買石親鎸紀。", "嗟予政理疏，無德行嵔壘。", "編民願尸祝，有愧庚桑子。", "惟茲楚客謠，可以傳下里。", "何時見椎擊，斷仆清江尾。"]'),
('52ab7712-43be-4c74-8413-1c92c59a27d2','寫懷寄獻樞密太尉','宋祁','宋','宋诗','song-poetry','','[]','僕本草茅人，守植自有素。',216,'全唐诗/poet.song.11000.json','["僕本草茅人，守植自有素。", "偶與力運偕，牽絲及榮路。", "矢將保獨行，安敢邀詭遇。", "朝躋綠霧閣，夕舍金馬署。", "鷃志屈鴻翼，珉質謝瑶圃。", "內省實空虛，焉得久留處。", "悟非不必老，斑領況云屢。", "竟獲一麾來，果此避賢趣。", "載以朱轓車，佩以銀符兔。", "君寵寄華冕，癯醜不成惡。", "淮郡梁楚交，刀筆紛民務。", "粗欲逃官責，何暇收民譽。", "平生覯宗工，亟爲拯淪誤。", "慚負知己言，遂貽越鄉慮。", "何圖霄與泥，肯問簪與屨。", "辛勤風波事，尺牘奚能訴。", "代馬愁南嘶，鷓鴣憎北翥。", "所戀明主恩，未理歸田馭。"]'),
('364260e0-1d8d-4eeb-a9ac-5145d00a8815','瓊花','宋祁','宋','宋诗','song-poetry','','[]','唐昌觀中樹，曾降九天人。',36,'全唐诗/poet.song.11000.json','["唐昌觀中樹，曾降九天人。", "鑾駕久何許，雪英如舊春。", "豈無遺佩者，來效捧心顰。"]'),
('3582d338-6119-4338-ba06-930fead8aa5c','抒懷上孫侍講學士','宋祁','宋','宋诗','song-poetry','','[]','僕本寒鄉士，始願託田隴。',288,'全唐诗/poet.song.11000.json','["僕本寒鄉士，始願託田隴。", "偶與亨會并，遂竊空名寵。", "黌胄信清閒，文書無倥傯。", "牽絲玷外舉，挾冊陪春誦。", "縹帙芸葉香，清池璧流壅。", "雖均五能知，猶冀三陌踊。", "有志慕孤直，多言畏奇中。", "往往犯怒狙，時時遭嚇鳳。", "脅肩方病畦，洗足幾成湩。", "言充衛士爨，賦蓋吳人甕。", "但望不汝瑕，安能賈予勇。", "叢雲屬帝辰，烝油樂賢共。", "前追三代風，旁鼓天下動。", "方正召華郤，賢良命晁董。", "務擢平津對，無罪賈生慟。", "裒然羣儁來，燦若春葩縱。", "咨予苦澀訥，望風猶陰拱。", "愁多目似蒿，疾久带移孔。", "直慮醒而狂，遂同微且尰。", "三千御上方，八九吞雲夢。", "訂正清廟詩，白罷旅獒貢。", "夫寧本無志，良憂拙于用。", "擊轅固歌鄙，殙金誠外重。", "中夕撫躬嘆，明恩愧孤奉。"]'),
('35bcd15c-a2f5-4ab1-98e7-b5c3aec808a7','溪上','宋祁','宋','宋诗','song-poetry','','[]','溪上玩秋水，使人意自清。',72,'全唐诗/poet.song.11000.json','["溪上玩秋水，使人意自清。", "烈烈回飈餘，鱗鱗夕浪生。", "有魚可垂餌，有蒲可芼羹。", "況值新酒熟，鮭菜辛鹹并。", "興來命一樽，樽至壺自傾。", "便值人間慮，浩然滄海情。"]'),
('90059fde-70ab-40e3-a88f-172069f24300','送行','宋祁','宋','宋诗','song-poetry','','[]','秋日苦凄凄，味若虀臼辛。',72,'全唐诗/poet.song.11000.json','["秋日苦凄凄，味若虀臼辛。", "如何多感地，更送將歸人。", "高蓋浮清旭，長纓縛素塵。", "慘色動車僕，離言發坐賓。", "霜珂響征馬，星脂滑行輪。", "契闊何所道，良飯自寵珍。"]'),
('9c2656b9-9bed-4a84-84d4-5734c091885a','曉櫛','宋祁','宋','宋诗','song-poetry','','[]','曉櫛理斑鬢，蕭蕭徧愁顛。',60,'全唐诗/poet.song.11000.json','["曉櫛理斑鬢，蕭蕭徧愁顛。", "多病始計日，蚤衰不待年。", "青青固未幾，種種今乃然。", "寡髮有巽象，施髲慚莊篇。", "且復委蓬葆，言就東山眠。"]'),
('7963fd5f-591b-407d-a547-09f7d8cf13ef','筠亭','宋祁','宋','宋诗','song-poetry','','[]','山阿彼有人，葺宇映脩竹。',36,'全唐诗/poet.song.11000.json','["山阿彼有人，葺宇映脩竹。", "露籜新舊斑，風梢動摇綠。", "此君自虛心，主公今實腹。"]'),
('e8d06d10-e290-4752-af6c-1efe6247b0b1','送屯田張員外','宋祁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','飛霜逐凋節，歲籥忽已闌。',84,'全唐诗/poet.song.11000.json','["飛霜逐凋節，歲籥忽已闌。", "奈何送歸客，置酒長江干。", "十載始一遇，別易會故難。", "此地嗟素領，昔日皆朱顔。", "詎意前歡餘，更爲後感端。", "行舟望不見，留驂相與還。", "芳訊幸無保，時付凌風翰。"]'),
('90ad7a69-9aa8-421d-bb87-86b700b2c4e3','古意','宋祁','宋','宋诗','song-poetry','','[]','薄宦若秋蔕，飄然去林枝。',72,'全唐诗/poet.song.11000.json','["薄宦若秋蔕，飄然去林枝。", "盲風不我愛，吹墮清淮湄。", "淮南苦憀慄，九月繁霜飛。", "晚蕙相爲歎，崇蘭偕此衰。", "凋落雖云苦，芬香終不移。", "但願陽春動，要當三秀期。"]'),
('c61e0156-34fc-472b-a167-2009631d35c3','秋氣','宋祁','宋','宋诗','song-poetry','','[]','清濁還二儀，秋氣颯然肅。',48,'全唐诗/poet.song.11000.json','["清濁還二儀，秋氣颯然肅。", "溪潔潦已殘，林疏條自矗。", "寒蛩思長階，歸燕眷華屋。", "凋年自茲始，鄉懷念松菊。"]'),
('37b77d78-9c40-4907-9a33-d4890a6fef04','感舊送虞曹楊員外','宋祁','宋','宋诗','song-poetry','','[]','曩笑長者言，感恨歲時遽。',192,'全唐诗/poet.song.11000.json','["曩笑長者言，感恨歲時遽。", "不云笑未幾，倐已及衰路。", "却懷眼中人，落落星向曙。", "寧無新相知，論新不如故。", "夫子惠然至，適慰離羣慕。", "締交三十載，契闊不同處。", "醜老向來妍，鬢黑今也素。", "伐木喜求舊，谷風念將懼。", "我顧濫榮班，君乃嘆奇數。", "根柢假容進，纏牽以長誤。", "久領一麾行，江湖極沿泝。", "杯酒曾未款，僕夫告方具。", "前樂暫還衿，後戚已盈慮。", "丈夫固有志，膂力經世務。", "何必常相從，卑若堂下屨。", "歲滿亟來旋，中朝著翔步。"]'),
('163882a1-dd7e-480b-8df8-5252ec4033c4','擬杜工部九成宮','宋祁','宋','宋诗','song-poetry','','[]','雲山鬰嵯峨，宮戶莽轇轕。',144,'全唐诗/poet.song.11000.json','["雲山鬰嵯峨，宮戶莽轇轕。", "摧峰隠馳道，鑱岫啟繡闥。", "游鵾邈飛鬭，陽馬恣陵突。", "危淙注銅池，翠瀲潄崖骨。", "落虹拖晨軒，奔蟾守夜窟。", "憑高眺鴻洞，念古一超忽。", "咄嗟有隋後，締構窮剞劂。", "徒矜昔日工，乃忘後世拙。", "居爲唐家保，功業何汩汩。", "牛酒望幸民，巖廊衛守卒。", "殘松抱空偃，卧楊委新伐。", "千載徧荒愁，金鋪鎖崷崒。"]'),
('5ffc86c9-5a68-4718-a04a-6aaae12cd12b','望仙亭','宋祁','宋','宋诗','song-poetry','','[]','淮山相蟬聯，萬景歸宇下。',48,'全唐诗/poet.song.11000.json','["淮山相蟬聯，萬景歸宇下。", "來波澹天末，歸霧滅巖罅。", "凄凄草色繁，肅肅桂叢亞。", "吾人愧攸館，僊屬冀來舍。"]'),
('36730d37-35ea-4a11-9dd1-1e25f2189fc2','湖山','宋祁','宋','宋诗','song-poetry','','[]','一水抱天回，千巖互相映。',36,'全唐诗/poet.song.11000.json','["一水抱天回，千巖互相映。", "寒湖囓沙痕，狂峰貫霞景。", "持此寫琴心，寧無子期聽。"]'),
('86897eef-b937-4c5c-951a-95e34fe4ee28','勸酒','宋祁','宋','宋诗','song-poetry','','[]','酌酒奉君壽，勸君慎勿辭。',84,'全唐诗/poet.song.11000.json','["酌酒奉君壽，勸君慎勿辭。", "只今舉酒罷，已異行觴時。", "波瀾前後來，日月分寸推。", "稚容不耐久，縞領無停緇。", "獨醒信勞人，茲事定何悲。", "假令古無死，晝夜常倭遲。", "正恐爽鳩樂，後人非所希。"]'),
('beaa2726-7d96-4ad0-b75e-69cfe7931a19','種竹','宋祁','宋','宋诗','song-poetry','','[]','世皆笑幽獨，可不少自貶。',48,'全唐诗/poet.song.11000.json','["世皆笑幽獨，可不少自貶。", "種竹南軒間，亦足以相驗。", "況茲歲華晚，衆卉日凋斂。", "清節良自如，栽培匪爲諂。"]'),
('f3e55511-ccfc-4229-a0cd-118ee27f878c','凉蟾','宋祁','宋','宋诗','song-poetry','','[]','凉蟾囓殘雲，飛影上西廡。',72,'全唐诗/poet.song.11000.json','["凉蟾囓殘雲，飛影上西廡。", "鵲鴉依空牆，蠨蛸已在戶。", "君行閱三歲，确戰亦云苦。", "新衣本自綻，故裳復誰補。", "朔風萬里來，儻或從君所。", "風過無傳音，徘徊獨誰語。"]'),
('248320be-cad6-40fb-a718-b90b1acf36c6','楊秘校秋懷  其一','宋祁','宋','宋诗','song-poetry','','[]','上天分四序，素秋獨可悲。',72,'全唐诗/poet.song.11000.json','["上天分四序，素秋獨可悲。", "商風勁危條，寒露鮮繁蕤。", "依依燕去巢，嘒嘒蟬抱枝。", "撫物喟然嘆，流光忽已馳。", "危衿恧新壯，華領移故緇。", "願君策高足，無後功名時。"]'),
('a5eb5a0d-ab32-4d61-a2e6-628401b73786','楊秘校秋懷  其二','宋祁','宋','宋诗','song-poetry','','[]','凉風颯彫年，遥昔耿多慮。',72,'全唐诗/poet.song.11000.json','["凉風颯彫年，遥昔耿多慮。", "冽冽寒螿鳴，離離客鴻度。", "之子懷茂器，有志康庶務。", "未蒙徐樂召，方感董生遇。", "道局駿願違，絃絙危響赴。", "此際怊悵情，偕之歲云暮。"]'),
('0002e2fc-a31e-4c03-91b6-64c7725f162b','楊秘校秋懷  其三','宋祁','宋','宋诗','song-poetry','','[]','治畹當樹蘭，治林當植桂。',72,'全唐诗/poet.song.11000.json','["治畹當樹蘭，治林當植桂。", "蘭生可香國，桂茂絕藂薈。", "邈哉志士節，所趣與人異。", "意經千古上，心包九垠際。", "道勝外物輕，矧復韁鎖細。", "所以搶榆者，局局笑鵬翅。"]'),
('53832f27-9cde-4e7e-8ea9-24489f979cb9','真珠龍柏','宋祁','宋','宋诗','song-poetry','','[]','彼美夜光喻，益之新甫名。',36,'全唐诗/poet.song.11000.json','["彼美夜光喻，益之新甫名。", "纍纍雲際艷，皎皎月中英。", "勿誚素爲絢，相期隆德聲。"]'),
('2f6ca7f8-fe5d-4455-935b-b3214876f882','度飛石嶺','宋祁','宋','宋诗','song-poetry','','[]','人不怨飄瓦，何用罪飛石。',36,'全唐诗/poet.song.11000.json','["人不怨飄瓦，何用罪飛石。", "石墜不可常，人值亦其適。", "去去走嶔崟，千金幸自惜。"]'),
('68b6c9c5-d424-4c4f-959a-863287c6eff8','擬王右丞瓜園','宋祁','宋','宋诗','song-poetry','','[]','荷鋤往瓜田，煙蔓紛廣疇。',132,'全唐诗/poet.song.11000.json','["荷鋤往瓜田，煙蔓紛廣疇。", "植杖未及憇，有客眷林丘。", "騶哄羅戶前，冠蓋蔭道周。", "進客北堂上，藉以氍毹柔。", "持盃再三跪，酌我清白酧。", "時時高興酣，矯首望神州。", "長衢貫廣陌，反宇注飛樓。", "惠風林間翔，早暉花上浮。", "新葉向蒙密，鷇雛已啁啾。", "時哉物可玩，況復忘吾憂。", "故人心儻爾，駕言時見求。"]'),
('51a06bf8-e19b-480d-846a-06b9d5465a4e','寄題宮師相公宴息園','宋祁','宋','宋诗','song-poetry','','[]','相公納衡樞，卜築來東里。',192,'全唐诗/poet.song.11000.json','["相公納衡樞，卜築來東里。", "恤他匪足尚，自適乃云美。", "中園興夷爽，薄言謝朝市。", "壤石非遠遷，松竹皆故蒔。", "絳蘤謝游軒，素波鳴禊戺。", "遐蒼眺京隩，側縹抱嵩趾。", "畦塍互演漾，灌薄紛靃靡。", "崒崒相向山，濺濺自流水。", "高雲靡還期，冥鴻無慕理。", "公時挾勝想，朅來遵逸軌。", "逢觴即陶然，坐樹亦欣止。", "沖情舍天倪，妙歌怯物類。", "揮金屢空鎰，愛客輒留屣。", "式俾衛公壽，弗取安石侈。", "有守卧淮壖，聆風竦予企。", "他日果西歸，角巾望松梓。"]'),
('6167d10b-8b46-4eec-888c-e34e436f2650','小渠','宋祁','宋','宋诗','song-poetry','','[]','唐溪析春溜，一股入清渠。',60,'全唐诗/poet.song.11000.json','["唐溪析春溜，一股入清渠。", "循庭始演漾，走圃輒縈紆。", "淙淙潄幽石，唯唯泳纖魚。", "瀑來聊激濁，澄罷復涵虛。", "恃源纔自潤，流波愧挹餘。"]'),
('7b4c0f66-1e03-4cc0-a38f-60c41b3a0ff6','曉過二里山','宋祁','宋','宋诗','song-poetry','','[]','黎明走蒼山，千仞勢如削。',108,'全唐诗/poet.song.11000.json','["黎明走蒼山，千仞勢如削。", "北斗挂西巔，徘徊久未落。", "驛道轉巖肩，人烟聚岑脚。", "太虛交昏旦，顥氣自噴薄。", "陽光排暗升，陰氛值明郤。", "翔禽散喬枿，啼狖思空壑。", "逢隈霧尚屯，投險泉爭躍。", "生平好山意，每遭事嬰縛。", "安得乘冷風，窮躋叩寥廓。"]'),
('36712143-dcf5-4b07-98f7-c7c4a95f2b1a','思賢閣圖予真愧而成詠','宋祁','宋','宋诗','song-poetry','','[]','忝中二千石，罷去輒圖真。',132,'全唐诗/poet.song.11000.json','["忝中二千石，罷去輒圖真。", "揆予本完士，蚤蒙善養仁。", "執笏班華位，飛綏侍邃宸。", "如何金紫服，乃裹丘壑身。", "西南一面重，朅來駕朱輪。", "牽拙歲再期，初無德在民。", "形象安足紀，崖略聊自陳。", "質陋眸子瞭，志泰眉宇伸。", "誰謂彼其子，而傳阿堵神。", "爵里三十八，赫赫多名臣。", "瞻前謝前哲，垂後慚後人。"]'),
('6aad856b-b7f9-4790-b723-dae02987570c','九日藥市作','宋祁','宋','宋诗','song-poetry','','[]','陽九協嘉辰，斯人始多暇。',144,'全唐诗/poet.song.11000.json','["陽九協嘉辰，斯人始多暇。", "五藥會廣廛，遊肩鬧相駕。", "靈品羅賈區，仙芬冒闉舍。", "擷露來山阿，斸煙去巖罅。", "載道雜提携，盈簷更薦藉。", "乘時物無賤，投乏利能射。", "饔苓互作主，參薺交相假。", "曹植謹贋令，韓康無二價。", "西南歲多癘，卑濕連春夏。", "佳劑止刀圭，千金厚相謝。", "刺史主求瘼，萬室繫吾化。", "顧頼藥石功，捫襟重慚唶。"]'),
('95574683-9341-4825-be61-d5690de2be36','迎春曲三闋  其一','宋祁','宋','宋诗','song-poetry','','[]','青陸斗杓回，河內動新灰。',36,'全唐诗/poet.song.11000.json','["青陸斗杓回，河內動新灰。", "冰際綃紋綻，雲邊鶴影來。", "漢宮行慶罷，花樹剪刀催。"]'),
('0dc89b88-7d12-4556-ab84-25047c9bcc8b','迎春曲三闋  其二','宋祁','宋','宋诗','song-poetry','','[]','東郊風馭軟，嚴署漏籌添。',36,'全唐诗/poet.song.11000.json','["東郊風馭軟，嚴署漏籌添。", "柳拂將軍壁，梅飄公主奩。", "舞衣裁幾許，新人解織縑。"]'),
('0ec1ff5c-7b5d-443b-bf42-5dbb630c8abe','迎春曲三闋  其三','宋祁','宋','宋诗','song-poetry','','[]','荔達陽膏動，冰解水紋融。',36,'全唐诗/poet.song.11000.json','["荔達陽膏動，冰解水紋融。", "天花四面碧，日氣幾竿紅。", "不言雙燕晚，爲嘆玉箱空。"]'),
('633d9105-8b3d-42a0-b10a-7ccb6623a734','散關','宋祁','宋','宋诗','song-poetry','','[]','磴道何盤盤，百步人一憩。',36,'全唐诗/poet.song.11000.json','["磴道何盤盤，百步人一憩。", "弭節高山顛，關存不置吏。", "昔緣暴客須，今爲有道廢。"]'),
('b404a6c2-e427-4546-8e7b-cc728a3c54d3','和成上人','宋祁','宋','宋诗','song-poetry','','[]','西山有尊者，秀出于稻麻。',204,'全唐诗/poet.song.11000.json','["西山有尊者，秀出于稻麻。", "徧參居第一，諸佛素所嗟。", "錫聲來赤縣，被祴垂青霞。", "流出一切妙，普見大千沙。", "我法果無在，昧者茲有涯。", "是凡方是聖，歸正即歸邪。", "妄懷萬緣息，舉意千里差。", "有客謝病免，清辭春月賒。", "靜眠金粟室，厭坐馬融紗。", "觀化哂罨勒，自呼嗤鏌鋣。", "瞻言世外友，相期心不遐。", "揮斤郢匠室，流水子期家。", "披雲示駛月，拂果去空花。", "師嘆未曾有，君對無以加。", "清襟互默遣，所得非齒牙。", "層陰朋盍阻，坐久丹霏斜。", "涵毫泚仙滴，抒藻揚晨葩。"]'),
('e823cf35-a09d-4bbc-a16c-1c52ff3e06a9','水文疊石','宋祁','宋','宋诗','song-poetry','','[]','曉波清蒼痕，豗激翠將腐。',60,'全唐诗/poet.song.11000.json','["曉波清蒼痕，豗激翠將腐。", "奔濤已東决，磊塊留不去。", "巧匠取之出，入資園亭趣。", "陰罅囓餘苔，寒凹逗輕露。", "彼怪予弗談，不轉吾所慕。"]'),
('2185da32-913e-474f-8b3d-f49c7dcf24cd','遠行','宋祁','宋','宋诗','song-poetry','','[]','楚人巧悲秋，分作四種戚。',72,'全唐诗/poet.song.11000.json','["楚人巧悲秋，分作四種戚。", "最極有遠行，百感攢羈臆。", "林鳥戢和哢，屯雲獻慘色。", "客久歸念長，年驚壯圖窄。", "撫物盈近嘆，驅騑擁遥惻。", "曉斗亦告勞，垂杓卧樓北。"]'),
('98ed266e-607d-4b55-88c0-9667ec119af1','早秋有感','宋祁','宋','宋诗','song-poetry','','[]','一葉飛足驚，要是變衰始。',96,'全唐诗/poet.song.11000.json','["一葉飛足驚，要是變衰始。", "毛澤自茲竭，多露方夜委。", "凉蜩抱空號，腐燐變幽煅。", "怊然感物化，鬚髮不常美。", "羲和鞭白日，已復向濛氾。", "功名未及見，軒冕胡足恃。", "坐客憫予憂，粲然啟玉齒。", "輟嗟謝諸郎，長年行自爾。"]'),
('090d683f-fb9a-44b9-8f02-d59dd5d166e8','讌集','宋祁','宋','宋诗','song-poetry','','[]','素節倐已宴，高風送浮凉。',72,'全唐诗/poet.song.11000.json','["素節倐已宴，高風送浮凉。", "拂席進賓客，釃酒羅壺觴。", "黄鷄跖跖美，紫蟹螯螯香。", "莫矜來歡早，須念後戚長。", "奔川無緩瀾，徂日不還光。", "願客且安坐，調絃未遽央。"]'),
('c8bb92ef-fe98-4bf1-9e2c-3c4a116778b9','水月','宋祁','宋','宋诗','song-poetry','','[]','渺渺遡雲波，盈盈柅霜馭。',36,'全唐诗/poet.song.11000.json','["渺渺遡雲波，盈盈柅霜馭。", "碎璧擁舟來，流金映沙聚。", "夜寂波已休，何人薦真趣。"]'),
('6ccbfe60-cacb-4eac-bdd1-8dadb03672f6','和君貺學士宿淮上見寄','宋祁','宋','宋诗','song-poetry','','[]','使舲既邅迴，淮溜劇沿泝。',72,'全唐诗/poet.song.11000.json','["使舲既邅迴，淮溜劇沿泝。", "我行非不遠，君節自前路。", "烟汰歷濠汭，霧氛逗荆樹。", "感此言邁情，慰予索居慕。", "曰歸歸未辰，慘別別已屢。", "努力保素衿，天途遲還翥。"]'),
('8fd0bb62-e576-4962-83fa-eda345324487','鈐轄冒上閤就移知雄州','宋祁','宋','宋诗','song-poetry','','[]','聚散非一端，賢逸難兩遂。',168,'全唐诗/poet.song.11000.json','["聚散非一端，賢逸難兩遂。", "擁節北臨邊，安得久交臂。", "此行詎不遠，印瑞三且二。", "背劍車炙輠，徑秦驂舞轡。", "雄州乃劇藩，喉領塞南地。", "譯通老上庭，道係單于使。", "適館授主粲，乘韋交客贄。", "列戍儼趨風，諸將走咨事。", "應變君所長，立功今可冀。", "君家誠易知，世烈在青史。", "齊楚異姓王，陰鄧后家里。", "券字金對行，戟带霞交尾。", "濬源無近波，高峰本洪址。", "行矣勵壯猷，公侯當復始。"]'),
('436f55ca-3b72-4f54-8498-40c579b530d1','常山楊氏有二怪石奇險百狀田曹張中行家雒陽徧見都中諸家所得異石皆出此下予他日思之恐常人忽而不珍作詩以詫其處并邀中行伯逢同賦','宋祁','宋','宋诗','song-poetry','','[]','塊然兩奇石，譎怪狀難悉。',180,'全唐诗/poet.song.11000.json','["塊然兩奇石，譎怪狀難悉。", "千仞裂嵯峨，一氣與崷崒。", "四隅蘚剝膚，萬古雲漬骨。", "補餘天所委，隕罷星不沒。", "橫蒼對偃蹇，怒翠競騰突。", "神媼祕弗露，狂鼇抃而失。", "由茲落人宇，得用玩奇質。", "屹如不可轉，挺若無所屈。", "鬭虎攫餘痕，乖龍卧殘窟。", "撐掉壯士槊，奮立直臣笏。", "危頂烟夭矯，窄竇雷鬰律。", "濤頭縮不長，魖臂憤相捽。", "變現載靈牒，呵護費神物。", "窮陬苦陋庳，珍碧恐湮汩。", "各保堅䃭姿，以待封山日。"]'),
('5c3d1942-5c8d-471c-b3b6-43faab0ef4e4','反騷','宋祁','宋','宋诗','song-poetry','','[]','我聞上天樂，仙聖並游賓。',96,'全唐诗/poet.song.11000.json','["我聞上天樂，仙聖並游賓。", "離楚何所據，招回逐客魂。", "謂門有九關，虎豹代守閽。", "砥舌饑涎流，觸之輒害人。", "譏呵自有常，帝意寧不仁。", "窮壤苦恨隔，傳聞恐失真。", "我欲稽首問，無梯倚青雲。", "塊然守下土，此憤何由伸。"]'),
('804cb932-b7e2-40e2-88c6-69e6d49c1e1b','懷三封墅  其一','宋祁','宋','宋诗','song-poetry','','[]','寡求願易足，久計還中林。',84,'全唐诗/poet.song.11000.json','["寡求願易足，久計還中林。", "君恩容有報，宿留未抽簪。", "淺謀乏經濟，流景倏頹侵。", "企翰羨鴻翥，俯泳愧魚沈。", "榮名非不勉，高坻良可歆。", "奈何賈生慟，又將莊舄吟。", "投沙乃聞古，懷春方在今。"]'),
('601476bf-169c-4f9a-ba20-889abeba31ce','懷三封墅  其二','宋祁','宋','宋诗','song-poetry','','[]','三封何所懷，懷我東南畝。',120,'全唐诗/poet.song.11000.json','["三封何所懷，懷我東南畝。", "方春原田秀，是時簦笠聚。", "杏花燦晴落，菖葉甲陰浦。", "泱泱雲抱岑，眇眇林鳴扈。", "野老携晨饁，薄醪間炊黍。", "安知五熟滋，但慰四友苦。", "日作夕還家，烟火青林下。", "嗟我仕易稼，窮年宦三輔。", "誓畢尚生累，將從平子賦。", "自省非大人，請事學農圃。"]'),
('49f0693b-32a0-4b0c-a995-c599d2177745','風雨','宋祁','宋','宋诗','song-poetry','','[]','昨夜東風急，疏窗薦雨入。',84,'全唐诗/poet.song.11000.json','["昨夜東風急，疏窗薦雨入。", "溪南梅正花，狼藉隨塵沙。", "皓皓多易汗，不得同春葩。", "春葩能有幾，紛紛入桃李。", "時哉小興衰，人生猶物理。", "明發簷沈聲，鳥雀喧新晴。", "老農脫襏沖，一犁原上耕。"]'),
('52f7e41a-5eb6-46b6-8781-2751cea289e6','秋興','宋祁','宋','宋诗','song-poetry','','[]','西顥肅凉氛，天宇正岑寂。',96,'全唐诗/poet.song.11000.json','["西顥肅凉氛，天宇正岑寂。", "凄風條末吟，浩露林下滴。", "寥寥燕辭楹，促促蛩在壁。", "池潦湛寒綠，鱗雲屯晚白。", "齊紈不復御，桃笙已復易。", "嗟哉無壯士，翻車忽西匿。", "有客過我廬，問我何悽惻。", "氣索不能對，披襟長太息。"]'),
('12a5eb2d-8dad-454c-8dd9-bfb61a5184e4','金雀花','宋祁','宋','宋诗','song-poetry','','[]','疊葉倚風綻，翩翾凌霧排。',36,'全唐诗/poet.song.11000.json','["疊葉倚風綻，翩翾凌霧排。", "齊名仙母使，寫樣漢宮釵。", "俗眼未應妬，勿憂珠彈來。"]'),
('06ad1e7e-1072-451b-bec3-66e6a51b08aa','浮屠','宋祁','宋','宋诗','song-poetry','','[]','乞食古爲恥，浮屠名自修。',72,'全唐诗/poet.song.11000.json','["乞食古爲恥，浮屠名自修。", "黎明抱應器，禺中飫乾餱。", "果腹固其願，之墦非所羞。", "歉歉常不足，遑遑茲有求。", "素飽聊安坐，調饑復來游。", "顧爾殊靈輒，翳桑何用酬。"]'),
('a6682e34-9a2f-4c7b-af30-0741e8f8ac3c','四季花','宋祁','宋','宋诗','song-poetry','','[]','羣葩各分榮，此獨貫時序。',36,'全唐诗/poet.song.11000.json','["羣葩各分榮，此獨貫時序。", "聊披淺深艷，不易冬春慮。", "真宰竟何言，予將造形悟。"]'),
('2d4ab40f-a6c9-4f9f-a92a-8478f0e24d99','雜興  其一','宋祁','宋','宋诗','song-poetry','','[]','寒暑亟徂謝，日月如崩波。',120,'全唐诗/poet.song.11000.json','["寒暑亟徂謝，日月如崩波。", "稚容不再妍，戚戚奈老何。", "聞有遯世客，安處西山阿。", "手操九籥契，晝夜養丹砂。", "藥成可化金，舉身凌紫霞。", "我願從之游，脫身此世羅。", "辦裝秣吾馬，臨路更自訶。", "古來松喬流，矜己好浮夸。", "萬一爲藥誤，得無我計差。", "速還具肴酒，毋爲後人嗟。"]'),
('0cdc22ac-2046-4955-865b-079ffcd3bd8c','雜興  其二','宋祁','宋','宋诗','song-poetry','','[]','河東有賢守，帝念不能已。',48,'全唐诗/poet.song.11000.json','["河東有賢守，帝念不能已。", "欲置之大夫，徵軺疾于水。", "留邸月餘罷，君恩詎可恃。", "召以一人譽，去由一人毀。"]'),
('ce51fa54-1189-454d-b628-db7bca91841f','雜興  其三','宋祁','宋','宋诗','song-poetry','','[]','鉅平名世賢，媢者强相軋。',48,'全唐诗/poet.song.11000.json','["鉅平名世賢，媢者强相軋。", "毀語填君聰，亡吳計中奪。", "人生不如意，在十常九八。", "茲事可奈何，惆悵千載末。"]'),
('bb385eff-72c7-401b-916a-b2c423a68822','雜興  其四','宋祁','宋','宋诗','song-poetry','','[]','殘暑辭遥夕，初凉澹蕭辰。',48,'全唐诗/poet.song.11000.json','["殘暑辭遥夕，初凉澹蕭辰。", "燕索西飛伴，雁作南來賓。", "霽巒靜矗矗，遠水清鱗鱗。", "由來摇落恨，先付長年人。"]'),
('d3b85366-0269-4831-a2cc-dd7811e694c5','錦亭晚矚','宋祁','宋','宋诗','song-poetry','','[]','長夏宜高明，緩带散煩窘。',72,'全唐诗/poet.song.11000.json','["長夏宜高明，緩带散煩窘。", "憑軒一超然，目與天共盡。", "山從雲端現，日就林外隠。", "風來草樹披，烟生井閭近。", "自公況多暇，沖臆無留藴。", "即此可宴居，何須事遊軫。"]'),
('98b6600e-a6a0-473b-a622-63b17b70d950','初伏休沐','宋祁','宋','宋诗','song-poetry','','[]','伏時詔休偃，閉門謝朋儕。',96,'全唐诗/poet.song.11000.json','["伏時詔休偃，閉門謝朋儕。", "羲和挾升陽，曉氣紅崔嵬。", "炎林欝歊露，焦原橫赭埃。", "怒甚崒崒雲，旱始隆隆雷。", "況我庇茨宇，煩襟安得開。", "囚拘訴巾幘，仇怨被酒杯。", "湯沐未及具，反爲蟣虱咍。", "北風殊杳嘿，羲人安在哉。"]'),
('ca641cf0-8a95-48b2-be7e-43c7143da342','遊矚','宋祁','宋','宋诗','song-poetry','','[]','顥風肅九旻，樓榭注明迥。',60,'全唐诗/poet.song.11000.json','["顥風肅九旻，樓榭注明迥。", "林爽無剩繁，溪澄有餘映。", "四阿延清霏，六幕盡高興。", "號枝蟬腹厲，掠野鶻拳勁。", "山意日久高，差差插空凈。"]'),
('d34156cb-629d-440a-a3a3-1f81c0396366','送蔡元翰賢良昆仲','宋祁','宋','宋诗','song-poetry','','[]','美箭出東南，之子裒然秀。',120,'全唐诗/poet.song.11000.json','["美箭出東南，之子裒然秀。", "綽綽令兄弟，茂器偕年就。", "九流無近討，六藝乃遐究。", "詔書求異等，二惠茲來覯。", "牘均方朔多，輻比吾丘湊。", "蹀足蟻封埸，刷羽桐花囿。", "孤音或少和，至寶不期售。", "肇允褰褐衣，薄言返巖竇。", "江皋看魚樂，山徑懷雉嗅。", "無忽豫章材，行參柏梁構。"]'),
('63065bf2-275b-4ed1-9919-e01e02120b2e','送伊闕鄭著作','宋祁','宋','宋诗','song-poetry','','[]','君年已艾服，沿牒困風塵。',60,'全唐诗/poet.song.11000.json','["君年已艾服，沿牒困風塵。", "硎新始發刃，鳴晚逾驚人。", "毋辭滯下邑，姑欲慰斯民。", "此路塵車往，明年郊雉馴。", "恨乏雙鳬舄，從子伊水濱。"]'),
('e0819cd8-4063-4fdc-9318-a500c529518b','攬鏡','宋祁','宋','宋诗','song-poetry','','[]','晚匣寫菱影，試觀憔悴顔。',36,'全唐诗/poet.song.11000.json','["晚匣寫菱影，試觀憔悴顔。", "支離骨不媚，蕭颯鬢垂斑。", "安得長康畫，致之巖壑間。"]'),
('7bd42c86-6f51-4444-ab61-e27936af9e95','望月西廡作','宋祁','宋','宋诗','song-poetry','','[]','夏琯倐已新，夕杓見南指。',72,'全唐诗/poet.song.11000.json','["夏琯倐已新，夕杓見南指。", "孤月霧中來，餘光淡前戺。", "賞襟初不淺，極睇天漢涘。", "浮雲竟未還，多露已徐委。", "太虛本自寂，遊氛强爲滓。", "安得千里風，披霄玩澄晷。"]'),
('c2205990-599c-48cc-90f3-94397eecacdc','歲豐','宋祁','宋','宋诗','song-poetry','','[]','皇天降豐年，本憂貧士食。',60,'全唐诗/poet.song.11000.json','["皇天降豐年，本憂貧士食。", "貧士無良疇，安能得稼穡。", "工傭輸富家，日落長歎息。", "爲供豪者糧，役盡匹夫力。", "天地莫施恩，施恩强有得。"]'),
('f3f6a04d-7e2a-4ab5-ad47-c98b80258a92','題信相院默庵','宋祁','宋','宋诗','song-poetry','','[]','對言方有默，因默乃名庵。',48,'全唐诗/poet.song.11000.json','["對言方有默，因默乃名庵。", "庵留默不遣，一物遂爲三。", "龜掃泥中痕，正恐力弗堪。", "自問呵默者，了然成妄談。"]'),
('19542a7b-d44a-4ff6-aa35-988604d1bedf','感懷','宋祁','宋','宋诗','song-poetry','','[]','夕風搜前林，墜葉快如剪。',72,'全唐诗/poet.song.11000.json','["夕風搜前林，墜葉快如剪。", "老月扣戶低，傾河去人遠。", "吉士感物化，勞勞意不展。", "輟飲屏樽杓，留釭討墳典。", "觸事孟軻迂，臨途安國蹇。", "不歎歲月遒，所悼功名晚。"]'),
('e822ad13-5938-46c0-83b1-b6c4a9e65ed2','念衰','宋祁','宋','宋诗','song-poetry','','[]','歲月不待人，驅我向衰境。',144,'全唐诗/poet.song.11000.json','["歲月不待人，驅我向衰境。", "朱顔日辭貌，縞鬢颯垂領。", "意昏若坐霧，歡墜似羸井。", "病多茲及慵，志怯遂依靜。", "問我何功德，乃玷鷄翹省。", "始願常謬悠，薄霄圖振景。", "棧車值塞路，蹇蹇莫吾騁。", "君恩蓋如天，分虎向東郢。", "沈憂誠萬緒，通宵付耿耿。", "失旦安暇鳴，值露徒能警。", "私計狹且偷，榮路浩方永。", "惟餘昧死章，將露乞身請。"]'),
('963101c5-8ce9-4d15-b03a-6dc2b1c5cb8b','擬東武曲二首  其一','宋祁','宋','宋诗','song-poetry','','[]','甘泉烽火照黄昏，候騎駸駸入雁門。',96,'全唐诗/poet.song.11000.json','["甘泉烽火照黄昏，候騎駸駸入雁門。", "光祿塞前逢夜月，黄龍城下見愁雲。", "隠隠輕雷逐車響，顔行使者樂相望。", "勞軍細柳尊亞夫，持節雲中赦魏尚。", "自從天子樂休牛，故障遺亭豈重修。", "李廣不生高祖世，豈得今封萬戶侯。"]'),
('426cf5a1-19b8-41c6-93ae-6b57d8f25561','擬東武曲二首  其二','宋祁','宋','宋诗','song-poetry','','[]','我家世世山西士，二十期門從天子。',144,'全唐诗/poet.song.11000.json','["我家世世山西士，二十期門從天子。", "始隨驃騎破祁連，晚逐樓船下䍧水。", "漢北雰雰飛雪暗，海中跕跕翔鳶墜。", "歸來武庫祭蚩尤，得從甘泉參豹尾。", "何意一朝兵後期，簿責侵誣屬軍吏。", "黄金納贖爲庶人，白首還家事田里。", "結髮從軍七十戰，利鏃金痍猶可記。", "龍鍾雖入玉關門，止呵還遇灞陵尉。", "不及金張藉舊勳，七葉華貂長富貴。"]'),
('0e8cfeb9-c1a8-4756-a0d7-c8028d8b997a','少年行','宋祁','宋','宋诗','song-poetry','','[]','君不見漢家五陵諸少年，白馬驪駒大道邊。',147,'全唐诗/poet.song.11000.json','["君不見漢家五陵諸少年，白馬驪駒大道邊。", "紫綸裁帽映兩紐，黄金錯带佩雙鞬。", "經過主第賜綠幘，歸宴前堂羅曲筵。", "長安多逐韓嫣彈，別藏仍收張氏錢。", "傳言天子將羽獵，千乘萬騎向甘泉。", "奉車金吾共馳騁，外家戚里見招延。", "徑去平岡馳狡兔，虛彎天際落飛鳶。", "朅來別館恣行樂，胡姬當罏酒十千。", "薄暮聊歸渭橋曲，明旦復會黄山前。"]'),
('3f948c99-0c0f-4167-8c31-18efa45a2b4a','天台梵才師長吉在都數以詩筆見授因答以轉句  其一','宋祁','宋','宋诗','song-poetry','','[]','九霞凝標倚霄極，爾時師在雲巖側。',32,'全唐诗/poet.song.11000.json','["九霞凝標倚霄極，爾時師在雲巖側。", "坐中不起見諸方，滿祴天香嗅薝蔔。"]'),
('5f137c72-e70a-4d94-9574-e631097a87ee','天台梵才師長吉在都數以詩筆見授因答以轉句  其二','宋祁','宋','宋诗','song-poetry','','[]','海嶠嶄嶄萬佛螺，赤髭半頷誰相過。',32,'全唐诗/poet.song.11000.json','["海嶠嶄嶄萬佛螺，赤髭半頷誰相過。", "卓錫時攀三宿樹，翻經詎著四圍駝。"]'),
('b76ceaad-82ec-4d73-81d0-d02a34e09927','天台梵才師長吉在都數以詩筆見授因答以轉句  其三','宋祁','宋','宋诗','song-poetry','','[]','何年擲鉢來京轂，抱蓬成畦紫蘭馥。',32,'全唐诗/poet.song.11000.json','["何年擲鉢來京轂，抱蓬成畦紫蘭馥。", "王公撇席爭逢迎，不意當今有平叔。"]'),
('ece97ded-1af7-415c-b4d5-ca360a49d5ec','天台梵才師長吉在都數以詩筆見授因答以轉句  其四','宋祁','宋','宋诗','song-poetry','','[]','第一多聞師子兒，碧雲餘力嗣工詩。',32,'全唐诗/poet.song.11000.json','["第一多聞師子兒，碧雲餘力嗣工詩。", "盡把天光注言語，真將清氣入肝脾。"]'),
('cd7d02e6-5985-4f3d-be6c-26e80fabb114','天台梵才師長吉在都數以詩筆見授因答以轉句  其五','宋祁','宋','宋诗','song-poetry','','[]','有人官冷抱窮愁，客坐無氈塵影流。',32,'全唐诗/poet.song.11000.json','["有人官冷抱窮愁，客坐無氈塵影流。", "吃口倦談真寂寞，移書避事喜旬休。"]'),
('b31c29b7-8961-47b5-9bd3-9df55fdc92cf','天台梵才師長吉在都數以詩筆見授因答以轉句  其六','宋祁','宋','宋诗','song-poetry','','[]','愧慚禪嫡來相問，刮目探懷授珍藴。',32,'全唐诗/poet.song.11000.json','["愧慚禪嫡來相問，刮目探懷授珍藴。", "已輕安石爲老生，更惱王筠賦强韵。"]'),
('fe4c52ab-4633-4ff2-81c3-23182e060231','天台梵才師長吉在都數以詩筆見授因答以轉句  其七','宋祁','宋','宋诗','song-poetry','','[]','比來緇侶頗言文，局促啁啾寧足論。',32,'全唐诗/poet.song.11000.json','["比來緇侶頗言文，局促啁啾寧足論。", "私地蛙鳴徒聒耳，長沙國小僅回身。"]'),
('e365ea60-7c01-48ed-acde-c01f78861663','天台梵才師長吉在都數以詩筆見授因答以轉句  其八','宋祁','宋','宋诗','song-poetry','','[]','惟師墨海多雄藻，具足身中無欠寶。',32,'全唐诗/poet.song.11000.json','["惟師墨海多雄藻，具足身中無欠寶。", "先追禦寇跨泠風，後伴騷人拾香草。"]'),
('61fffd46-e327-409f-bf35-e362504dd6b3','天台梵才師長吉在都數以詩筆見授因答以轉句  其九','宋祁','宋','宋诗','song-poetry','','[]','嗟余投報乏瓊瑰，目睇金園剩九回。',32,'全唐诗/poet.song.11000.json','["嗟余投報乏瓊瑰，目睇金園剩九回。", "籃轝媻姍兩生舉，定容元亮醉中來。"]'),
('f344efc5-dfe8-4c43-b240-0f1d2c47504e','謝提點刑獄李郎中贈扇','宋祁','宋','宋诗','song-poetry','','[]','規裁珍素裂輕雲，柄剪春篁燥叢露。',96,'全唐诗/poet.song.11000.json','["規裁珍素裂輕雲，柄剪春篁燥叢露。", "製以爲扇持贈君，拂君懷袖袪君暑。", "蜀天六月苦炎歊，赤龍秋秋駐雲霧。", "火走膚脈汗若流，暗逗浮凉下天宇。", "畫作飛蠅緣誤點，徐隔游塵不成污。", "何以爲報我知之，奉揚仁風慰黎庶。"]'),
('a03d3cb9-ebe2-4a5e-8651-1552d8fabaa5','詠西湖上寄潁州相公','宋祁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖邊烟樹與天齊，獨愛湖波照影時。',48,'全唐诗/poet.song.11000.json','["湖邊烟樹與天齊，獨愛湖波照影時。", "崖蔣渚蘋春披靡，佛樓僧閣暝參差。", "相君萬一來湖上，手弄潺湲更憶誰。"]'),
('870c0b88-255a-4a97-b181-fe76544e0315','和賈相公覽杜工部北征篇','宋祁','宋','宋诗','song-poetry','','[]','唐家六葉太平罷，宮豔醉骨恬無憂。',192,'全唐诗/poet.song.11000.json','["唐家六葉太平罷，宮豔醉骨恬無憂。", "阿犖詬天翠華出，糢糊戰血腥九州。", "乾瘡坤痍四海破，白日殺氣寒颼飀。", "少陵背賊走行在，採梠拾橡填饑喉。", "眼前亂離不忍見，作詩感慨陳大猷。", "北征之篇辭最切，讀者心隕如摧輈。", "莫肯念亂小雅怨，自然流涕袁安愁。", "才高位下言不入，憤氣鬰屈蟠長虬。", "今日奔亡匪天作，向來顛倒皆廟謀。", "忠骸佞骨相撐拄，一燎同燼悲崑丘。", "相君覽古慨前事，追美子美真詩流。", "前王不見後王見，願以此語貽千秋。"]'),
('a1579eaf-a0ed-454a-b4bd-cbd468960878','羅承制自戎州罷歸','宋祁','宋','宋诗','song-poetry','','[]','乘障一麾逮出守，終更三歲今來旋。',64,'全唐诗/poet.song.11000.json','["乘障一麾逮出守，終更三歲今來旋。", "巴雲晨趣東北道，僰月曉背西南天。", "故人把酒數卷白，離亭贈柳長于鞭。", "屬羌羈詔久款塞，歸爲天子細論邊。"]'),
('0d05a184-15ec-49c1-911c-cda2e24c7cdd','高亭駐眺招宮苑張端臣','宋祁','宋','宋诗','song-poetry','','[]','蜀天向臘寒未極，倚檻綿睇亭臯分。',64,'全唐诗/poet.song.11000.json','["蜀天向臘寒未極，倚檻綿睇亭臯分。", "一萍團紅江上日，數蓋淡白樓頭雲。", "杯中竹葉與誰舉，笛裏梅花那忍聞。", "願君枉步數相勞，他時離緒徒紛紛。"]'),
('c4db4b65-e4b9-4b1e-836c-fe547b9b4a4a','嘉祐庚子秋七月予還臺明年始對家圃春物作','宋祁','宋','宋诗','song-poetry','','[]','十年去國老蒙召，今歲始見家園春。',64,'全唐诗/poet.song.11000.json','["十年去國老蒙召，今歲始見家園春。", "雙燕初來即賓客，羣鶑相逢如故人。", "蒙茸草樹延野色，碎璅鮭菜供盤珍。", "多慚吾黨共醒醉，收得澤邊憔悴身。"]'),
('b4fb1a91-b41c-40aa-a7fc-f3e8f68b03f3','登齊雲亭','宋祁','宋','宋诗','song-poetry','','[]','少城西北最高處，憑檻極眺襟懷開。',64,'全唐诗/poet.song.11000.json','["少城西北最高處，憑檻極眺襟懷開。", "糢糊烟樹鳥邊靜，突兀雲山天外來。", "歸檣櫛櫛逗淮浦，凉颸獵獵生巖隈。", "雖非吾土信云美，伴客留連傾一盃。"]'),
('ec1ff493-94ed-4bd9-b697-cfb1eb2ab134','太廟侍祠雪霽有作','宋祁','宋','宋诗','song-poetry','','[]','喜雪靜氛埃，繁雲即日回。',48,'全唐诗/poet.song.11000.json','["喜雪靜氛埃，繁雲即日回。", "清光動冠劍，餘素著樓臺。", "樹雜瓊枝竦，途平玉轍開。", "惟應餘兩騎，知是海神來。"]'),
('ed77c542-2909-4985-b272-77d1cb86cac4','和吳侍郎朝謁天慶宮','宋祁','宋','宋诗','song-poetry','','[]','上路鳴騶遠，叢霄故館開。',48,'全唐诗/poet.song.11000.json','["上路鳴騶遠，叢霄故館開。", "華簪堯豸出，輕舄漢鳬來。", "探妙雲敷笈，蠲煩露溢杯。", "直須重締約，飛蓋一徘徊。"]'),
('3cef86d2-f40e-4a77-9eb8-fb85cba700d0','後苑賞花釣魚應制','宋祁','宋','宋诗','song-poetry','','[]','清籞披蘭路，雕輿眷蕙辰。',48,'全唐诗/poet.song.11000.json','["清籞披蘭路，雕輿眷蕙辰。", "漢池平浴日，溫樹暗留春。", "樂石來威鳳，恩波上翠鱗。", "成文傳睿唱，賡曲徧華紳。"]'),
('b118d3da-2178-420f-862a-029aa2fe6dec','元會詩','宋祁','宋','宋诗','song-poetry','','[]','寶典叢三朔，中闈闢九閽。',48,'全唐诗/poet.song.11000.json','["寶典叢三朔，中闈闢九閽。", "羣臣深拱宁，列仗儼屯門。", "輦出東房秘，辰居北極尊。", "熊羆連案負，日月傍旗翻。"]'),
('6185b5db-3f1d-4b0a-b3e0-bc13ceefa06a','奉和聖製清明日','宋祁','宋','宋诗','song-poetry','','[]','璇杓臨乙位，羲御屆婁初。',48,'全唐诗/poet.song.11000.json','["璇杓臨乙位，羲御屆婁初。", "碧浪桃花湧，珍叢錦段舒。", "輪蹄晴縹緲，鐘漏夕虛徐。", "穆穆宣溫殿，披文日有餘。"]'),
('341bb685-39f3-4c50-bd14-d41346b73174','晨赴書局','宋祁','宋','宋诗','song-poetry','','[]','上直蓬山遠，輕軒截九逵。',48,'全唐诗/poet.song.11000.json','["上直蓬山遠，輕軒截九逵。", "曉光銜睥睨，秋色靜罘罳。", "漸覺蘇裘敝，行嗟潘領衰。", "鷦鷯自有志，不羨帝梧枝。"]'),
('09815a19-f393-4cc9-be3d-829d59bb7692','和道卿舍人奉祠太一齋宮  其一','宋祁','宋','宋诗','song-poetry','','[]','素秋來蕊館，瑞祝達霄晨。',48,'全唐诗/poet.song.11000.json','["素秋來蕊館，瑞祝達霄晨。", "蘋薦祠無餼，樓居地不塵。", "擲波琴鯉樂，傍畤漢雞馴。", "此際清懷極，盈杯沆瀣津。"]'),
('ceeea2e6-a0f5-402e-b31d-fbaf50a11b4d','和道卿舍人奉祠太一齋宮  其二','宋祁','宋','宋诗','song-poetry','','[]','塵氛不可到，深注五城樓。',48,'全唐诗/poet.song.11000.json','["塵氛不可到，深注五城樓。", "素瑟少今韵，仙春無俗秋。", "晨杯三秀潔，夜檠九光流。", "順報通霄極，紛綸瑞福遒。"]'),
('24673682-7176-46f9-ae60-de55b58ba60b','和道卿舍人奉祠太一齋宮  其三','宋祁','宋','宋诗','song-poetry','','[]','地占叢霄勝，人持禁橐來。',48,'全唐诗/poet.song.11000.json','["地占叢霄勝，人持禁橐來。", "詩長清夜徧，祠罷素秋回。", "爽籟天中發，虛絃月際開。", "無容以風解，身自到蓬萊。"]'),
('66d6fcf3-b418-4c65-89a5-190881860ff5','和天休舍人奉祠太一宮見寄','宋祁','宋','宋诗','song-poetry','','[]','順祝齋琳館，翛然隔世埃。',48,'全唐诗/poet.song.11000.json','["順祝齋琳館，翛然隔世埃。", "空歌靈鵠下，祠節寶雞來。", "瑞木千尋竦，仙圖幾卷開。", "如無清夜唱，誰識帝車回。"]'),
('32c34f42-5a42-480b-865a-e5b3275f27df','玉堂感舊','宋祁','宋','宋诗','song-poetry','','[]','七年辭玉署，再入佐黄扉。',48,'全唐诗/poet.song.11000.json','["七年辭玉署，再入佐黄扉。", "樹與青春換，人將素領歸。", "磚花仍可記，厦雀稍驚飛。", "爐蕙非無意，逢人尚襲衣。"]'),
('cd396de4-4261-46aa-9630-db30900431ed','旬沐二首  其一','宋祁','宋','宋诗','song-poetry','','[]','薄澣還私室，陶嘉屬小園。',48,'全唐诗/poet.song.11000.json','["薄澣還私室，陶嘉屬小園。", "筍餘林嚮密，花後果初繁。", "燕口將泥重，蜂脾抱蜜喧。", "此時蕭散意，都欲忘乘軒。"]'),
('9eff3a62-25e6-4030-b388-36ea65315340','旬沐二首  其二','宋祁','宋','宋诗','song-poetry','','[]','待詔官非急，還家體不勤。',48,'全唐诗/poet.song.11000.json','["待詔官非急，還家體不勤。", "里無休汝騎，窗有上羲人。", "密樹稍迎夏，晚花猶及春。", "幽懷誰與晤，杯酒强相親。"]'),
('24ae5638-30b4-4f78-a8b1-853669b2c773','學舍直歸晚霽三首  其一','宋祁','宋','宋诗','song-poetry','','[]','驟雨挫炎威，歸軒廣陌西。',48,'全唐诗/poet.song.11000.json','["驟雨挫炎威，歸軒廣陌西。", "渠聲流作瀑，日脚側成霓。", "換錦龍媒埒，淹花燕子泥。", "比來巾角墊，李郭定相携。"]'),
('8fef7c4e-867e-40f9-a81a-9a8fc1a44478','學舍直歸晚霽三首  其二','宋祁','宋','宋诗','song-poetry','','[]','雨罷殘陽在，風微酷暑收。',48,'全唐诗/poet.song.11000.json','["雨罷殘陽在，風微酷暑收。", "餘昏淡雲翳，聚沫泛河流。", "桃簟雙紋展，盤瓜五色浮。", "潘郎最多感，庭樹莫先秋。"]'),
('731a0f4a-0746-47e5-b950-866eab04b011','學舍直歸晚霽三首  其三','宋祁','宋','宋诗','song-poetry','','[]','密霧披層宙，濃雲霽四溟。',48,'全唐诗/poet.song.11000.json','["密霧披層宙，濃雲霽四溟。", "亂流初潄玉，紅日不藏萍。", "萬葉張晴幄，千山卓翠屏。", "無煩事鐃吹，蛙響自堪聽。"]'),
('ff965b9e-7dcd-488b-9be7-965744a9b603','赴直馬上觀市','宋祁','宋','宋诗','song-poetry','','[]','上直驅羸馬，凌晨望百廛。',48,'全唐诗/poet.song.11000.json','["上直驅羸馬，凌晨望百廛。", "壚喧滌器市，簫暖賣餳天。", "流水隨輕轂，翻花送駛韉。", "區區市門吏，無復子真仙。"]'),
('7d81272c-bd15-46c1-8d23-5a943d2fcbe8','初到郡齋  其一','宋祁','宋','宋诗','song-poetry','','[]','專城四十外，中石二千餘。',48,'全唐诗/poet.song.11000.json','["專城四十外，中石二千餘。", "曠日慚良術，班春頼細書。", "學慵前志忘，身遠故人疏。", "姑俟天藏疾，雌堂日燕居。"]'),
('058c5071-2bcc-40b4-af88-29025a746e98','初到郡齋  其二','宋祁','宋','宋诗','song-poetry','','[]','省分由來拙，操心本自危。',48,'全唐诗/poet.song.11000.json','["省分由來拙，操心本自危。", "十年今得調，三匝此逢枝。", "攘臂貪豐粟，裝懷倦訴詞。", "竹林誰見憶，迢遞始平麾。"]'),
('5d7db8c6-72a4-4ff4-b1bf-4c48439524a7','初到郡齋三首  其一','宋祁','宋','宋诗','song-poetry','','[]','暫解樞機任，來從海上閒。',48,'全唐诗/poet.song.11000.json','["暫解樞機任，來從海上閒。", "浮雲富貴外，一馬是非間。", "月衮生潮浦，風香墮桂山。", "蒼生雖繫望，要作冶城還。"]'),
('d1666ed1-6146-43e9-9b58-6d315b7cab2b','初到郡齋三首  其二','宋祁','宋','宋诗','song-poetry','','[]','我里誠云樂，公今况釋勞。',48,'全唐诗/poet.song.11000.json','["我里誠云樂，公今况釋勞。", "秋蓴不下豉，霜蟹恣持螯。", "林靜來晨燎，江喧入夜濤。", "功成奮嘉藻，寧欲傍離騷。"]'),
('edfbb503-a567-4ab7-aba1-17880070f660','初到郡齋三首  其三','宋祁','宋','宋诗','song-poetry','','[]','溫省綢繆罷，鄉州偃息時。',48,'全唐诗/poet.song.11000.json','["溫省綢繆罷，鄉州偃息時。", "鶴情歸不怨，鳳德老無衰。", "月樹供園蒔，仙囊續宴巵。", "自慚淮守薄，千里與言詩。"]'),
('b58a612a-f469-48ec-ba47-94c9eba0abed','到官三歲四首  其一','宋祁','宋','宋诗','song-poetry','','[]','芳歲已三換，寵名仍再遷。',48,'全唐诗/poet.song.11000.json','["芳歲已三換，寵名仍再遷。", "生平一丘壑，衰晚右櫜鞬。", "客眼登樓外，鄉愁把酒前。", "巾箱多舊賦，只是欠歸田。"]'),
('9cc0aa63-d3d6-43ab-b1b3-c97131e9445e','到官三歲四首  其二','宋祁','宋','宋诗','song-poetry','','[]','一忝中山守，仍班第四春。',48,'全唐诗/poet.song.11000.json','["一忝中山守，仍班第四春。", "老應無所事，少尚不如人。", "適野愚謀短，將蕪舊産貧。", "須慚丈二組，羈束最慵身。"]'),
('6cae98aa-c001-4c89-84ad-475d4cbac227','到官三歲四首  其三','宋祁','宋','宋诗','song-poetry','','[]','儒帥非真帥，瓜時定幾時。',48,'全唐诗/poet.song.11000.json','["儒帥非真帥，瓜時定幾時。", "丹心雖許壯，白髮不藏衰。", "罟密游鱗駭，山遥倦翼遲。", "歲成無奏最，準擬雁門踦。"]'),
('d89654b9-a3d2-4bf7-bcce-b11ec9ee25c4','到官三歲四首  其四','宋祁','宋','宋诗','song-poetry','','[]','塞下靜無事，軍中奚告勞。',48,'全唐诗/poet.song.11000.json','["塞下靜無事，軍中奚告勞。", "青山側身遠，白日舉頭高。", "作奏閒雙筆，流年耗二毛。", "惟應不能飲，元解讀離騷。"]'),
('a5bba36a-9f01-49e5-9ad0-9f4062f272f7','潁上唐公張集仙相勞','宋祁','宋','宋诗','song-poetry','','[]','去時成恨恨，喜見眼中人。',48,'全唐诗/poet.song.11000.json','["去時成恨恨，喜見眼中人。", "共束西崑帙，都爲左虎鄰。", "年華衰意早，酒所故情親。", "後日孤舟遠，離懷怯重陳。"]'),
('2ca42a9b-ad8a-4ae3-b84a-128344069c70','同張子春淮上作','宋祁','宋','宋诗','song-poetry','','[]','南風今日好，歸棹上淮津。',48,'全唐诗/poet.song.11000.json','["南風今日好，歸棹上淮津。", "川迥舟如葉，山遥石似人。", "波光篙底動，沙壘漲餘新。", "誰信機心少，溪鷗伴此身。"]'),
('cecaa22b-a089-494a-8d75-55ee619a0970','思歸','宋祁','宋','宋诗','song-poetry','','[]','去國倏三歲，頗知歸思紛。',48,'全唐诗/poet.song.11000.json','["去國倏三歲，頗知歸思紛。", "南心曉城斗，北眼暮樓雲。", "珥筆行將脫，朝珂冷不聞。", "莫論持帥節，畎畝尚思君。"]'),
('7d1f4764-c913-41d1-be56-c0b4bdbbb581','有詔換淮陽','宋祁','宋','宋诗','song-poetry','','[]','比出淮陽守，今移寰內州。',48,'全唐诗/poet.song.11000.json','["比出淮陽守，今移寰內州。", "真無弱翁治，只是茂陵求。", "換節矜新假，循襟釋故愁。", "桑榆知未晚，前失庶能收。"]'),
('a795803e-c393-4017-bbce-abd1a71fcf9f','次江都  其一','宋祁','宋','宋诗','song-poetry','','[]','道險疑無地，巖高欲近天。',48,'全唐诗/poet.song.11000.json','["道險疑無地，巖高欲近天。", "家收代田粟，官鑄即山錢。", "雲變陰晴候，林容旦暮烟。", "落花真有意，時解拂行韉。"]'),
('bbd7893c-ddbc-47a4-b441-537794995218','次江都  其二','宋祁','宋','宋诗','song-poetry','','[]','江溜灘灘急，崖腰棧棧新。',48,'全唐诗/poet.song.11000.json','["江溜灘灘急，崖腰棧棧新。", "天深罕見日，路險不容塵。", "遠草夤緣綠，幽花落漠春。", "逢津何必問，夫我自知津。"]'),
('96a1b5ef-43b6-4a05-a679-80ec9539d3ca','齊雲亭晚矚','宋祁','宋','宋诗','song-poetry','','[]','山暝日云稷，天清風寖和。',48,'全唐诗/poet.song.11000.json','["山暝日云稷，天清風寖和。", "樹花紅暗淡，城草綠坡陀。", "歸艇衝烟去，昏鳬接翅過。", "年華無限樂，判作是狂歌。"]'),
('d9dc1fc3-d19d-4f1a-adc5-d5dcfd592caf','惠民隄河晚矚','宋祁','宋','宋诗','song-poetry','','[]','遠水同縈带，聯隄類築垣。',48,'全唐诗/poet.song.11000.json','["遠水同縈带，聯隄類築垣。", "行舟壓天底，卧木擁沙痕。", "魴鱮逃空罶，鳬鷖泊迥村。", "層波真可羨，由此到都門。"]'),
('af1ad1c0-c228-42fb-b2b0-93a908cdcf28','九日至衛南','宋祁','宋','宋诗','song-poetry','','[]','良辰獨據鞍，節物强相干。',48,'全唐诗/poet.song.11000.json','["良辰獨據鞍，節物强相干。", "酒駐衰顔淺，風吹客帽寒。", "暫吟非有屬，倦曲不成歡。", "多謝黄花意，還如故國看。"]'),
('db966f36-d4f1-4998-83b4-e6e573456cda','鄭子産廟','宋祁','宋','宋诗','song-poetry','','[]','不知東里叟，遺跡但堪尋。',48,'全唐诗/poet.song.11000.json','["不知東里叟，遺跡但堪尋。", "語愛東家淚，論交季子心。", "故墳猶有石，遺鼎遂無金。", "謬政爲邦久，千秋謝所欽。"]'),
('c1f87cc8-23de-4705-8a5c-fa8843e92849','疊嶂樓','宋祁','宋','宋诗','song-poetry','','[]','霍射盤西北，高樓勝覽并。',48,'全唐诗/poet.song.11000.json','["霍射盤西北，高樓勝覽并。", "景閒思謝守，名重擬宣城。", "天闕雲來緩，風微鳥去輕。", "客憂銷更有，須到此中傾。"]'),
('ee941305-e1a4-40ba-bf0a-4441fe092ccf','去鄭暮次中牟','宋祁','宋','宋诗','song-poetry','','[]','暮投京縣宿，氣象已紛羅。',48,'全唐诗/poet.song.11000.json','["暮投京縣宿，氣象已紛羅。", "菀樹道旁密，侯田關內多。", "高城切星斗，秋水似天河。", "自問還臺馬，猶餘幾子珂。"]'),
('b1228402-d6c6-4829-94ee-7506c173deae','廢鄭河','宋祁','宋','宋诗','song-poetry','','[]','當年食溱洧，此地控長津。',48,'全唐诗/poet.song.11000.json','["當年食溱洧，此地控長津。", "却見爲陵日，難尋病涉人。", "落霞遥送鶩，荐草暗留麏。", "代往詩風變，田渠數報春。"]'),
('6c29e0a5-f9a6-490c-b2f1-98175d78ea35','宛丘作','宋祁','宋','宋诗','song-poetry','','[]','宛丘真善地，承詔幸班春。',48,'全唐诗/poet.song.11000.json','["宛丘真善地，承詔幸班春。", "鈴下聽無訟，日邊來有人。", "吟餘多感客，睡足本慵身。", "蟣虱休相賀，吾今湯沐頻。"]'),
('18b7f523-ad21-4734-a23d-6d9a2d2e9cac','望漢江','宋祁','宋','宋诗','song-poetry','','[]','西導岷源闊，南浮楚望開。',48,'全唐诗/poet.song.11000.json','["西導岷源闊，南浮楚望開。", "弄珠嫌蚌隠，投璧讓蛟迴。", "岸翠山烟逼，波紅日影來。", "萬艘徒擾擾，誰是濟川材。"]'),
('4d888f73-d129-40f9-a903-814ecd661497','次劍門','宋祁','宋','宋诗','song-poetry','','[]','昔驅千騎往，今解五魚還。',48,'全唐诗/poet.song.11000.json','["昔驅千騎往，今解五魚還。", "誰憚老銷髀，自憐生入關。", "春風來迥野，曉斗掛空山。", "却整康成帢，依然愧膩顔。"]'),
('6aaac40d-a546-47f9-858f-bc0b3c000204','隴州魚龍川石魚','宋祁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','纖鱗藏介石，物化自何年。',48,'全唐诗/poet.song.11000.json','["纖鱗藏介石，物化自何年。", "無復西江水，長依東海田。", "苔紋堪代藻，雲葉即成蓮。", "琥珀藏蚊影，佳名共此傳。"]'),
('d7fccbc9-08ef-49b1-b2eb-7bfdde0534c8','次梓潼','宋祁','宋','宋诗','song-poetry','','[]','行行芳序深，秀色媚諸岑。',48,'全唐诗/poet.song.11000.json','["行行芳序深，秀色媚諸岑。", "早葉易經吹，暖雲難久陰。", "擁條孤狖嘯，戲荇一鳬沈。", "不是無樽酒，其誰共獻斟。"]'),
('fb6051b7-facc-4ec8-aeda-4321e3a36a9d','張亞子廟','宋祁','宋','宋诗','song-poetry','','[]','偉哉真丈夫，廟食此山隅。',48,'全唐诗/poet.song.11000.json','["偉哉真丈夫，廟食此山隅。", "生作百夫特，死爲南面孤。", "鹿庖償故約，雷杼驗幽符。", "潼水無時腐，英名相與俱。"]'),
('6fba0306-ec45-4e2c-b7c6-e9c9befdff98','敝俗','宋祁','宋','宋诗','song-poetry','','[]','陶姚民屋富，梁魏敝風存。',48,'全唐诗/poet.song.11000.json','["陶姚民屋富，梁魏敝風存。", "士闕游鄉校，人爭倚市門。", "椎埋時結客，博掩競成喧。", "誰與遷荼堇，移甘膴膴原。"]'),
('617591d6-839f-4502-8795-89ea0c3788c7','城外','宋祁','宋','宋诗','song-poetry','','[]','次舍梁陳外，風烟周鄭間。',48,'全唐诗/poet.song.11000.json','["次舍梁陳外，風烟周鄭間。", "徐驅四郊路，徧識屬城山。", "野雪融殘素，岑霞就暝殷。", "幾宵星影動，知伴傳車還。"]'),
('78094574-8b22-437d-9dae-0a4e82891972','題蜀州修覺寺','宋祁','宋','宋诗','song-poetry','','[]','蜀嶂紛重沓，祇園隠寂寥。',48,'全唐诗/poet.song.11000.json','["蜀嶂紛重沓，祇園隠寂寥。", "花供法界雨，江助梵音朝。", "海水聞鐘下，天風引磬遥。", "少陵佳句後，物色付吾僚。"]'),
('b879626f-103a-42e4-85f8-496cf98b271c','巡視河防置酒晚歸作二首  其一','宋祁','宋','宋诗','song-poetry','','[]','古戍連沙曲，層阿屬岸隈。',48,'全唐诗/poet.song.11000.json','["古戍連沙曲，層阿屬岸隈。", "天長倦鳥沒，山晚跛牂回。", "斜日低官樹，輕寒犯客杯。", "還城聞暮角，三疊落江梅。"]'),
('3212b487-138a-49ab-97f5-4791b822ead0','巡視河防置酒晚歸作二首  其二','宋祁','宋','宋诗','song-poetry','','[]','夾石雙隄轉，逍遥千騎留。',48,'全唐诗/poet.song.11000.json','["夾石雙隄轉，逍遥千騎留。", "川昏多晝霧，水落足寒洲。", "岸石危相倚，橋澌暮不流。", "風烟非渭曲，誰有釣璜鈎。"]'),
('28513405-e0ea-4251-a952-8e8f3228f0e1','轉運彭季長學士小集數辭宴集','宋祁','宋','宋诗','song-poetry','','[]','此日疾爲解，遂將杯酒疏。',48,'全唐诗/poet.song.11000.json','["此日疾爲解，遂將杯酒疏。", "多愁庾開府，苦瘦沈尚書。", "倦曲琴襓後，霏香藥裹餘。", "莫令詩思劇，正是落花初。"]'),
('06ddd937-5123-4dcf-a757-5fde3bc2f8fb','送張法曹','宋祁','宋','宋诗','song-poetry','','[]','駛騎柳枝鞭，春逵望雒廛。',48,'全唐诗/poet.song.11000.json','["駛騎柳枝鞭，春逵望雒廛。", "賦才賓右俊，掾諾府中賢。", "宮楯含櫻密，王渠泛醳聯。", "勝期資一笑，刑矢措周年。"]'),
('af448da6-4c3d-48cc-a672-384d3060e3d8','送呂太初法曹之許田','宋祁','宋','宋诗','song-poetry','','[]','秋涯艤客艫，潘鬢不勝梳。',48,'全唐诗/poet.song.11000.json','["秋涯艤客艫，潘鬢不勝梳。", "去决卿軍事，還親城旦書。", "驛鴉啼月早，庖鯉躍冰餘。", "白沖公庭步，翹材首曳裾。"]'),
('cc1387c8-4dc6-47bb-af99-2e6f631bb292','農歌','宋祁','宋','宋诗','song-poetry','','[]','農歌非度曲，新樂信蚩蚩。',48,'全唐诗/poet.song.11000.json','["農歌非度曲，新樂信蚩蚩。", "迺父知田事，吾王采諺辭。", "折楊時動笑，鼓腹自成嬉。", "日暮牛童笛，連聲下遠陂。"]'),
('0cb55387-58bb-457e-96ca-a75cf80e3d54','初宿東閣追憶文簡丁公作','宋祁','宋','宋诗','song-poetry','','[]','辭閣玉堂東，依然昔所從。',48,'全唐诗/poet.song.11000.json','["辭閣玉堂東，依然昔所從。", "舊池空嘆鳳，殘友不成龍。", "制藁流塵積，磚花駁蘚重。", "過車三步約，何日酹塋松。"]'),
('0e804daf-5123-428b-a4ab-e379ba8b02ae','三司晏尚書西園玩菊','宋祁','宋','宋诗','song-poetry','','[]','涉園求勝賞，時菊艷秋光。',48,'全唐诗/poet.song.11000.json','["涉園求勝賞，時菊艷秋光。", "散漫仙潭餌，褵褷瑞鵠裳。", "酒熏吹晚蕊，蜂冷抱殘香。", "公意周盈感，留杯盡夕陽。"]'),
('d63b04fc-7732-4e02-9700-134aa82b811b','玩齋前菊','宋祁','宋','宋诗','song-poetry','','[]','高秋玩佳菊，繁采照前除。',48,'全唐诗/poet.song.11000.json','["高秋玩佳菊，繁采照前除。", "似粟金無算，爲裳鵠有餘。", "不甘興薏謗，長免共蘭鉏。", "爲爾浮罇酒，非邀栗里輿。"]'),
('7d5864f2-abb7-4c1c-8ae5-09e35db1fffe','望僊亭書所見  其一','宋祁','宋','宋诗','song-poetry','','[]','危軒冠層堞，永日付登臨。',48,'全唐诗/poet.song.11000.json','["危軒冠層堞，永日付登臨。", "寒雁猶能陣，喬柯自不林。", "溪流橫趣島，樵路側依岑。", "西北雖堪望，浮雲易作陰。"]'),
('61c118e5-e4fa-4fb6-bd36-2caf4a2b7337','望僊亭書所見  其二','宋祁','宋','宋诗','song-poetry','','[]','南國冬無雪，居然氣候迷。',48,'全唐诗/poet.song.11000.json','["南國冬無雪，居然氣候迷。", "柔蔬傲霜甲，幽鳥逆春啼。", "神鼓聲無歇，樵歌韵不齊。", "舉頭看白日，還過太山西。"]'),
('300f3652-457d-475e-85d5-9e65ac6592f2','和楊學士同晏尚書西園對菊','宋祁','宋','宋诗','song-poetry','','[]','歲秋無異卉，佳菊自成妍。',48,'全唐诗/poet.song.11000.json','["歲秋無異卉，佳菊自成妍。", "薄采稱觴客，繁開落帽天。", "抱池閒沮洳，留蝶小翩翾。", "爲結胡公賞，并懷酈水邊。"]'),
('b4fbb347-6867-4e8e-b903-f2132b532b33','東亭','宋祁','宋','宋诗','song-poetry','','[]','左圃魚鱗闊，前軒翬翅開。',48,'全唐诗/poet.song.11000.json','["左圃魚鱗闊，前軒翬翅開。", "虹將一雨罷，潮送萬艘來。", "山凈秋妍露，林虛晚籟回。", "此時蕭散樂，誰奉醉言杯。"]'),
('9c0e88ee-6c1b-43e4-bf7d-81f7622d5122','隴西都尉禪會圖','宋祁','宋','宋诗','song-poetry','','[]','宴場禪集盛，霜幅繪毫工。',48,'全唐诗/poet.song.11000.json','["宴場禪集盛，霜幅繪毫工。", "竺社同開葉，嵇姿宛送鴻。", "法身寧滯相，世眼願瞻風。", "厨鑰方傳寶，非專巖壑中。"]'),
('f34e60d0-69fd-494b-829e-fa3769dc0e68','善惠大師禪齋','宋祁','宋','宋诗','song-poetry','','[]','丈室傳心地，安閒歲臘賒。',48,'全唐诗/poet.song.11000.json','["丈室傳心地，安閒歲臘賒。", "水能涵寶月，風解去萎花。", "鵠焰紗圍短，牛香篆引斜。", "化城無憚遠，門外即三車。"]'),
('22f8585d-7dee-4f6c-9aff-72c7625e0729','晚夏北軒','宋祁','宋','宋诗','song-poetry','','[]','螟崦霞霏罷，嚴城鼓疊通。',48,'全唐诗/poet.song.11000.json','["螟崦霞霏罷，嚴城鼓疊通。", "梧陰破階月，筵吹亂林風。", "浩露來無際，明河望若空。", "玉繩低影處，知是建章宮。"]'),
('d88adce5-bcdb-4d51-92b3-15bef796d634','呈胡希元進士二首  其一','宋祁','宋','宋诗','song-poetry','','[]','離邦嗟病免，道舊樂朋簪。',48,'全唐诗/poet.song.11000.json','["離邦嗟病免，道舊樂朋簪。", "刻畫忘齊醜，膏肓倚鄭箴。", "軒鴻遡霄路，和鶴答溪陰。", "爲薙求羊徑，時容一往尋。"]'),
('b560fa3c-0e9a-4310-a3e3-5da15234806b','呈胡希元進士二首  其二','宋祁','宋','宋诗','song-poetry','','[]','煢煢官綬解，落落飲瓢空。',48,'全唐诗/poet.song.11000.json','["煢煢官綬解，落落飲瓢空。", "君惠容藏疾，交情助諱窮。", "倦談嗟墨客，掉首覯鴻蒙。", "已卜良鄰計，無憂吾道東。"]'),
('418ad1ee-cb1b-4747-bccd-c13e342a4b62','贈罷征邊將','宋祁','宋','宋诗','song-poetry','','[]','罷征光祿塞，初入玉門關。',48,'全唐诗/poet.song.11000.json','["罷征光祿塞，初入玉門關。", "殘月邊兵盡，寒風壯士還。", "旗光侵桂卷，箭鏑半星閒。", "歸賜將軍第，長銘竇憲山。"]'),
('377bf0fa-346b-45db-a64a-7509b1146260','惠泉','宋祁','宋','宋诗','song-poetry','','[]','遥源辭疊嶂，澄派鑒晴虛。',48,'全唐诗/poet.song.11000.json','["遥源辭疊嶂，澄派鑒晴虛。", "流迅無汾惡，波長盡楚餘。", "隠之徒酌水，鄭伯謾名渠。", "不必西江去，憑君起鮒魚。"]'),
('48370812-2b7f-4a33-b347-b6288f6968ea','寄沂州王學士','宋祁','宋','宋诗','song-poetry','','[]','舊租丞相國，新治使君州。',48,'全唐诗/poet.song.11000.json','["舊租丞相國，新治使君州。", "坐樹貪循政，懷鉛倦雅遊。", "猿驚鄉嶺樹，蜃結海天樓。", "誰見行春盛，東方最上頭。"]'),
('bea87fd7-a317-4490-9eb3-346431f12cee','途中新歲憶三城兄長相公','宋祁','宋','宋诗','song-poetry','','[]','馬上逢元朔，匆匆記物華。',48,'全唐诗/poet.song.11000.json','["馬上逢元朔，匆匆記物華。", "趁盤呈柏葉，偷筆弄椒花。", "臈暝殘晨炬，春暉上早霞。", "三城今日酒，知我獨思家。"]'),
('2be3ec13-281c-4630-b605-e485f9113ee5','入壬辰新歲','宋祁','宋','宋诗','song-poetry','','[]','五十爲衰始，仍餘五歲衰。',48,'全唐诗/poet.song.11000.json','["五十爲衰始，仍餘五歲衰。", "雙眸不明鑑，殘鬢已紛絲。", "銅虎雖頻剖，荷囊信濫持。", "何須依老格，先作故山期。"]'),
('c4f8cb74-82c8-4488-b62a-78bbb8b8e540','送餘姚尉顧洵美先輩','宋祁','宋','宋诗','song-poetry','','[]','蓬葆已蕭蕭，從官越絕遥。',48,'全唐诗/poet.song.11000.json','["蓬葆已蕭蕭，從官越絕遥。", "山圖禹穴近，濤氣伍神驕。", "卧帳藏新論，舟行問故樵。", "寄聲時謝我，江上足蘭苕。"]'),
('1a9d71ee-bae5-40a4-b52e-8983fb2079ea','送張士安同年赴上元尉','宋祁','宋','宋诗','song-poetry','','[]','千名聯唱第，一尉滯徒勞。',48,'全唐诗/poet.song.11000.json','["千名聯唱第，一尉滯徒勞。", "山入黄旗國，江浮白鷺濤。", "苑葩依日晚，官樹共秋高。", "少賦思歸恨，潘才是二毛。"]'),
('3557bd9f-f60f-454a-a1c4-9594a20a0356','同賦飲舫','宋祁','宋','宋诗','song-poetry','','[]','飲有乘舟樂，舟因得飲名。',48,'全唐诗/poet.song.11000.json','["飲有乘舟樂，舟因得飲名。", "能招習池客，便載景山鐺。", "暫脣留頹玉，徐牽倒醉罌。", "莫辭沿泝遠，雙檝自逢迎。"]'),
('81632e05-0655-44eb-a767-9acf2da92a37','閱古堂','宋祁','宋','宋诗','song-poetry','','[]','堂皇對岑蔚，歡酌坐怡然。',48,'全唐诗/poet.song.11000.json','["堂皇對岑蔚，歡酌坐怡然。", "蟹美持螯日，魴甘抑鮓天。", "渚翹幽處鷺，林響靜時蟬。", "老去興非淺，無妨清夜旋。"]'),
('537b293b-7e17-4cb2-99ee-28880a0cb7a8','胡寅赴明州慈溪尉','宋祁','宋','宋诗','song-poetry','','[]','久困天官調，東南亦第如。',48,'全唐诗/poet.song.11000.json','["久困天官調，東南亦第如。", "客篙新溜急，春樹雜花餘。", "越𦞦豐池鴨，吳袍競庫綀。", "還音與歸夢，併附浙江魚。"]'),
('8102c63b-7d67-4eb5-bbec-6563e0e15fec','孫景赴懷寧尉','宋祁','宋','宋诗','song-poetry','','[]','一行爲吏日，千里背淮人。',48,'全唐诗/poet.song.11000.json','["一行爲吏日，千里背淮人。", "蘭助朝昏膳，絲垂宛轉綸。", "雲容侵驛曉，江態引帆春。", "靜治龍舒邑，氂生盜向秦。"]'),
('6b316f5c-3ba0-45bf-b9b0-2816edbff1d7','送王鼎同年尉滎陽','宋祁','宋','宋诗','song-poetry','','[]','氈毫聯署榜，蘭酒悵離杯。',48,'全唐诗/poet.song.11000.json','["氈毫聯署榜，蘭酒悵離杯。", "作吏緇衣國，工吟白社才。", "浮凉御風至，澄翠溢滎來。", "盜息連殊課，章封刺史臺。"]'),
('3ba69b46-76b3-4ff3-9e3c-74a0ff930131','奉節朱尉','宋祁','宋','宋诗','song-poetry','','[]','初命東南尉，征途上下弦。',48,'全唐诗/poet.song.11000.json','["初命東南尉，征途上下弦。", "傳家萬石貴，結綬半綸鮮。", "邑籍饒岷芋，公囊滿鄧錢。", "仙才今有助，銘閣待新篇。"]'),
('2798e06e-3ae6-4f5a-89f5-b22883559e5b','送靜海勾稽高洎','宋祁','宋','宋诗','song-poetry','','[]','豪錐殘試墨，綸綬照恩裳。',48,'全唐诗/poet.song.11000.json','["豪錐殘試墨，綸綬照恩裳。", "沿牒天官調，承家父任郎。", "曲長溪舫遠，宴密酒螯香。", "得助江山國，仍縫古錦囊。"]'),
('bb09ab7f-fd84-43a4-8480-f040bb73b519','送倪敦復朝奉','宋祁','宋','宋诗','song-poetry','','[]','倪侯喜清曠，遇物乃虛舟。',48,'全唐诗/poet.song.11000.json','["倪侯喜清曠，遇物乃虛舟。", "富貴知輕視，胸懷肯誤投。", "青雲非近器，滄海納羣流。", "道在從藏顯，功名晚可收。"]'),
('13cef7d9-3da3-41a3-a88a-7370a9bbc5f2','寄王共','宋祁','宋','宋诗','song-poetry','','[]','沸蟻雲罍溢，離鵾雪苑開。',48,'全唐诗/poet.song.11000.json','["沸蟻雲罍溢，離鵾雪苑開。", "吏催東府計，卿待楚人材。", "舊隠周蘿月，前期禹鑿雷。", "我慚芳歲晚，猶俊蹇修媒。"]'),
('388f1cad-5dd1-497a-9659-f6e846bf28e6','寄葉道卿','宋祁','宋','宋诗','song-poetry','','[]','懇乞東南節，貪榮綵繡衣。',48,'全唐诗/poet.song.11000.json','["懇乞東南節，貪榮綵繡衣。", "禁中嚴助往，江上子牟歸。", "併覺秋蓴美，時驚夜鶴飛。", "遥知具雞黍，日與故人揮。"]'),
('a1479d81-16e7-4ee0-8855-a2450bc303bf','秋霽二首  其一','宋祁','宋','宋诗','song-poetry','','[]','曉河迴北陸，夕雨凈西郊。',48,'全唐诗/poet.song.11000.json','["曉河迴北陸，夕雨凈西郊。", "水足魚忘喣，林寒鳥戀巢。", "閣苔浮綠暈，社橘老丹包。", "誰與同真想，清風是淡交。"]'),
('12199e61-7209-4992-89ef-df4e4e9308dd','秋霽二首  其二','宋祁','宋','宋诗','song-poetry','','[]','氣爽無餘暑，天高不住陰。',48,'全唐诗/poet.song.11000.json','["氣爽無餘暑，天高不住陰。", "霞殘仍是綺，風冷即名金。", "烟沼雙魚樂，霜郊一鶚心。", "此時靈運唱，無復答愁霖。"]'),
('ab53a78a-bc49-40a4-bcf6-f2169e0926ed','玩晚菊','宋祁','宋','宋诗','song-poetry','','[]','佳節雖云晚，繁英尚獨開。',48,'全唐诗/poet.song.11000.json','["佳節雖云晚，繁英尚獨開。", "新醪相伴熟，寒蝶不空來。", "細折愁香破，長吟恐暝催。", "自嫌霜白鬢，將插重裴回。"]'),
('7dffa4f1-38bc-4268-9080-cadaf286bded','殘秋霽景','宋祁','宋','宋诗','song-poetry','','[]','霜旻初畢雨，日氣上熹微。',48,'全唐诗/poet.song.11000.json','["霜旻初畢雨，日氣上熹微。", "寒水流無急，高雲薄未歸。", "書閒仍積簀，琴燥乍移徽。", "負郭泥妨轍，翻勞急掩扉。"]'),
('1c1ad113-5455-4de6-b12c-6ce093230db4','冬日呈應之','宋祁','宋','宋诗','song-poetry','','[]','賓席滿浮埃，勞歌倦撫懷。',48,'全唐诗/poet.song.11000.json','["賓席滿浮埃，勞歌倦撫懷。", "囊風寒薄木，鵾雪夜平階。", "莊室虛仍白，顔心靜已齋。", "北山如借問，矯首謝丹崖。"]'),
('8a114433-400b-4eb7-b6e6-2ba9217688bb','秋夕不寐','宋祁','宋','宋诗','song-poetry','','[]','槭槭始遥夜，騷騷無寐時。',48,'全唐诗/poet.song.11000.json','["槭槭始遥夜，騷騷無寐時。", "啼螿思歲晚，寒葉伴人衰。", "白髮生將遍，丹砂化苦遲。", "多情是殘月，通曉共遥帷。"]'),
('f9514c53-c59c-49a5-a260-b755a2a00109','冬日野外  其一','宋祁','宋','宋诗','song-poetry','','[]','霜郊堪極目，萬籟共騷騷。',48,'全唐诗/poet.song.11000.json','["霜郊堪極目，萬籟共騷騷。", "遠水無窮綠，寒雲自不高。", "候鴻差入渚，田雀短翔蒿。", "歲稔期民阜，中田饁凍醪。"]'),
('e7972e85-0fe8-409c-bbb5-914360829ef1','冬日野外  其二','宋祁','宋','宋诗','song-poetry','','[]','野迥人來少，天平鳥去長。',48,'全唐诗/poet.song.11000.json','["野迥人來少，天平鳥去長。", "魚梁四寸罟，樵市五家漿。", "谷轉留寒霧，霞休罷夕陽。", "不須教目極，即是到迴腸。"]'),
('722b298a-1ad1-4cba-83e1-48f423339c00','冬日野外  其三','宋祁','宋','宋诗','song-poetry','','[]','朔吹低凝野，層陰迥匝天。',48,'全唐诗/poet.song.11000.json','["朔吹低凝野，層陰迥匝天。", "葉飄霜外柳，烟山燒餘田。", "晼晚流芳後，崢嶸急景前。", "平生魚鳥志，寧免爲留連。"]'),
('d8a9f6ab-92d4-479b-a9e4-e1fa79fd6886','行春野外','宋祁','宋','宋诗','song-poetry','','[]','綠野陽膏動，春旗出曉衢。',48,'全唐诗/poet.song.11000.json','["綠野陽膏動，春旗出曉衢。", "川長羅後乘，林轉隠前驅。", "早蕊紅粘杏，輕苞紫綴榆。", "桑郊不敢問，直爲使君愚。"]'),
('56b15731-b8f7-43ad-ad69-8ff6421d80f2','贈文雅度大士','宋祁','宋','宋诗','song-poetry','','[]','高臘頷髭霜，棲閒寄寶坊。',48,'全唐诗/poet.song.11000.json','["高臘頷髭霜，棲閒寄寶坊。", "祕園金側布，薰夾字旁行。", "賜服恩華重，分燈祖意長。", "祗陀學久徧，餘力在雕章。"]'),
('7346c48e-34d0-425c-8480-f2af9946be94','守歲','宋祁','宋','宋诗','song-poetry','','[]','已覺新杓動，猶聞促漏餘。',48,'全唐诗/poet.song.11000.json','["已覺新杓動，猶聞促漏餘。", "夜寒窮臘尾，春色併年初。", "事往成追計，身羈況索居。", "明朝爲壽酒，無奈故人疏。"]'),
('bea6b9af-c9f3-4014-9b7a-a8fadaf2dbcf','歲晚私感','宋祁','宋','宋诗','song-poetry','','[]','已嗟官落魄，更值歲崢嶸。',48,'全唐诗/poet.song.11000.json','["已嗟官落魄，更值歲崢嶸。", "一絓區中累，千慚谷口耕。", "休文偏恨瘦，夷甫太鍾情。", "借問長安米，侏儒有底榮。"]'),
('6da510ee-6d20-43f0-b2bf-d26b48bbe01d','送同年葉文卿尉高郵','宋祁','宋','宋诗','song-poetry','','[]','檜檝艤河滣，東南再命新。',48,'全唐诗/poet.song.11000.json','["檜檝艤河滣，東南再命新。", "還家倦游客，隠市謫仙人。", "驛舍霜梅早，鄉壺蟻酎醇。", "疏林摇落盡，持底贈蕭辰。"]'),
('91ee834e-1b2d-4043-b53d-9330a03b9059','春晏病體少悰退卧北齋有寄','宋祁','宋','宋诗','song-poetry','','[]','小有負薪疾，早成憔悴姿。',48,'全唐诗/poet.song.11000.json','["小有負薪疾，早成憔悴姿。", "無人來迓跛，頼酒與扶衰。", "樸斲知林短，腥膢厭席卑。", "西山一丸藥，何忍獨相遺。"]'),
('1a975a79-38d8-4f42-ac54-132d09623009','殘花','宋祁','宋','宋诗','song-poetry','','[]','林下感餘歡，流芳逐雨殘。',48,'全唐诗/poet.song.11000.json','["林下感餘歡，流芳逐雨殘。", "香歸蜜房盡，紅入燕泥乾。", "夢短休成蝶，腸迴却掩鸞。", "故應成異果，持去擲潘安。"]'),
('0386bcf9-44c5-4c64-902d-c9a1466fdad2','王秀才贄賦乞詩爲別歸毗陵','宋祁','宋','宋诗','song-poetry','','[]','矩步敝長裾，清漳訪病夫。',48,'全唐诗/poet.song.11000.json','["矩步敝長裾，清漳訪病夫。", "得交欣鳳舉，賞賦怯霓呼。", "道勝稽論秀，人遐亟去都。", "一篷江上雨，歸思滿菰蘆。"]'),
('3b9164dc-2515-4e64-9769-d0ed790fc8d7','春郊曉望','宋祁','宋','宋诗','song-poetry','','[]','睡足猶欹枕，歡沉即掩樽。',48,'全唐诗/poet.song.11000.json','["睡足猶欹枕，歡沉即掩樽。", "風花飛有態，烟絮墜無痕。", "野色兼山遠，溪流漲雨渾。", "淵明有歸意，惟是對桐孫。"]'),
('32f42e59-5089-4907-bb30-db15a567edf1','送王識游洛陽','宋祁','宋','宋诗','song-poetry','','[]','上京漫客刺，西道摻離裾。',48,'全唐诗/poet.song.11000.json','["上京漫客刺，西道摻離裾。", "天倚呼嵩外，川橫鬭穀餘。", "敝襓琴晦軫，行笈簡聯書。", "却見槐花候，期君促計車。"]'),
('8a8623a3-a2e0-45aa-83cb-57182c6f3c64','僑居二首  其一','宋祁','宋','宋诗','song-poetry','','[]','抱病苦幽憂，都城困倦游。',48,'全唐诗/poet.song.11000.json','["抱病苦幽憂，都城困倦游。", "身拋禿翁版，言入稗家流。", "世路風波惡，天涯日月遒。", "危心正無泊，持底喻窮愁。"]'),
('e1ba4e0a-1763-46d5-a5a5-3803f0b35c40','僑居二首  其二','宋祁','宋','宋诗','song-poetry','','[]','公宇靜寥寥，居然俗意銷。',48,'全唐诗/poet.song.11000.json','["公宇靜寥寥，居然俗意銷。", "屐閒誰記齒，带適自忘腰。", "畝首秋殘穫，城西日暮樵。", "比來行樂熟，隨意度溪橋。"]'),
('340ec80a-0275-4212-ad93-931093804bb2','春晏北園三首  其一','宋祁','宋','宋诗','song-poetry','','[]','春物在無幾，景隨人意閒。',48,'全唐诗/poet.song.11000.json','["春物在無幾，景隨人意閒。", "筍生迷塢缺，花盡失林殷。", "墜絮來何所，輕雲久未還。", "持杯問流照，肯信有朱顔。"]'),
('b57b47e1-8789-4cdf-b803-82dda6ce56bb','春晏北園三首  其二','宋祁','宋','宋诗','song-poetry','','[]','天意歇餘芳，人閒日始長。',48,'全唐诗/poet.song.11000.json','["天意歇餘芳，人閒日始長。", "落花風觀閣，睡鴨雨池塘。", "稍倦持螯手，猶殘婪尾觴。", "春歸無所預，羈客自迴腸。"]'),
('2ba80027-6d47-45c6-a06d-082ff1d6218b','春晏北園三首  其三','宋祁','宋','宋诗','song-poetry','','[]','日晏休塵慮，中園眷物華。',48,'全唐诗/poet.song.11000.json','["日晏休塵慮，中園眷物華。", "驚禽曳啼去，弱柳受吹斜。", "暝早月沈碧，凉生水進涯。", "悠然望層堞，千翅度昏鴉。"]'),
('b5791973-1dd6-4831-a2e0-94c722eb1128','屏居寄獻侍講孫尚書','宋祁','宋','宋诗','song-poetry','','[]','僑版農廛陋，飛灰歲琯周。',48,'全唐诗/poet.song.11000.json','["僑版農廛陋，飛灰歲琯周。", "危疴負薪困，生事播精求。", "雨露遺幽谷，乾坤占一丘。", "惟餘道邊樹，獨爲報春遊。"]'),
('1952bd3f-82a1-40f0-aacb-8f5ce5701ac5','和丞相小園雨霽','宋祁','宋','宋诗','song-poetry','','[]','霽碧凝天宙，規紅轉日車。',48,'全唐诗/poet.song.11000.json','["霽碧凝天宙，規紅轉日車。", "鵲輕來燥枿，蜂濕抱寒花。", "林果高仍在，葅菘晚自嘉。", "須知窮僻處，要是酇侯家。"]'),
('6a3294e6-6c3f-4112-921d-9479fb4fad1e','送人歸衡陽','宋祁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','別曲慘鵾雞，沿湘望翠微。',48,'全唐诗/poet.song.11000.json','["別曲慘鵾雞，沿湘望翠微。", "人從南浦別，客向洞庭歸。", "曉雁并蘆遠，宵禽負葉飛。", "還家落秋後，社橘老金衣。"]'),
('a06e0637-da2c-43ac-bb58-1a0c74c8c715','松','宋祁','宋','宋诗','song-poetry','','[]','冒雪虬枝密，凌空麈影勻。',48,'全唐诗/poet.song.11000.json','["冒雪虬枝密，凌空麈影勻。", "葉傾秦帝雨，華老宓妃塵。", "不見棲鸞客，多逢繫馬人。", "寄聲遭匠石，千尺謝輪囷。"]'),
('dea227d7-148a-4c19-aebd-01b8cb37baa4','聞蟬','宋祁','宋','宋诗','song-poetry','','[]','秋風日夕驚，庭樹喝蟬聲。',48,'全唐诗/poet.song.11000.json','["秋風日夕驚，庭樹喝蟬聲。", "衰意先鶗鴂，繁音伴沸羹。", "斜陽掛高柳，落日淡遥城。", "此際君懷苦，非徒客子情。"]'),
('a609555c-165d-4be0-8c4f-35beaa469f3d','聞蟬有感三首  其一','宋祁','宋','宋诗','song-poetry','','[]','初聞蜀樹蟬，含喝晚風前。',48,'全唐诗/poet.song.11000.json','["初聞蜀樹蟬，含喝晚風前。", "便把凄凉意，催成摇落天。", "易驚惟遠客，所得是流年。", "空腹悲何事，繁于五十絃。"]'),
('9490f30e-755e-42e2-b21e-c4631baa5e9b','聞蟬有感三首  其二','宋祁','宋','宋诗','song-poetry','','[]','殘蛻拋何處，新聲集迥枝。',48,'全唐诗/poet.song.11000.json','["殘蛻拋何處，新聲集迥枝。", "歲芳鵙後妬，露信鶴前知。", "風塢嘶清御，霞梢咽暝規。", "此時兼一葉，併助長年悲。"]'),
('0d0eb2c3-3682-4fe2-bed3-cf7db44d10c3','聞蟬有感三首  其三','宋祁','宋','宋诗','song-poetry','','[]','勞君驚暮節，助我思流年。',48,'全唐诗/poet.song.11000.json','["勞君驚暮節，助我思流年。", "嘒若橫吹管，繁如未破絃。", "城殘嘶外月，林暝噪餘烟。", "塊坐秋風裏，潘郎鬢颯然。"]'),
('3116bf87-8c5c-4342-bef6-04aec9e8cd32','遠行','宋祁','宋','宋诗','song-poetry','','[]','平原已超忽，山徑亦紆餘。',48,'全唐诗/poet.song.11000.json','["平原已超忽，山徑亦紆餘。", "匹練迷征馬，孤蓬伴客車。", "江楓極目外，隴水斷腸初。", "行行不顧返，秋露泫人裾。"]'),
('1402fa5a-051b-4ff9-ad30-3aaa1b360843','夜緒','宋祁','宋','宋诗','song-poetry','','[]','炎氛歇層宇，清氣肅重帷。',48,'全唐诗/poet.song.11000.json','["炎氛歇層宇，清氣肅重帷。", "籟遠天人雜，宵閒甲乙遲。", "江湖牽客慮，日月與人衰。", "經國謀安在，悠悠空我思。"]'),
('65582bbd-d80e-4530-b285-2fd60ac807ea','幽禽','宋祁','宋','宋诗','song-poetry','','[]','已伴傳書燕，休隨匝樹鴉。',48,'全唐诗/poet.song.11000.json','["已伴傳書燕，休隨匝樹鴉。", "春鳴變高柳，暮散落餘花。", "格磔林烟迥，啁啾觀月斜。", "寧同七十二，鎮在莫愁家。"]'),
('065f04f6-7027-411f-bfda-6774fa4b973d','集江瀆池亭','宋祁','宋','宋诗','song-poetry','','[]','五月追凉地，滄江剩素漣。',48,'全唐诗/poet.song.11000.json','["五月追凉地，滄江剩素漣。", "林烟昏午日，樓影壓池天。", "篠密工迷徑，荷欹巧避船。", "機忘更何事，魚鳥亦留連。"]'),
('dd66f889-5011-42b4-934f-7f961028514b','出郊','宋祁','宋','宋诗','song-poetry','','[]','茂草平堪藉，長楊綠自垂。',48,'全唐诗/poet.song.11000.json','["茂草平堪藉，長楊綠自垂。", "郊晴艾帳遠，橋迥犢車遲。", "有鶴迎飛蓋，無蛇賭賜巵。", "秦樓何用識，馬尾結青絲。"]'),
('22aa3fd3-462f-48c5-9fc9-93a567be3e17','清暉亭','宋祁','宋','宋诗','song-poetry','','[]','亭外大江流，亭前萬里舟。',48,'全唐诗/poet.song.11000.json','["亭外大江流，亭前萬里舟。", "春波賦別地，秋水送歸愁。", "客路風烟闊，年光日月遒。", "瑶華何所爲，從古伴離憂。"]'),
('364f74d1-e8ca-4422-b382-80516cced07d','不言','宋祁','宋','宋诗','song-poetry','','[]','不言非巧宦，要是乏高符。',48,'全唐诗/poet.song.11000.json','["不言非巧宦，要是乏高符。", "託社天教散，爲公谷與愚。", "桂枝懷隠樹，荆葉戀歡株。", "榮路多高足，爭傳八列呼。"]'),
('fc56985e-cb86-4267-adb6-acd71bf7d791','朝天嶺','宋祁','宋','宋诗','song-poetry','','[]','天嶺循歸道，征旟面早暾。',48,'全唐诗/poet.song.11000.json','["天嶺循歸道，征旟面早暾。", "灘聲逢石怒，山氣附林昏。", "谷囀如禽哢，塵交作馬痕。", "萋萋芳草意，無乃爲王孫。"]'),
('748b3282-83d2-46ea-8905-de775534f9c0','讀張巡故事','宋祁','宋','宋诗','song-poetry','','[]','叛將闚華日，英臣死節年。',48,'全唐诗/poet.song.11000.json','["叛將闚華日，英臣死節年。", "城當勁兵處，人甚綴旒然。", "直木摧貪隧，長隄制盜泉。", "羯塵雖覆馬，不污沛南天。"]'),
('27c7074c-edce-4326-87c5-941771843c82','兔','宋祁','宋','宋诗','song-poetry','','[]','脫兔馳岡地，饑鷹厲吻天。',48,'全唐诗/poet.song.11000.json','["脫兔馳岡地，饑鷹厲吻天。", "爲煩麋狗顧，遂給獸人鮮。", "狂目兼槐落，驚毫共月捐。", "可嗟多狡穴，歸肉助庖羶。"]'),
('8b5d0ead-43e2-4da1-ae20-97f2ac3a6ac9','江休復潞掾','宋祁','宋','宋诗','song-poetry','','[]','君家能賦別，釋褐重凄然。',48,'全唐诗/poet.song.11000.json','["君家能賦別，釋褐重凄然。", "客袂移緇素，離杯並聖賢。", "坐曹煩折獄，奏牘竚懷鉛。", "十載青袍困，須饒草色鮮。"]'),
('641c57d2-2b15-4901-acf7-9f2bf7dd1ecb','同年李宗太平法掾','宋祁','宋','宋诗','song-poetry','','[]','俊名參吏啟，掾事補編堂。',48,'全唐诗/poet.song.11000.json','["俊名參吏啟，掾事補編堂。", "盡取黄金酒，重紆碧鶴裳。", "佐庖鮭菜厚，束帙秘厨香。", "認得公庭步，鬑鬚白皙郎。"]'),
('07568a46-94e0-4c8c-baba-01b53814b269','答安陸龐掾','宋祁','宋','宋诗','song-poetry','','[]','囊文嘗奏御，軍事此參卿。',48,'全唐诗/poet.song.11000.json','["囊文嘗奏御，軍事此參卿。", "座隘升堂友，鄉榮乞墅甥。", "清言飄麈毳，慎疾搴芝英。", "談幄尸官久，煩襟怯報瓊。"]'),
('4838a6fd-5ed9-4b20-8207-1062515a6482','出城暫憩林下','宋祁','宋','宋诗','song-poetry','','[]','下馬清林下，翛然忘俗情。',48,'全唐诗/poet.song.11000.json','["下馬清林下，翛然忘俗情。", "山禽不辨種，溪草盡無名。", "露笋披斑箬，風葩抗紫莖。", "徘徊漱巖溜，未忍濯塵纓。"]'),
('fd1bb19f-f926-4002-b83c-00d269d585a9','林下','宋祁','宋','宋诗','song-poetry','','[]','林下追凉久，山西反照初。',48,'全唐诗/poet.song.11000.json','["林下追凉久，山西反照初。", "蘭苕香自怨，蟬腹飽猶虛。", "李暗傾冠外，棋殘折屐餘。", "蕭然臯壤樂，何必羨池魚。"]'),
('187141d4-2bc1-4d08-8d0c-3bb0b711cea2','南國','宋祁','宋','宋诗','song-poetry','','[]','南國豪華地，東風駘蕩天。',48,'全唐诗/poet.song.11000.json','["南國豪華地，東風駘蕩天。", "露蘭薰夕夢，烟柳重春眠。", "歌斷雲空度，書長燕未傳。", "吟成休自許，芳草更綿綿。"]'),
('10b4bc41-099a-4ee9-b33f-c210db5a5ac1','送鞏漢卿同年赴五原理掾','宋祁','宋','宋诗','song-poetry','','[]','再赴天官調，仍還多士鄉。',48,'全唐诗/poet.song.11000.json','["再赴天官調，仍還多士鄉。", "華陰餘霧散，光祿故垣長。", "春柳侵湖綠，秋雲際幕黄。", "片言民訟息，編美冠州堂。"]'),
('ef3511c6-bef4-419c-ba42-9631032ffdfa','馮彭年蘇州法掾','宋祁','宋','宋诗','song-poetry','','[]','竹箭征艫駛，驪駒客袂分。',48,'全唐诗/poet.song.11000.json','["竹箭征艫駛，驪駒客袂分。", "倦游銷仲産，參事厭卿軍。", "象闕天中隔，鄉朝月外聞。", "西山朝氣爽，拄頰待談雲。"]'),
('95bdf9e0-31de-4829-b5ec-bc052dce2538','吏上','宋祁','宋','宋诗','song-poetry','','[]','吏上重門鑰，樓喧疊鼓撾。',48,'全唐诗/poet.song.11000.json','["吏上重門鑰，樓喧疊鼓撾。", "翠沈遥嶺樹，紅斂暝叢花。", "杼促蟲聲急，眉拖月魄斜。", "煩心銷熱盡，不待鎮嘉瓜。"]'),
('85131a4b-0dde-4234-8a23-25cec427ceb6','曲幌','宋祁','宋','宋诗','song-poetry','','[]','曲幌囊風入，前軒峽雨收。',48,'全唐诗/poet.song.11000.json','["曲幌囊風入，前軒峽雨收。", "醉羅初解夕，珍簟暗知秋。", "衰柳金城恨，幽蘭楚國愁。", "更堪聞短笛，珪月在西樓。"]'),
('31a2cbe8-51cb-4b64-a2f3-dca7faca6d46','林缺','宋祁','宋','宋诗','song-poetry','','[]','林缺榛苞綻，溪平芡嘴開。',48,'全唐诗/poet.song.11000.json','["林缺榛苞綻，溪平芡嘴開。", "衰烟稍辭柳，寒雨併饒苔。", "天意凄凄早，鄉愁衮衮來。", "此時論四戚，方驗楚人材。"]'),
('6db03558-a86f-4141-8860-ec66a2ea5f15','送朱十翁','宋祁','宋','宋诗','song-poetry','','[]','手把臨渦酒，人歸如夢城。',48,'全唐诗/poet.song.11000.json','["手把臨渦酒，人歸如夢城。", "何言一歡笑，便作兩離情。", "園樹丹蕤老，家山鈿髻明。", "不妨還軫促，芝崦趁春耕。"]'),
('cedc72c4-f616-4ac1-89b7-2dd7d37db052','司馬相如琴臺','宋祁','宋','宋诗','song-poetry','','[]','故臺千古恨，猶對舊家山。',48,'全唐诗/poet.song.11000.json','["故臺千古恨，猶對舊家山。", "半夜鸞凰去，他年駟馬還。", "死憂封禪晚，生愛茂陵閒。", "惟有飄飄氣，仍存天地間。"]'),
('ddaa19e9-393d-4ef0-a12b-c9b0dc46d92d','黄孝基歸上饒','宋祁','宋','宋诗','song-poetry','','[]','街徼曙鼕喧，行人岸艤船。',48,'全唐诗/poet.song.11000.json','["街徼曙鼕喧，行人岸艤船。", "杓星背城隠，萍日過江圓。", "霧晦書囊竹，塵昏劍室蓮。", "他時漢廷用，未減賈生年。"]'),
('bd74701b-b8a0-4e5a-a907-a67a96e25903','送謝處士南歸','宋祁','宋','宋诗','song-poetry','','[]','歲晏心無著，時清遁更肥。',48,'全唐诗/poet.song.11000.json','["歲晏心無著，時清遁更肥。", "江蓴縈箸滑，海鳥傍帆飛。", "鄉思生閩霧，吟懷入楚霏。", "趨庭多令子，綵服間荷衣。"]'),
('fcf237c4-7d71-4709-8703-0ca370fe77b4','登望臺','宋祁','宋','宋诗','song-poetry','','[]','年華無限景，況復上高臺。',48,'全唐诗/poet.song.11000.json','["年華無限景，況復上高臺。", "曉氣先明樹，春寒不著梅。", "幽禽仍早囀，戲蝶即雙來。", "此地流霞意，同誰一釂杯。"]'),
('50c6d471-0652-4428-832d-e60029f12514','連秀才東歸','宋祁','宋','宋诗','song-poetry','','[]','烟樹徧雲中，迎君馬首東。',48,'全唐诗/poet.song.11000.json','["烟樹徧雲中，迎君馬首東。", "鳴雞關下曉，歸鳥漢陽窮。", "倦客辭城闕，深耕託灌叢。", "還將數日惡，故故惱衰翁。"]'),
('a07d6a7b-566e-44a2-b9ea-7670029d4f87','徐帥北歸','宋祁','宋','宋诗','song-poetry','','[]','舊國青山闊，仙巖綠桂春。',48,'全唐诗/poet.song.11000.json','["舊國青山闊，仙巖綠桂春。", "金壺柱史客，玉札上清人。", "學霧應成市，泠風肯待旬。", "他年留半劑，牝谷願凝神。"]'),
('824c8e7b-21bc-4ed7-90df-d88fa4f7609c','北歸','宋祁','宋','宋诗','song-poetry','','[]','一水清波駛，還將檜檝歸。',48,'全唐诗/poet.song.11000.json','["一水清波駛，還將檜檝歸。", "纓緌成素濫，猿鶴恐長違。", "斗外城隅出，雲端闕影微。", "定知朝夕鳥，却望漢臺飛。"]'),
('bcaadfe6-2314-4536-ae9b-e1e7a752c5f2','宣徽太尉鄭公挽詞二首  其一','宋祁','宋','宋诗','song-poetry','','[]','祕幄留高議，雄邊倚茂勛。',48,'全唐诗/poet.song.11000.json','["祕幄留高議，雄邊倚茂勛。", "風流自南國，禮樂得中軍。", "卧疾初無損，遺忠忍遽聞。", "寢門今日慟，長作死生分。"]'),
('cab5bd02-1fe5-43a1-b590-1df8ad2abbfd','宣徽太尉鄭公挽詞二首  其二','宋祁','宋','宋诗','song-poetry','','[]','誰爲云亡恨，曾無可贖身。',48,'全唐诗/poet.song.11000.json','["誰爲云亡恨，曾無可贖身。", "江山歸國路，桃李泣蹊人。", "追冊君恩厚，題功史筆新。", "所嗟經濟事，不及相平津。"]'),
('af467ca4-55cf-40b3-9ca6-6dc561841dc8','肅簡魯公挽詞四首  其一','宋祁','宋','宋诗','song-poetry','','[]','拂世謨謀盛，端朝載采熙。',48,'全唐诗/poet.song.11000.json','["拂世謨謀盛，端朝載采熙。", "上前推汲直，天下詠曹隨。", "密啟多焚草，加餐饜嗜葵。", "不圖霜露疾，奄忽喪元龜。"]'),
('0e5a985a-f2c6-43f5-b3fa-eb187966da80','肅簡魯公挽詞四首  其二','宋祁','宋','宋诗','song-poetry','','[]','震邸陪翔鳳，天壇侍祭牲。',48,'全唐诗/poet.song.11000.json','["震邸陪翔鳳，天壇侍祭牲。", "參謀大丞相，別對小延英。", "上棟方隆國，頹山遽奠楹。", "武公年不至，輔德是功名。"]'),
('e7872eb9-4798-475c-9404-435c500fadf7','肅簡魯公挽詞四首  其三','宋祁','宋','宋诗','song-poetry','','[]','憂國神無愛，呼醫體寖臞。',48,'全唐诗/poet.song.11000.json','["憂國神無愛，呼醫體寖臞。", "人憂一臺坼，帝遣兩騶扶。", "臨視回襄御，遺言入舜謨。", "七兵榮贈冊，沉礎賁龜趺。"]'),
('7049c945-f6bc-478d-8720-fc8a10f174af','肅簡魯公挽詞四首  其四','宋祁','宋','宋诗','song-poetry','','[]','密勿千齡旦，生平三命恭。',48,'全唐诗/poet.song.11000.json','["密勿千齡旦，生平三命恭。", "承家男得鳳，擇婿女乘龍。", "酇邑窮遺産，邢山卜素封。", "空餘弔客淚，傾海望長松。"]'),
('2696a602-ee20-4352-b4d9-61fe11ce6078','王沂公挽詞三首  其一','宋祁','宋','宋诗','song-poetry','','[]','盡瘁辭當國，均勞得偃藩。',48,'全唐诗/poet.song.11000.json','["盡瘁辭當國，均勞得偃藩。", "幄中留秘畫，天下滿危言。", "日企還三事，寧圖閟九原。", "誰將河海淚，一灑問乾坤。"]'),
('3a372905-b57b-4d88-bf96-9a3167980575','王沂公挽詞三首  其二','宋祁','宋','宋诗','song-poetry','','[]','下閣成憂疢，飛郵走詔醫。',48,'全唐诗/poet.song.11000.json','["下閣成憂疢，飛郵走詔醫。", "遵鴻徒望渚，浴鳳不歸池。", "宣室君朝罷，翹車客涕垂。", "正應廊廟上，畫一奉蕭規。"]'),
('81d6256e-6ed1-4296-8bb4-591d2adfb36e','王沂公挽詞三首  其三','宋祁','宋','宋诗','song-poetry','','[]','翣路風號野，松阡水溢滎。',48,'全唐诗/poet.song.11000.json','["翣路風號野，松阡水溢滎。", "滕君今見日，傅魄上騎星。", "詒訓金籯滿，圖功籀史青。", "空嗟令君坐，千古掩餘馨。"]'),
('0910d53e-d6c3-48ba-8342-0f7fc99f778a','卜居','宋祁','宋','宋诗','song-poetry','','[]','自樂顔居陋，非論晏市囂。',48,'全唐诗/poet.song.11000.json','["自樂顔居陋，非論晏市囂。", "西山宜託疾，東路便歸樵。", "穴邃狐情樂，巢完鳥意遥。", "居然深隠去，寧待左生招。"]'),
('cf6dbde3-a8a6-465e-8161-204f05e2c983','訪隠者不遇','宋祁','宋','宋诗','song-poetry','','[]','青蘿白石扉，霞薄動春暉。',48,'全唐诗/poet.song.11000.json','["青蘿白石扉，霞薄動春暉。", "鶴去書空在，鳬閒舄自飛。", "驂鸞僊馭遠，出岫昔心違。", "拂衽雄風動，猶疑禦寇歸。"]'),
('f3e5563d-38b4-42c4-bc35-13cab83ad7c7','退居五首  其一','宋祁','宋','宋诗','song-poetry','','[]','干祿非三釜，躬耕戀一丘。',48,'全唐诗/poet.song.11000.json','["干祿非三釜，躬耕戀一丘。", "才無作奏巧，窮有著書愁。", "雀噪門羅晚，蓬飛鬢葆秋。", "平生鷗鳥志，未去戀滄洲。"]'),
('694d7260-62cc-4143-98b5-8ede2926b1c2','退居五首  其二','宋祁','宋','宋诗','song-poetry','','[]','貧極非關病，憂多信自傷。',48,'全唐诗/poet.song.11000.json','["貧極非關病，憂多信自傷。", "悲歌一頃豆，驚饋五家漿。", "擁耒宜耕石，沈鉤豈爲璜。", "中林環室在，開徑望求羊。"]'),
('3636ff16-f56f-444a-bc1c-23b887505a0f','退居五首  其三','宋祁','宋','宋诗','song-poetry','','[]','昔愧公車牘，今投海岸簪。',48,'全唐诗/poet.song.11000.json','["昔愧公車牘，今投海岸簪。", "逢齏還忌熱，居陸更憂沈。", "楚岫偏藏玉，燕臺豈乏金。", "前途見楊阮，只是有沾襟。"]'),
('f21d685b-af7a-44cb-afcd-6101fd48d4ea','退居五首  其四','宋祁','宋','宋诗','song-poetry','','[]','利固慚龍斷，長非累纆牽。',48,'全唐诗/poet.song.11000.json','["利固慚龍斷，長非累纆牽。", "難求迎鮒水，空望戴盆天。", "喘急常悲月，驚多遂惡弦。", "誠非窮者歎，民頌正堯年。"]'),
('bd51a026-a902-4051-bee9-21621d4e3911','退居五首  其五','宋祁','宋','宋诗','song-poetry','','[]','勇退方藏密，營生信有涯。',48,'全唐诗/poet.song.11000.json','["勇退方藏密，營生信有涯。", "千株素封栗，五色故侯瓜。", "虞骨誠非媚，潘毛故易華。", "履穿誰復問，新進競青緺。"]'),
('9cc2f2c7-8088-4954-b70d-2f4db2bc9c04','詠苔','宋祁','宋','宋诗','song-poetry','','[]','雨牆蒼暈合，烟渚碧紋通。',48,'全唐诗/poet.song.11000.json','["雨牆蒼暈合，烟渚碧紋通。", "賦閣并塵掩，詩階伴藥紅。", "萍流煩結實，絮亂枉因風。", "少閟回腸恨，春閨隔歲空。"]'),
('02e6cdd3-ffce-4510-9067-6dd88f820a6b','南齋二首  其一','宋祁','宋','宋诗','song-poetry','','[]','隠有山林願，閒非江海身。',48,'全唐诗/poet.song.11000.json','["隠有山林願，閒非江海身。", "孔書罕言命，莊意闇同人。", "敢衒能鳴雁，須慚不獵鶉。", "緣何無麗句，多病極漳濱。"]'),
('c543f802-185a-4ac2-8bc7-a62ea657973a','南齋二首  其二','宋祁','宋','宋诗','song-poetry','','[]','曩宦緣三釜，今歸分一丘。',48,'全唐诗/poet.song.11000.json','["曩宦緣三釜，今歸分一丘。", "杯棬非柳性，塗尾是龜謀。", "薪意矜來仕，瓜名託故侯。", "恍然桑下計，蠶妾詎相尤。"]'),
('98a668a9-af44-408d-8181-2779a8d71559','哀故文節公  其一','宋祁','宋','宋诗','song-poetry','','[]','早傳黄石系，未伴赤松遊。',48,'全唐诗/poet.song.11000.json','["早傳黄石系，未伴赤松遊。", "暴疹驚牀蟻，深恩賜養牛。", "谿璜俄碎玉，川檝遂藏舟。", "蕭相今無嗣，夫人紹酇侯。"]'),
('6e0bd607-16a6-4f6f-8e39-cb3a77435e21','哀故文節公  其二','宋祁','宋','宋诗','song-poetry','','[]','順采思忠藎，宣謀歎巧勞。',48,'全唐诗/poet.song.11000.json','["順采思忠藎，宣謀歎巧勞。", "憗遺無一老，投弔剩三號。", "撤奠哀笳引，追榮斂衮褒。", "欲知憑厚慶，弟覽得傳刀。"]'),
('63d43ff1-073c-4829-bedc-31f7e3a6f0a4','哀故文節公  其三','宋祁','宋','宋诗','song-poetry','','[]','霜露纔嬰疾，龍蛇已喪賢。',48,'全唐诗/poet.song.11000.json','["霜露纔嬰疾，龍蛇已喪賢。", "神騎尾星次，家託寢丘田。", "長樂申君弔，東堂罷禊筵。", "佳城白日掩，從此即千年。"]'),
('62df023b-97a6-4ae1-a486-9be83b44eeed','章靖馮公哀詞  其一','宋祁','宋','宋诗','song-poetry','','[]','華殿推名學，南宮重亞卿。',48,'全唐诗/poet.song.11000.json','["華殿推名學，南宮重亞卿。", "心無二何佞，身有兩龔清。", "歸沐賓綦鮮，幽通筆思精。", "邦人爲公恨，不見相承平。"]'),
('8017dd67-e0ad-416b-8eb7-fcb88dc4ea4f','章靖馮公哀詞  其二','宋祁','宋','宋诗','song-poetry','','[]','讀易三編斷，當朝萬事知。',48,'全唐诗/poet.song.11000.json','["讀易三編斷，當朝萬事知。", "由來不語怪，何意遂無兒。", "酒德歡長絕，書林藁尚遺。", "異時逢玉尺，方爲阮咸悲。"]'),
('90b0031a-b406-4a43-bd08-9f664f6513f9','章靖馮公哀詞  其三','宋祁','宋','宋诗','song-poetry','','[]','睆簀綿疴革，中楹奠夢還。',48,'全唐诗/poet.song.11000.json','["睆簀綿疴革，中楹奠夢還。", "蕝儀猶在野，書副即藏山。", "友酹生芻潔，君恩刻印頒。", "一朝交臂失，寧復易睎顔。"]'),
('a6d6b3e2-aafe-43ea-8019-81fe439db93c','章靖馮公哀詞  其四','宋祁','宋','宋诗','song-poetry','','[]','風旌引素轅，歌紼遠猶喧。',48,'全唐诗/poet.song.11000.json','["風旌引素轅，歌紼遠猶喧。", "此路成千古，何人歎九原。", "未亡鍾淑儷，不朽寄空言。", "兄子今爲後，春秋無餒魂。"]'),
('3bf45bb2-915b-4926-a09e-d33da3f9d12d','光祿葉大卿哀詞  其一','宋祁','宋','宋诗','song-poetry','','[]','八十浮齡盡，三千去日長。',48,'全唐诗/poet.song.11000.json','["八十浮齡盡，三千去日長。", "叢蘭秋寂寞，卿月夜蒼茫。", "里友歌迎紼，州民酹續漿。", "英魂知所託，橋梓藹成行。"]'),
('839cf98b-8a77-47c9-a3a4-628cd295c334','光祿葉大卿哀詞  其二','宋祁','宋','宋诗','song-poetry','','[]','偃息朋三壽，生平定四知。',48,'全唐诗/poet.song.11000.json','["偃息朋三壽，生平定四知。", "鄉人榮衣繡，光祿號能詩。", "未赴安車召，遽成埋玉悲。", "方珉紀遺愛，無誑冢中辭。"]'),
('01b9b805-91b8-47f5-b5cd-28ace187e652','辨才少白師歸天台','宋祁','宋','宋诗','song-poetry','','[]','壤色擁行肩，南方應有緣。',48,'全唐诗/poet.song.11000.json','["壤色擁行肩，南方應有緣。", "歸艎素車浪，寶戺赤城天。", "宴樹春園密，談花畫祴鮮。", "憑師無閡智，呵黜二宗禪。"]'),
('b403f95c-c709-4a99-9b0d-cca8fdb9b22a','懷滕秘校書','宋祁','宋','宋诗','song-poetry','','[]','解職青袍困，驚年素髮多。',48,'全唐诗/poet.song.11000.json','["解職青袍困，驚年素髮多。", "囊中彭澤米，門外下邽羅。", "露鶴驚霄島，風蜩喝暝柯。", "此時潘簟冷，爭奈近秋何。"]'),
('46710527-c069-42af-acb1-0f0c0c6251de','送黄秘校書','宋祁','宋','宋诗','song-poetry','','[]','妙齡看試牘，共嘆俊登喧。',48,'全唐诗/poet.song.11000.json','["妙齡看試牘，共嘆俊登喧。", "十載重來調，猶參軍事煩。", "吳艎沿迅溜，京炙伴芳樽。", "東觀他年選，當求江夏孫。"]'),
('8f3d580e-f389-4af7-80e6-25437aa03a14','公會亭  其一','宋祁','宋','宋诗','song-poetry','','[]','日下炎氛歇，風生凉意添。',48,'全唐诗/poet.song.11000.json','["日下炎氛歇，風生凉意添。", "樹花閒纂纂，樓月靜纖纖。", "倦綆仍垂缶，昏鈎半上簾。", "畦瓜已堪摘，納履自無嫌。"]'),
('ba2816a6-a491-452e-851f-1de8a530130f','公會亭  其二','宋祁','宋','宋诗','song-poetry','','[]','吏罷得休沐，襟懷蕭散中。',48,'全唐诗/poet.song.11000.json','["吏罷得休沐，襟懷蕭散中。", "靜時飛蝶夢，閒處上皇風。", "稚篠因依碧，疏花磔索紅。", "素餐無所事，天幸一衰翁。"]'),
('51db5ea7-4609-4332-afc9-9323f79f1800','和小飲','宋祁','宋','宋诗','song-poetry','','[]','天帟暮雲消，飛觴夜正遥。',48,'全唐诗/poet.song.11000.json','["天帟暮雲消，飛觴夜正遥。", "洛吟聊擁鼻，陶舞惜迴腰。", "露曉蟬嘶樹，河秋鵲映橋。", "客歡殊未幾，離恨又霞朝。"]'),
('a13d1599-27bb-4d1c-a966-cd58e2dfd49b','夏日江瀆亭小飲','宋祁','宋','宋诗','song-poetry','','[]','飛檻枕溪光，歡言客徧觴。',48,'全唐诗/poet.song.11000.json','["飛檻枕溪光，歡言客徧觴。", "暫雲消樹影，驟雨發荷香。", "辛臼橙齏熟，庖刀膾縷長。", "蘋風如有意，盈衽借浮凉。"]'),
('fb153861-c711-48f4-baeb-fcd0210d8302','朝陽','宋祁','宋','宋诗','song-poetry','','[]','縮宿沈榆彩，滄溟轉若華。',48,'全唐诗/poet.song.11000.json','["縮宿沈榆彩，滄溟轉若華。", "纔晞漢盤露，便映洛神霞。", "鳴鳳梧岡迥，桑柔桂籠斜。", "照梁休自許，城上已啼鴉。"]'),
('71e35d5c-a499-4f5a-bcb3-ad3e2eade3e2','唐李衛公廟','宋祁','宋','宋诗','song-poetry','','[]','斯人天挺傑，賊膽畏膏肓。',48,'全唐诗/poet.song.11000.json','["斯人天挺傑，賊膽畏膏肓。", "疾戰江陵破，長驅頡利亡。", "成功在不伐，垂烈付無疆。", "血食雄京輔，于今異姓王。"]'),
('ec2011bd-c1f3-42a1-8d90-b415420676b6','夜出溪上','宋祁','宋','宋诗','song-poetry','','[]','隴首孤雲斷，坳塘綠水周。',48,'全唐诗/poet.song.11000.json','["隴首孤雲斷，坳塘綠水周。", "螢光不欺夜，蟲織自悲秋。", "早雁離離度，歸舟泛泛流。", "萱蘇共摇落，底處是忘憂。"]'),
('b8d47b26-00a0-4a21-8898-40ed2a5c836f','秋晚溪上','宋祁','宋','宋诗','song-poetry','','[]','積水增波潤，蒼霞變露餘。',48,'全唐诗/poet.song.11000.json','["積水增波潤，蒼霞變露餘。", "斷煙隨鳥遠，寒葉向人疏。", "萍老猶迎日，蓮衰尚戲魚。", "臨川方病涉，誰借鄭卿輿。"]'),
('f6349adb-73f5-4ea5-8379-8606780c1234','出城所見賦五題  其一','宋祁','宋','宋诗','song-poetry','','[]','二月雨堪愛，霏霏膏澤盈。',48,'全唐诗/poet.song.11000.json','["二月雨堪愛，霏霏膏澤盈。", "添成竹箭浪，催發杏花耕。", "迥濕風頭冷，微含日脚明。", "居然嘉應在，誰是束長生。"]'),
('70869f80-dd16-4487-a84d-97b3df7139da','出城所見賦五題  其二','宋祁','宋','宋诗','song-poetry','','[]','二月水堪愛，泮流清復渾。',48,'全唐诗/poet.song.11000.json','["二月水堪愛，泮流清復渾。", "影深天在底，紅亂日摇痕。", "鶩沒小舟度，魚喁新藻翻。", "有人無限思，慚愧仲長言。"]'),
('c2448d7b-548b-41f4-b963-474254ba2cf7','出城所見賦五題  其三','宋祁','宋','宋诗','song-poetry','','[]','二月花堪愛，全開未落時。',48,'全唐诗/poet.song.11000.json','["二月花堪愛，全開未落時。", "香輕長抱蕊，霞破即團枝。", "舞蝶何曾定，流鶑不待期。", "勞君金縷唱，更盡拍浮巵。"]'),
('d1488eef-da29-400f-8044-0e36815e728c','出城所見賦五題  其四','宋祁','宋','宋诗','song-poetry','','[]','二月草堪愛，一番芳意還。',48,'全唐诗/poet.song.11000.json','["二月草堪愛，一番芳意還。", "遠迷天泱泱，低隠雉斑斑。", "細雨鮮原潤，東風古道閒。", "王孫歸定否，持問桂枝山。"]'),
('0253092e-4269-48f5-af0e-754bb0aeafd2','出城所見賦五題  其五','宋祁','宋','宋诗','song-poetry','','[]','二月風堪愛，悠悠天際生。',48,'全唐诗/poet.song.11000.json','["二月風堪愛，悠悠天際生。", "向空鳴籟細，乘暝作寒輕。", "拂水紋層浪，穿條杌紫莖。", "煩君期素魄，相伴倒春清。"]'),
('a3e22e97-8ea7-4eb1-ad7d-670b3b049209','重葺敝廬有作','宋祁','宋','宋诗','song-poetry','','[]','屨市喧卑極，家林改築初。',48,'全唐诗/poet.song.11000.json','["屨市喧卑極，家林改築初。", "藩傾猶置筆，楹破尚逢書。", "徑草臨江府，園畦洛涘居。", "憑誰遣真意，仁義亦蘧廬。"]'),
('124ce624-8dd2-498d-9a0e-ebde655e691d','華州西溪','宋祁','宋','宋诗','song-poetry','','[]','山近重嵐逼，溪長匹練分。',48,'全唐诗/poet.song.11000.json','["山近重嵐逼，溪長匹練分。", "霽波平撼日，寒崦側藏雲。", "弄荇魚差尾，投汀鷺列羣。", "如何去尋丈，塵路已紛紛。"]'),
('d105f64f-612c-4597-8485-e3d197b0f61f','送客','宋祁','宋','宋诗','song-poetry','','[]','西出都門路，橫參送客鞍。',48,'全唐诗/poet.song.11000.json','["西出都門路，橫參送客鞍。", "低雲能作暝，輕吹不成寒。", "天勢高無極，原姿秀可餐。", "長年傷別甚，作惡叵能歡。"]'),
('eb3eaf0d-ab7e-4849-b8e5-6317990d4b67','僖宗在蜀諫官孟昭圖上疏言田令孜屏書不奏沈之蝦蟆津詩人鄭谷傷之略曰徒將心許國不識道消時予欽其人作詩投弔','宋祁','宋','宋诗','song-poetry','','[]','密疏即儲胥，指言刀鋸餘。',48,'全唐诗/poet.song.11000.json','["密疏即儲胥，指言刀鋸餘。", "難排趙高鹿，竟葬楚江魚。", "憤魄棲長瀨，冤氛犯太虛。", "無人抉君目，他日見誅除。"]'),
('ffbd5bd6-631b-4226-bd4a-8a04efeba8f3','李九言寺丞知懷安軍金堂縣','宋祁','宋','宋诗','song-poetry','','[]','雲棧馬蕭蕭，銅章庇邑遥。',48,'全唐诗/poet.song.11000.json','["雲棧馬蕭蕭，銅章庇邑遥。", "晨暉碧雞路，春色錦官橋。", "美政方宣布，斯人舊富饒。", "早須飛兩舄，歸趁漢家朝。"]'),
('c5713cd2-cafb-4168-a5f1-3c718720dd76','挽張元常葬母夫人二首  其一','宋祁','宋','宋诗','song-poetry','','[]','象服流恩貴，輕輿就養榮。',48,'全唐诗/poet.song.11000.json','["象服流恩貴，輕輿就養榮。", "新成大家賦，經餉潁封羹。", "過隙誠難駐，藏舟自不驚。", "子賢能順禮，三月祔佳城。"]'),
('83b25cdb-ac7e-4ebf-88a6-86f7f0f054ba','挽張元常葬母夫人二首  其二','宋祁','宋','宋诗','song-poetry','','[]','嬰病曾無苦，期頤未滿年。',48,'全唐诗/poet.song.11000.json','["嬰病曾無苦，期頤未滿年。", "風酸吹棘地，露泣採蘭天。", "庀具藏分澤，張琴委暗絃。", "江流終不竭，懿範此俱傳。"]'),
('e9988459-f31f-45ed-a36e-b62a1fa66e34','遣吏視諸公塋樹回有感 文正王丞相','宋祁','宋','宋诗','song-poetry','','[]','兩朝推巨德，萬務罄斯猷。',48,'全唐诗/poet.song.11000.json','["兩朝推巨德，萬務罄斯猷。", "漢日左右手，堯年忠孝侯。", "名言天下滿，故事省中留。", "宸篆旌碑首，刊文又幾秋。"]'),
('a43d05b5-3e57-407e-bc50-011ed87a8547','遣吏視諸公塋樹回有感 文靖呂丞相','宋祁','宋','宋诗','song-poetry','','[]','慶曆公三入，邊陲擾太平。',48,'全唐诗/poet.song.11000.json','["慶曆公三入，邊陲擾太平。", "啖金真間敵，撓酒不寒盟。", "上印情雖切，然髭病遽輕。", "惜哉天弗憗，宸幄淚先橫。"]'),
('b427b37b-62fa-4f4e-8065-362640e3d5ac','遣吏視諸公塋樹回有感 宣獻宋公','宋祁','宋','宋诗','song-poetry','','[]','昔去勸明辟，俄歸參大鈞。',48,'全唐诗/poet.song.11000.json','["昔去勸明辟，俄歸參大鈞。", "公孫未及相，諸葛已傷神。", "名待天淵蔽，文爭日月新。", "英魂同玉樹，不向土中春。"]'),
('f9e2b5aa-07b1-4e1b-b5ea-939dcb9933bb','遣吏視諸公塋樹回有感 文惠陳丞相','宋祁','宋','宋诗','song-poetry','','[]','巖廊號元老，禮數盛中台。',48,'全唐诗/poet.song.11000.json','["巖廊號元老，禮數盛中台。", "萬石父子貴，八元兄弟才。", "新詩玉可扣，奇隸鵲爭回。", "今日看碑字，真緣灑淚來。"]'),
('6f0bac35-4889-46b7-bfab-1b23e35a0399','答客','宋祁','宋','宋诗','song-poetry','','[]','賤子空虛甚，何煩跪自陳。',48,'全唐诗/poet.song.11000.json','["賤子空虛甚，何煩跪自陳。", "摧藏不鳴雁，排迮後來薪。", "櫛短三秋髮，途奔四海塵。", "安能得所欲，況是數奇人。"]'),
('1e124c64-648a-43e9-8107-9d9d50c05c22','送同年吳瑴尉烏程','宋祁','宋','宋诗','song-poetry','','[]','鼕鼕報曙天，歸趁越人船。',48,'全唐诗/poet.song.11000.json','["鼕鼕報曙天，歸趁越人船。", "閩月長留夢，吳門自是仙。", "漆書多汗竹，圭祀有名田。", "剩著凌雲賦，囊帷待奏篇。"]'),
('0f6a7c2e-31e1-4488-ba44-8ee7a050ec00','送王庾  其一','宋祁','宋','宋诗','song-poetry','','[]','土甑殘炊黍，津航促扣舷。',48,'全唐诗/poet.song.11000.json','["土甑殘炊黍，津航促扣舷。", "雲迷孝王苑，星認太丘躔。", "破瑟弦鵾舞，吟囊錦獸鮮。", "晚淮他夜月，離思共娟娟。"]'),
('ce0839b0-9b95-4d37-bd06-162c5c516615','送王庾  其二','宋祁','宋','宋诗','song-poetry','','[]','倦客衣空化，求知刺欲漫。',48,'全唐诗/poet.song.11000.json','["倦客衣空化，求知刺欲漫。", "孤飛回鷁路，別淚溢鮫盤。", "待舉秋槐老，承顔夏枕安。", "新篇時寄我，魚信接長瀾。"]'),
('e4eceed7-9550-4d93-9d87-125683615c29','送祝熙載','宋祁','宋','宋诗','song-poetry','','[]','昔誓繻仍在，今行綬已新。',48,'全唐诗/poet.song.11000.json','["昔誓繻仍在，今行綬已新。", "春鶑得遷友，夜鶴怨歸人。", "倦枕低潮月，征帆截渚蘋。", "清時偏樂職，寒鼈佐吳醇。"]'),
('c1524ca3-0f18-4678-b9b8-bf3d986cd504','寒食日送李公佐歸漢東','宋祁','宋','宋诗','song-poetry','','[]','有客改南轅，春郊駐祖筵。',48,'全唐诗/poet.song.11000.json','["有客改南轅，春郊駐祖筵。", "罇寒禁火國，風暖浴沂天。", "茂草平無際，殘花慘更妍。", "鹿鳴偕計近，簪盍約初年。"]'),
('57a882f9-3c55-411f-993a-8601f0ddfe2d','送連庶','宋祁','宋','宋诗','song-poetry','','[]','之子遠參卿，勞勞千里行。',48,'全唐诗/poet.song.11000.json','["之子遠參卿，勞勞千里行。", "素衣因客變，華髮看秋生。", "遇鯉頻爲訊，逢蓴試作羹。", "塵埃半通綬，何地免將迎。"]'),
('2cbc7179-48e8-4a84-8233-0dcd3a93ff51','送陳動之','宋祁','宋','宋诗','song-poetry','','[]','綈帙拋蓬觀，軍牙佐柳屯。',48,'全唐诗/poet.song.11000.json','["綈帙拋蓬觀，軍牙佐柳屯。", "伏熊均軾寵，睡貉襲裘溫。", "睢苑寒雲隔，漁撾暝鼓喧。", "帛書無厭數，知有雁爲門。"]'),
('838143d2-f6c7-460f-8375-69df1d2732f3','送梅堯臣','宋祁','宋','宋诗','song-poetry','','[]','祖帟都門路，秋風滿客衣。',48,'全唐诗/poet.song.11000.json','["祖帟都門路，秋風滿客衣。", "臺舟三鷁駛，官舄兩鳬飛。", "鄉思臨波遠，離憂傍酒微。", "不應緣事事，手自廢談圍。"]'),
('5c2c79c3-b695-4b1c-882a-a27d46f55ec6','春暉寓目二首  其一','宋祁','宋','宋诗','song-poetry','','[]','春序倏云晚，高臺芳意多。',48,'全唐诗/poet.song.11000.json','["春序倏云晚，高臺芳意多。", "花成風地纈，鳥作暝林歌。", "樹氣薰繁幄，池文疊細波。", "夾城歸騎散，煙絮徧銅駝。"]'),
('9111e968-5727-46a4-bf03-d53b0623fdfb','春暉寓目二首  其二','宋祁','宋','宋诗','song-poetry','','[]','春意都無幾，還持歡緒歸。',48,'全唐诗/poet.song.11000.json','["春意都無幾，還持歡緒歸。", "游蜂抱蕊去，驚燕失泥飛。", "風下幡幡影，霞留暝暝霏。", "既知瑶席恨，不減欲沾衣。"]'),
('e50aa611-138c-4a6c-9779-c06c9aa3c7dc','累夕大風','宋祁','宋','宋诗','song-poetry','','[]','乘秋萬竅怒，拂野恣離披。',48,'全唐诗/poet.song.11000.json','["乘秋萬竅怒，拂野恣離披。", "祭鳥東門酒，鳴鳶上將旗。", "有誰樵旦暮，無客賦雄雌。", "何用呼號甚，枯桑了不知。"]'),
('8298899a-6465-47fc-8cd4-d8b10a3632ab','武安侯','宋祁','宋','宋诗','song-poetry','','[]','貴甚宮中勢，軒然帝右趨。',48,'全唐诗/poet.song.11000.json','["貴甚宮中勢，軒然帝右趨。", "所貪惟狗馬，寧是學盤盂。", "驕取武庫地，氣凌轅下駒。", "淮南他日語，悔不共嚴誅。"]'),
('467911ed-c1fa-4a56-ba5a-077af38773f7','庭石','宋祁','宋','宋诗','song-poetry','','[]','嗟爾一拳質，塊生天地中。',48,'全唐诗/poet.song.11000.json','["嗟爾一拳質，塊生天地中。", "柱雲蒸作潤，山溜滴成空。", "松蓋何年化，星槎此路窮。", "無邀什襲裹，近出宋臺東。"]'),
('81279b3d-1d64-45af-9a9c-bcadd6143ba7','感秋','宋祁','宋','宋诗','song-poetry','','[]','樂事行將晚，華年怯早衰。',48,'全唐诗/poet.song.11000.json','["樂事行將晚，華年怯早衰。", "翻車壯士速，落葉長年悲。", "別燕風簾靜，驚烏月樹危。", "播精寧有用，皮骨極支離。"]'),
('61193cb8-c506-4334-ae93-41d00f002d01','秋日四首  其一','宋祁','宋','宋诗','song-poetry','','[]','短影悠揚日，薄寒憀慄天。',48,'全唐诗/poet.song.11000.json','["短影悠揚日，薄寒憀慄天。", "林聲蟬后老，陂影雁賓聯。", "悽感客自爾，變衰時適然。", "何須問容鬢，所遇是凋年。"]'),
('bcfd59ba-ff73-4fbe-a59d-f073ef7e9b24','秋日四首  其二','宋祁','宋','宋诗','song-poetry','','[]','客心驚暮節，天意歇餘芳。',48,'全唐诗/poet.song.11000.json','["客心驚暮節，天意歇餘芳。", "蓮罷池收子，榴成露罅房。", "綈袍親故暖，紈扇委空凉。", "庾信真愁否，仍能用斛量。"]'),
('0bf875fc-1c71-4fe6-b6ba-8e2a5796d810','秋日四首  其三','宋祁','宋','宋诗','song-poetry','','[]','禁林成宿忝，愚谷負深歸。',48,'全唐诗/poet.song.11000.json','["禁林成宿忝，愚谷負深歸。", "未識前途遠，容知昨日非。", "巧勞真物役，靜勝乃天機。", "君看琴中意，何嘗在玉徽。"]'),
('c6d09cfc-8f5c-4283-9d11-2204daa34508','秋日四首  其四','宋祁','宋','宋诗','song-poetry','','[]','秋氣颯然爽，宴居差有情。',48,'全唐诗/poet.song.11000.json','["秋氣颯然爽，宴居差有情。", "蠅休几案潔，蟬罷亭臯清。", "溪水照心碧，雲山刮眼明。", "其如歲云晏，天地莽崢嶸。"]'),
('88666864-8d80-46eb-9682-d8c1e1933819','晚發  其一','宋祁','宋','宋诗','song-poetry','','[]','候鼓遥喧岸，行舟逆上湍。',48,'全唐诗/poet.song.11000.json','["候鼓遥喧岸，行舟逆上湍。", "輕煙著波面，斜月罷林端。", "颯沓鳬鷖亂，蒼茫葭葦寒。", "致君何所憚，便道許之官。"]'),
('09d68d13-0870-44a8-a56e-6fe964d2fa76','晚發  其二','宋祁','宋','宋诗','song-poetry','','[]','曉瀨雖能迅，寒波不復揚。',48,'全唐诗/poet.song.11000.json','["曉瀨雖能迅，寒波不復揚。", "林聲散棲鳥，隄影度風檣。", "茲歲方云暮，吾行未遽央。", "病身非汲黯，安敢薄淮陽。"]'),
('00a730d5-8fb8-43e6-b72a-80198be39161','遊海雲寺','宋祁','宋','宋诗','song-poetry','','[]','十里雲邊寺，重驅千騎來。',48,'全唐诗/poet.song.11000.json','["十里雲邊寺，重驅千騎來。", "天形欹野盡，江勢讓山回。", "園竹濃成幄，樓鐘近殷雷。", "斜陽歸鞅促，飛蓋冒輕埃。"]'),
('4a67b46f-2f10-4a8e-8627-e3919a3b27eb','行藥','宋祁','宋','宋诗','song-poetry','','[]','行藥徧城闉，仍逢摇落辰。',48,'全唐诗/poet.song.11000.json','["行藥徧城闉，仍逢摇落辰。", "塢風焦粟罅，園露飽梨津。", "遠水多成浦，高雲自作鱗。", "匕丹無復得，魂斷小山人。"]'),
('884a0564-b289-4d60-9b65-002d9d0c196f','湖上晚矚','宋祁','宋','宋诗','song-poetry','','[]','湖平潦已收，清興暫夷猶。',48,'全唐诗/poet.song.11000.json','["湖平潦已收，清興暫夷猶。", "風舸時摇纜，眠鳬自去洲。", "荒藤依樹老，殘芡聽波浮。", "珍重芣山色，蒼蒼到暝樓。"]'),
('0e0e8593-2b7e-4914-b485-0e0685de541c','答京西提刑張司封次韵','宋祁','宋','宋诗','song-poetry','','[]','乞得二千石，終非循吏才。',48,'全唐诗/poet.song.11000.json','["乞得二千石，終非循吏才。", "霜蓬根易動，籠鳥翅難開。", "夢寤慚封邑，陶埏仰鉉台。", "報言殊麗藻，虛附驛筩回。"]'),
('fceb75a2-ce46-4436-8531-f662cb565ce5','閏月晦日','宋祁','宋','宋诗','song-poetry','','[]','春物都城晚，歡遊一倍慵。',48,'全唐诗/poet.song.11000.json','["春物都城晚，歡遊一倍慵。", "輕風生樹態，暖日淡雲容。", "小閣時翻燕，閒花更少蜂。", "幽襟真濩落，所得是無悰。"]'),
('853836d4-5ede-4c83-915c-4b1bfde51778','贈楞嚴舒上人','宋祁','宋','宋诗','song-poetry','','[]','丈室錦城隈，庭閒地徧苔。',48,'全唐诗/poet.song.11000.json','["丈室錦城隈，庭閒地徧苔。", "飯從香積取，花續少林開。", "講晝經殘葉，禪宵燭委煤。", "無嫌一時學，要是暮雲才。"]'),
('6693a18b-fe57-460a-8959-1f1616434522','柔上人','宋祁','宋','宋诗','song-poetry','','[]','行年踰八十，安坐布金園。',48,'全唐诗/poet.song.11000.json','["行年踰八十，安坐布金園。", "指柏仍餘樹，栽桐遂見孫。", "巖泉晨自濯，經葉夜能翻。", "顧我生多病，勞師默遣言。"]'),
('281ac946-0039-4afe-909b-6dfe6cfb80fc','壽上人南游','宋祁','宋','宋诗','song-poetry','','[]','拂曉鐶鳴月，迎寒毳擁霞。',48,'全唐诗/poet.song.11000.json','["拂曉鐶鳴月，迎寒毳擁霞。", "衆香摩詰飯，五葉祖師花。", "託宿林枝俯，分風夕影斜。", "前期逢晤賞，持對碧雲誇。"]'),
('3d2bc714-9be9-45f2-abc1-0ba12416a395','送梵才長吉還天台','宋祁','宋','宋诗','song-poetry','','[]','歸祴卷蘭芽，城標拂曙霞。',48,'全唐诗/poet.song.11000.json','["歸祴卷蘭芽，城標拂曙霞。", "溪行鷗避錫，巖供馬銜花。", "翠柰經園密，蒼莓渡彴斜。", "暮雲他日合，相望在天涯。"]'),
('bc2dc229-eeaf-4fb6-bd94-11f445dad694','寄藥山長老省賢','宋祁','宋','宋诗','song-poetry','','[]','南方有尊者，卓錫戀林丘。',48,'全唐诗/poet.song.11000.json','["南方有尊者，卓錫戀林丘。", "演法三千界，多聞第一流。", "爐烟熏定几，笋脯供齋甌。", "社約慚成負，霜蓮落幾秋。"]'),
('f88a7dee-f610-4299-b200-84de899fc0dc','訪僧舍','宋祁','宋','宋诗','song-poetry','','[]','近郭一牛鳴，金園界寶繩。',48,'全唐诗/poet.song.11000.json','["近郭一牛鳴，金園界寶繩。", "衆花天作雨，千焰佛傳燈。", "碧柰垂園老，青蓮雜漏凝。", "病襟多俗物，時此訪南能。"]'),
('e15b1d7a-45b7-4c6c-b7b7-ee4a31d2b1a9','寥寥','宋祁','宋','宋诗','song-poetry','','[]','寥寥私沐地，索索晚秋時。',48,'全唐诗/poet.song.11000.json','["寥寥私沐地，索索晚秋時。", "高樹足危響，寒花無媚姿。", "遠砧投會急，昏雁赴行遲。", "撫物能無感，年華及始衰。"]'),
('e7bc238b-bf08-4d21-b0e0-916c1d5cb583','早秋','宋祁','宋','宋诗','song-poetry','','[]','脫葉驚彫歲，翻車送落暉。',48,'全唐诗/poet.song.11000.json','["脫葉驚彫歲，翻車送落暉。", "蔗漿晨渴減，桃簟夜凉歸。", "怨月收紈扇，輕雲怯紵衣。", "沈愁知幾許，带眼不勝圍。"]'),
('7092592e-cad1-42f3-a459-089a18fc396c','山中晚春','宋祁','宋','宋诗','song-poetry','','[]','新火暮春天，窮山寄一廛。',48,'全唐诗/poet.song.11000.json','["新火暮春天，窮山寄一廛。", "畹蘭催酒熟，溪草作茵眠。", "落絮輕無定，殘花淺自憐。", "緇帷談久倦，江上問挐船。"]'),
('1b325159-5560-410b-8ff9-36947c8ad453','早春  其一','宋祁','宋','宋诗','song-poetry','','[]','春來人暗知，何物驗來時。',48,'全唐诗/poet.song.11000.json','["春來人暗知，何物驗來時。", "林暖樹改色，山晴雲弄姿。", "歸鴻高的的，生浪細差差。", "老帥非行樂，劭農一駐旂。"]'),
('21ec32e1-7514-44c1-92a8-f33145f93e21','早春  其二','宋祁','宋','宋诗','song-poetry','','[]','鵾雪鎖平苑，烏風裊迥竿。',48,'全唐诗/poet.song.11000.json','["鵾雪鎖平苑，烏風裊迥竿。", "暖容侵柳動，寒意向梅殘。", "雲薄來無定，天晴望更寬。", "杯霞莫辭醉，朝野日多歡。"]'),
('eeca50ac-5489-4f25-b128-045082a0849e','西園早春二首  其一','宋祁','宋','宋诗','song-poetry','','[]','芳意稍菲菲，春城濃淡暉。',48,'全唐诗/poet.song.11000.json','["芳意稍菲菲，春城濃淡暉。", "霞留早陰住，風遣薄寒歸。", "細溜兼沙漾，初禽隠葉飛。", "要知刀筆暇，文酒得相依。"]'),
('092c1ec2-e515-4190-950f-e79bd233a341','西園早春二首  其二','宋祁','宋','宋诗','song-poetry','','[]','樽酒不常滿，年華祗自春。',48,'全唐诗/poet.song.11000.json','["樽酒不常滿，年華祗自春。", "言歸雖薄澣，業已負良辰。", "野翠欣欣徧，林紅撲撲新。", "其如好風景，料理愛詩人。"]'),
('c04cd6ce-7065-4949-a01f-f0f40001f77b','答翁愈賦卷','宋祁','宋','宋诗','song-poetry','','[]','登高大夫事，感物古詩流。',48,'全唐诗/poet.song.11000.json','["登高大夫事，感物古詩流。", "韵變齊風緩，辭凌漢氣遒。", "恨非雌霓賞，惟祝洞簫求。", "病客無盤玉，琅玕未易酬。"]'),
('262caa1e-6171-4835-ad1f-84477732c694','池上  其一','宋祁','宋','宋诗','song-poetry','','[]','晚矚西池上，池清暑氣微。',48,'全唐诗/poet.song.11000.json','["晚矚西池上，池清暑氣微。", "雲煙互明滅，蒲荇兩因依。", "戲鰋來無定，眠鳬久自飛。", "紛吾刀筆慮，逢此憺忘歸。"]'),
('b4f13ef3-4cb5-4a10-9937-3c71d165591a','池上  其二','宋祁','宋','宋诗','song-poetry','','[]','雨止菰蒲老，風生杜若秋。',48,'全唐诗/poet.song.11000.json','["雨止菰蒲老，風生杜若秋。", "水光晴動日，蓮氣晚薰舟。", "暗塢飛螢出，疏叢白鳥留。", "此時成麗賦，寧減翫游鯈。"]'),
('da2a46db-aede-41cb-be2c-9b5b1f8d82b0','北園池上','宋祁','宋','宋诗','song-poetry','','[]','中園稍蕭槭，日脚凈空埃。',48,'全唐诗/poet.song.11000.json','["中園稍蕭槭，日脚凈空埃。", "寒蝶飛還下，饑鷗去又回。", "林高風攪葉，垣暗雨留苔。", "頗賦高秋興，人非騎省才。"]'),
('255151bd-c462-47a8-9797-01ab939752cc','避暑江瀆祠池','宋祁','宋','宋诗','song-poetry','','[]','溪淺容篙短，舟移覺岸長。',48,'全唐诗/poet.song.11000.json','["溪淺容篙短，舟移覺岸長。", "煙稠芰荷葉，霞熱荔支房。", "技疊參撾鼓，杯寒十饋漿。", "便成逃暑醉，官事底相妨。"]'),
('76cbb950-e66d-4558-b3c3-74cbc74822ce','夏日池上  其一','宋祁','宋','宋诗','song-poetry','','[]','溪流來不近，永日映霞霏。',48,'全唐诗/poet.song.11000.json','["溪流來不近，永日映霞霏。", "水荇自相繚，汀禽無次飛。", "頹沙時損路，幽瀨忽藏磯。", "誰欲留連我，相將日暮歸。"]'),
('6c9dd5fe-e8b1-4bc1-a252-7345bdb8d430','夏日池上  其二','宋祁','宋','宋诗','song-poetry','','[]','獨坐溪堂上，炎天客少過。',48,'全唐诗/poet.song.11000.json','["獨坐溪堂上，炎天客少過。", "紅垂初熟果，碧捲未開荷。", "曳絮雲更塢，摇金日弄波。", "一杯聊自舉，凉意雨前多。"]'),
('6cc51ac3-8ab0-40dd-b162-98a06edd088c','揚雄墨池','宋祁','宋','宋诗','song-poetry','','[]','宅廢經池在，人亡墨溜乾。',48,'全唐诗/poet.song.11000.json','["宅廢經池在，人亡墨溜乾。", "蟾蜍兼滴破，科斗共書殘。", "蠹罷芸猶翠，蒸餘竹自寒。", "他楊無可問，撫物費長嘆。"]'),
('9b5e20cb-14a2-4017-842e-1ee3609a908b','秋熱','宋祁','宋','宋诗','song-poetry','','[]','風物連南國，炎威逼早秋。',48,'全唐诗/poet.song.11000.json','["風物連南國，炎威逼早秋。", "墮飛波上翼，誤喘月中牛。", "雲杼衣全解，冰壺渴未瘳。", "此時班女怨，虛爲素紈愁。"]'),
('f0470ad9-7e45-475c-a745-9ccbc2ef8e97','晚冬行園','宋祁','宋','宋诗','song-poetry','','[]','官舍同山舍，蕭然日杖藜。',48,'全唐诗/poet.song.11000.json','["官舍同山舍，蕭然日杖藜。", "饑鷗守冰沼，寒薺犯蔬畦。", "霜逼晴空迥，霞牽晚照低。", "城鴉棲已定，無事莫驚啼。"]'),
('793fb410-14b3-466a-abd4-c93de87f41af','過惠崇舊居  其一','宋祁','宋','宋诗','song-poetry','','[]','人往名長在，欽風歷故居。',48,'全唐诗/poet.song.11000.json','["人往名長在，欽風歷故居。", "社殘蓮即老，園廢柰仍疏。", "麈憶清談外，雲經合座餘。", "裴回視齋壁，行草暗殘書。"]'),
('8a29464d-f587-4dc0-9ae8-1c2927c75411','過惠崇舊居  其二','宋祁','宋','宋诗','song-poetry','','[]','雖昧平生契，懷賢要可傷。',48,'全唐诗/poet.song.11000.json','["雖昧平生契，懷賢要可傷。", "生涯與薪盡，法意共燈長。", "遺畫空觀貌，殘詩孰補亡。", "神期通一語，無乃困津梁。"]'),
('278cb9df-4989-4082-9ad7-b1157eec967c','和鑒宗遊南禪別墅','宋祁','宋','宋诗','song-poetry','','[]','鹿園開別墅，牛駕此回輪。',48,'全唐诗/poet.song.11000.json','["鹿園開別墅，牛駕此回輪。", "花識莊嚴界，林容宴坐人。", "遠煙時誤晚，靜塢若遺春。", "共照前溪水，煩師洗六塵。"]'),
('dc66bee5-9728-4822-9475-4ad3650afc94','對月  其一','宋祁','宋','宋诗','song-poetry','','[]','林梢霞尾暗，海面月華新。',48,'全唐诗/poet.song.11000.json','["林梢霞尾暗，海面月華新。", "一水開天鑑，千金上佛輪。", "幽巖涵靜桂，潜蚌溢凉津。", "不必姑山去，翛然自玉人。"]'),
('ba0d9f35-bb95-4b1d-be00-9eb86713f0d3','對月  其二','宋祁','宋','宋诗','song-poetry','','[]','月華真可愛，堂上共徘徊。',48,'全唐诗/poet.song.11000.json','["月華真可愛，堂上共徘徊。", "白露方徐貺，清風適共來。", "蚌津隨照滿，烏閣爲啼開。", "萬慮方岑寂，愁看雲漢回。"]'),
('d03bd16b-465a-43d3-bbfe-e1649d6e6d20','望月','宋祁','宋','宋诗','song-poetry','','[]','早月始娟娟，西南寥泬天。',48,'全唐诗/poet.song.11000.json','["早月始娟娟，西南寥泬天。", "魄中藏暗樹，輪外上虛弦。", "傍漢含銀淺，過雲漏葉鮮。", "遥知今夜鵲，猶得穩枝眠。"]'),
('a3899266-553d-4e47-a310-c2df1b5a411f','同小姪珪璞溪上汎舟','宋祁','宋','宋诗','song-poetry','','[]','出郭曉雲霽，泛舟春日遲。',48,'全唐诗/poet.song.11000.json','["出郭曉雲霽，泛舟春日遲。", "詩懷隨物放，酒面任風吹。", "循岸煩鷗起，看山惜棹移。", "州人輕此樂，頼與汝曹期。"]'),
('0fbd4b4d-a841-467f-a2cb-a1f328c6492d','擬明月逐人來','宋祁','宋','宋诗','song-poetry','','[]','玉漏催成夜，蘭釭換作晨。',48,'全唐诗/poet.song.11000.json','["玉漏催成夜，蘭釭換作晨。", "併花排綵樹，分月送遊人。", "醉幕星臨酒，天街露禁塵。", "輕雷與流水，隨意伴香輪。"]'),
('b3a6365a-b8bb-4714-8cc3-c9bd8c50defa','月','宋祁','宋','宋诗','song-poetry','','[]','西顥凉飈度，金樞宿靄收。',48,'全唐诗/poet.song.11000.json','["西顥凉飈度，金樞宿靄收。", "映波休混璧，入幔且迷鈎。", "蚌冷侵珠潤，羅疏逼帳秋。", "風流知不淺，庾令在江樓。"]'),
('126ae8ad-3518-4850-9510-9012d1e19b30','新月','宋祁','宋','宋诗','song-poetry','','[]','幾宵閒北寢，始見映西樓。',48,'全唐诗/poet.song.11000.json','["幾宵閒北寢，始見映西樓。", "曲篆臨鈎誤，殘黄映額羞。", "桂稀山自冷，珠淺蚌兼愁。", "巧作纖纖句，纔能喻兩頭。"]'),
('14dbb51d-aea5-49e5-bdc7-4912c8db6693','殘月','宋祁','宋','宋诗','song-poetry','','[]','陰光隨落宿，有意待朝陽。',48,'全唐诗/poet.song.11000.json','["陰光隨落宿，有意待朝陽。", "暈缺灰餘影，潮平鷺息狂。", "殘兵驕子國，隠語大刀郎。", "此夜方諸淚，寧能減數行。"]'),
('b630724e-b865-4bc3-846f-2e84826a02dd','馬上見殘月','宋祁','宋','宋诗','song-poetry','','[]','娟娟天外月，正見上朝人。',48,'全唐诗/poet.song.11000.json','["娟娟天外月，正見上朝人。", "老桂欹藏樹，纖鈎側抱輪。", "氣清仍泛露，光淡即迎晨。", "尚作裴回意，西樓對結鄰。"]'),
('0ca04b97-89fc-43ac-923a-e1771aebb029','落月','宋祁','宋','宋诗','song-poetry','','[]','已照金樞穴，初乘玉女扉。',48,'全唐诗/poet.song.11000.json','["已照金樞穴，初乘玉女扉。", "望花愁桂老，數葉畏蓂稀。", "漢蚌兼珠隠，邊兵背塞歸。", "持將離妾恨，一問上天飛。"]'),
('de6bfd2c-fea1-4029-84e5-01178313d897','答勸農李淵宗嘉州江行','宋祁','宋','宋诗','song-poetry','','[]','嘉月嘉州路，軻峨按部船。',48,'全唐诗/poet.song.11000.json','["嘉月嘉州路，軻峨按部船。", "山圍杜宇國，江入夜郎天。", "霽引溪樓望，凉供水館眠。", "愧君舟檝意，遂欲濟長川。"]'),
('dade499b-b549-4146-b01a-f6dc7b485927','早發大堰','宋祁','宋','宋诗','song-poetry','','[]','曉戍朧朧白，春流納納深。',48,'全唐诗/poet.song.11000.json','["曉戍朧朧白，春流納納深。", "生煙纔著樹，罷月稍依林。", "野路趨斜岸，漁舠泊暗潯。", "尚緣歸國意，差足慰離襟。"]'),
('efba290c-49bc-4355-9a48-c181634dcde8','新竹','宋祁','宋','宋诗','song-poetry','','[]','最愛中唐竹，春來百箇鮮。',48,'全唐诗/poet.song.11000.json','["最愛中唐竹，春來百箇鮮。", "笋殘霞落泊，梢散粉嬋娟。", "早葉危銜露，昏枝巧住煙。", "寧孤一日賞，況在此君前。"]'),
('79c0db58-ebd4-4daa-a604-a8cb6dc221d7','永興鄭資政鞏縣路逢雪見寄','宋祁','宋','宋诗','song-poetry','','[]','大旆關河遠，同雲天地浮。',48,'全唐诗/poet.song.11000.json','["大旆關河遠，同雲天地浮。", "凌晨逢朔雪，此路向西州。", "寒襲生犀健，光催暢轂流。", "餘清念東郭，穿履趁英游。"]'),
('37cd34b7-48a3-4a3e-b27b-495a28e397f7','峽中逢雪','宋祁','宋','宋诗','song-poetry','','[]','峽內逢霏霰，凌辰望已迷。',48,'全唐诗/poet.song.11000.json','["峽內逢霏霰，凌辰望已迷。", "寒花纔集棧，斜片旋沈溪。", "戶入垂繒壤，田成種玉畦。", "速乾殊未惜，山道潤無泥。"]'),
('0f5ded65-548d-46d1-9499-b3ba37fb8459','冒雪馬上作','宋祁','宋','宋诗','song-poetry','','[]','大雪浹天畿，晨驂望禁扉。',48,'全唐诗/poet.song.11000.json','["大雪浹天畿，晨驂望禁扉。", "二儀連皓氣，萬物共清輝。", "樓迥標銀闕，臺寒壓粉圍。", "瑞花真有意，偏著入朝衣。"]'),
('ca3a6b1c-3f5c-4e49-98c4-5feb91633802','四望亭','宋祁','宋','宋诗','song-poetry','','[]','秋城聊一眺，物色已蒼茫。',48,'全唐诗/poet.song.11000.json','["秋城聊一眺，物色已蒼茫。", "爽籟風驅遠，寒烟晚曳長。", "祠成樗作社，戍罷女留牆。", "要是凋年感，能回倦客腸。"]'),
('be859be4-f4ca-4950-89c3-cf7105b35338','秋日書懷','宋祁','宋','宋诗','song-poetry','','[]','秋旻蕩喧濁，茂宰屬高情。',48,'全唐诗/poet.song.11000.json','["秋旻蕩喧濁，茂宰屬高情。", "水遶溪初浪，林乾籟自聲。", "醉茵留剩暖，歡瑟泛餘清。", "尚念江湖守，其如華髮生。"]'),
('649b8a5b-de04-4d26-9f5b-78d454af4c51','送潘秘校赴潁上簿','宋祁','宋','宋诗','song-poetry','','[]','捧檄去三銓，招招客叩船。',48,'全唐诗/poet.song.11000.json','["捧檄去三銓，招招客叩船。", "倦游驚密雪，離思著幺絃。", "淮月開帆暝，京塵減綬鮮。", "枳鸞非久息，刷羽竚來旋。"]'),
('b4bee2b5-a6af-4edc-9aa8-03f530303bf9','送南頓胡簿','宋祁','宋','宋诗','song-poetry','','[]','密雪妍辭盛，垂窗怒翼開。',48,'全唐诗/poet.song.11000.json','["密雪妍辭盛，垂窗怒翼開。", "聊從百里佐，初露七年材。", "集隼趨侯府，歌驪酧客罍。", "時年無道茀，庇邑邇天臺。"]'),
('195c7b00-6ed3-464f-8afa-ad90691f9f9d','舟中三首  其一','宋祁','宋','宋诗','song-poetry','','[]','舟行不礙動，縱目望聯隄。',48,'全唐诗/poet.song.11000.json','["舟行不礙動，縱目望聯隄。", "稍覺前川近，徐驚後樹低。", "魚游隨聚沫，禽度带殘啼。", "自趣家田路，春清況日携。"]'),
('77ff00aa-ddc8-4c80-8682-f5f9efb4961c','舟中三首  其二','宋祁','宋','宋诗','song-poetry','','[]','漠漠朝煙上，霏霏野氣和。',48,'全唐诗/poet.song.11000.json','["漠漠朝煙上，霏霏野氣和。", "驚鴻自去渚，戲鶩不沈波。", "田畯耕扶耒，溪童食啄蠡。", "紺舟時一眺，䍧踐損春莎。"]'),
('dd43d32e-6f4d-453a-acc5-d9badc668beb','舟中三首  其三','宋祁','宋','宋诗','song-poetry','','[]','霧迥絙林趾，波生齧岸沙。',48,'全唐诗/poet.song.11000.json','["霧迥絙林趾，波生齧岸沙。", "漫紅披杏带，短碧上蒲芽。", "鮭菜隨宜有，漿醪不用賒。", "行行樂蕭散，未覺遠京華。"]'),
('38549d4f-0232-410d-9eba-6be22f6ed93b','物外亭','宋祁','宋','宋诗','song-poetry','','[]','飛宇冠蒼岑，盤盤上百尋。',48,'全唐诗/poet.song.11000.json','["飛宇冠蒼岑，盤盤上百尋。", "風含太虛爽，雲作下方陰。", "塢桂寒仍燠，岩猿暝始吟。", "知君有高興，天壤共登臨。"]'),
('3b7ddbf1-2b78-4be3-ac35-2d387777e8b0','秋日詠庭樹','宋祁','宋','宋诗','song-poetry','','[]','庭樹報秋歸，蕭然芳意衰。',48,'全唐诗/poet.song.11000.json','["庭樹報秋歸，蕭然芳意衰。", "露危陰處葉，風勁暝前枝。", "嘒嘒蟬嘶早，梢梢鵲定遲。", "江潭正摇落，司馬不無悲。"]'),
('ca497e8e-7e91-41b6-8fde-46e2a0a31772','司徒侍中宣獻公挽詞二首  其一','宋祁','宋','宋诗','song-poetry','','[]','斯文推舊德，憂國變華顛。',48,'全唐诗/poet.song.11000.json','["斯文推舊德，憂國變華顛。", "夙夜勞三事，東西止百年。", "溫辭聯冊祕，良史大都傳。", "他日賢臣壠，心知望圃田。"]'),
('9112df6f-453e-48b4-a294-d0eabdccb708','司徒侍中宣獻公挽詞二首  其二','宋祁','宋','宋诗','song-poetry','','[]','美疢交明晦，浮齡詎控摶。',48,'全唐诗/poet.song.11000.json','["美疢交明晦，浮齡詎控摶。", "宗盟一箇弱，人贖百身難。", "賜歛榮絺衮，臨哀駐玉鑾。", "欲知桃李愛，朝紱共汍瀾。"]'),
('8610623d-8026-46dc-ad92-00819bee4bbb','送蒙城簿謝煜先輩','宋祁','宋','宋诗','song-poetry','','[]','曾第飄飄賦，仍勞冉冉趨。',48,'全唐诗/poet.song.11000.json','["曾第飄飄賦，仍勞冉冉趨。", "嘆時三嗅雉，倦別一飛鳬。", "句簿虛公几，迎漿溢里壺。", "異時齎閥閱，明陟在丹塗。"]'),
('8753b919-507f-4722-a25d-b354dce176a8','送江陰簿江楚材先輩','宋祁','宋','宋诗','song-poetry','','[]','黌舍久過從，清言服阿戎。',48,'全唐诗/poet.song.11000.json','["黌舍久過從，清言服阿戎。", "半綸人結綬，一箭水分風。", "行稻鮮原綠，攀花雜樹紅。", "羨君談有助，新論得王充。"]'),
('1bd75167-b3d3-4920-87b0-08b1a24ac695','送炳宗巢簿','宋祁','宋','宋诗','song-poetry','','[]','世德封胡後，英游終賈年。',48,'全唐诗/poet.song.11000.json','["世德封胡後，英游終賈年。", "塵緇去郡客，木落渡淮天。", "揖吏貪持簿，勞歌倦倚弦。", "無憂親釜薄，新復古圭田。"]'),
('0490a869-ed2d-4e74-9ec1-112b8bf282d5','觀相國長城公留題藥師院壁','宋祁','宋','宋诗','song-poetry','','[]','擁節趨瑶縣，回輿禮梵仙。',48,'全唐诗/poet.song.11000.json','["擁節趨瑶縣，回輿禮梵仙。", "望雲催覲日，零雨記歸年。", "蕙露霏毫潤，尼珠入局圓。", "斯人具瞻地，二絕賁金田。"]'),
('f86e39fe-28e3-4ead-b31c-83334be371c7','題玉溪符上人清風閣','宋祁','宋','宋诗','song-poetry','','[]','齋橑翠霏間，人高境自閒。',48,'全唐诗/poet.song.11000.json','["齋橑翠霏間，人高境自閒。", "禪心溪上月，佛髻檻前山。", "晝漏依蓮改，晴雲識棟還。", "誰持快哉意，來此共躋攀。"]'),
('6ac82577-3727-4f37-a16b-327d352b1577','李中令挽詞二首  其一','宋祁','宋','宋诗','song-poetry','','[]','家賜齊侯履，人推郤縠文。',48,'全唐诗/poet.song.11000.json','["家賜齊侯履，人推郤縠文。", "結婚榮外館，謀帥得中軍。", "盛集追園蓋，遒章託隴雲。", "不圖新渚畔，更作死生分。"]'),
('90cfe97b-1c7d-4314-90aa-d84f12d8259a','李中令挽詞二首  其二','宋祁','宋','宋诗','song-poetry','','[]','贈窆充幽隧，鳴簫異素輪。',48,'全唐诗/poet.song.11000.json','["贈窆充幽隧，鳴簫異素輪。", "山丘華屋遠，桃李故蹊春。", "使幕被愁霧，談犀委暗塵。", "須知悟生滅，終得法爲身。"]'),
('a200809f-e59a-4b11-9866-83d5f4247aac','龍巖寺','宋祁','宋','宋诗','song-poetry','','[]','磴齒緣蒼巘，簷牙冒紫氛。',48,'全唐诗/poet.song.11000.json','["磴齒緣蒼巘，簷牙冒紫氛。", "樓鳴穿峽瀨，堂宿抱峰雲。", "鳥散生臺晏，僧歸浴樹曛。", "居然化城地，長與客塵分。"]'),
('a038f771-af12-4782-ad55-b30a70996145','農閣','宋祁','宋','宋诗','song-poetry','','[]','菌閣俯江干，西南蜀塞寬。',48,'全唐诗/poet.song.11000.json','["菌閣俯江干，西南蜀塞寬。", "看雲記巫峽，望日省長安。", "鈿崒峰頭碧，霞皴荔子丹。", "比來秋物好，誰伴數憑欄。"]'),
('4f68d77f-b9ef-42ed-a243-2739a88e9580','聞杜宇','宋祁','宋','宋诗','song-poetry','','[]','傳聞望帝冤，底處最堪憐。',48,'全唐诗/poet.song.11000.json','["傳聞望帝冤，底處最堪憐。", "蜀月將殘夜，巴山欲曉天。", "周軍嘗化鶴，齊后亦爲蟬。", "物變皆如此，非君是偶然。"]'),
('a0654d5f-84d3-467a-adcc-8beee4f6cfe2','春野觀農事','宋祁','宋','宋诗','song-poetry','','[]','茂氣回鮮野，寒姿換故林。',48,'全唐诗/poet.song.11000.json','["茂氣回鮮野，寒姿換故林。", "敗防溪響急，新甽耒痕深。", "乳雉嬉原隩，歌牛下浦陰。", "吾廬堪學稼，將老有初心。"]'),
('7b0f6748-6586-4ef6-a816-aef137e6f803','唐詔監簿池陽市征','宋祁','宋','宋诗','song-poetry','','[]','五鼓歇津亭，風帆去斗城。',48,'全唐诗/poet.song.11000.json','["五鼓歇津亭，風帆去斗城。", "美材王國秀，獨木縣官征。", "萍密浮罌劑，蓴絲雜釜羹。", "袁郎秋詠去，江月對盈盈。"]'),
('29e04741-1288-4df4-b7f7-c2b5352d9e2a','早秋夜坐','宋祁','宋','宋诗','song-poetry','','[]','穹旻炎𡏖歇，顥氣襲中閨。',48,'全唐诗/poet.song.11000.json','["穹旻炎𡏖歇，顥氣襲中閨。", "倦鵲兼河轉，初蟾共月西。", "客愁無處所，世慮足端倪。", "清客纔成泫，皋禽且穩棲。"]'),
('140ae53d-b7ec-4346-8958-b4bfc48880c3','秋日書懷','宋祁','宋','宋诗','song-poetry','','[]','風頭日蕭索，爽氣自西岑。',48,'全唐诗/poet.song.11000.json','["風頭日蕭索，爽氣自西岑。", "暝戍有傳鼓，寒城無罷砧。", "未論鄉思苦，且念歲華侵。", "目羨高高雁，先時到上林。"]'),
('56df449a-e19c-4e5e-b71d-f06b187e0e3a','得伯逢書','宋祁','宋','宋诗','song-poetry','','[]','書來何所道，報我二毛生。',48,'全唐诗/poet.song.11000.json','["書來何所道，報我二毛生。", "種種因年化，星星著領明。", "別離纔幾日，感慨若爲情。", "且莫悲遲暮，須容四海兄。"]'),
('66c6759a-6a44-40b4-be71-7a107e3441bb','伯逢欲予買一田墅因成自訟','宋祁','宋','宋诗','song-poetry','','[]','予從大夫後，祿乃二千餘。',48,'全唐诗/poet.song.11000.json','["予從大夫後，祿乃二千餘。", "簪筆論何事，藏山著底書。", "病教年事早，拙使宦情疏。", "合治菟裘未，蝸牛尚有廬。"]'),
('478c0048-7bae-4225-bf51-d036342addf1','西園晚眺','宋祁','宋','宋诗','song-poetry','','[]','弱柳蒙蒙密，新花衮衮繁。',48,'全唐诗/poet.song.11000.json','["弱柳蒙蒙密，新花衮衮繁。", "貪尋芳蒨遠，遂到落霞昏。", "亭橑銜山靄，池波撼月痕。", "惜春還語客，慎勿訴餘樽。"]'),
('e2a5e2d6-c21e-4eda-83d8-7c0b8d8db27b','李先輩昆仲見過','宋祁','宋','宋诗','song-poetry','','[]','有客過窮巷，門羅日晏開。',48,'全唐诗/poet.song.11000.json','["有客過窮巷，門羅日晏開。", "南州一榻下，平轝二龍來。", "霏雪欣談麈，炊菰乏案杯。", "自慚鄰壁焰，時照不燃灰。"]'),
('e875b38e-2a92-4e43-a529-97510fa458c3','公園','宋祁','宋','宋诗','song-poetry','','[]','幽興足端倪，危橋便見溪。',48,'全唐诗/poet.song.11000.json','["幽興足端倪，危橋便見溪。", "浪輕魚喜擲，山近鳥工啼。", "弱葦披風溆，凉蔬甲雨畦。", "使君來已屢，林下自成蹊。"]'),
('a212344e-9dca-4c3a-81b7-e077a0aa3445','八月十四日夜東軒餞趙同州志元吳陝州沖卿徐潤州君章','宋祁','宋','宋诗','song-poetry','','[]','明月不常值，中秋能暫新。',48,'全唐诗/poet.song.11000.json','["明月不常值，中秋能暫新。", "誰言一堂上，相與異州人。", "適意苦難得，舉杯寧厭頻。", "清光定千里，他日遠相親。"]'),
('0091da0f-bfa0-4d09-97fe-c33252621769','訪隠者因題壁','宋祁','宋','宋诗','song-poetry','','[]','巖徑躡雲層，藤蘿失晦明。',48,'全唐诗/poet.song.11000.json','["巖徑躡雲層，藤蘿失晦明。", "青谿一道士，籃轝兩門生。", "山溜足奔響，松風無罷聲。", "願同沮桀侶，林下耦寒耕。"]'),
('07843c3e-9285-43c4-b3ba-a90f5a9df9d5','哭郭仲微三首  其一','宋祁','宋','宋诗','song-poetry','','[]','倉卒聞嬰疾，何辜遂沒身。',48,'全唐诗/poet.song.11000.json','["倉卒聞嬰疾，何辜遂沒身。", "哭筵同産子，霜寢未亡人。", "冢有邢山舊，天爲京兆鄰。", "想君齎志恨，不使白楊春。"]'),
('f990c75c-af6d-4282-ad46-920ee7a3af18','哭郭仲微三首  其二','宋祁','宋','宋诗','song-poetry','','[]','我作魚符守，君司鳳詔文。',48,'全唐诗/poet.song.11000.json','["我作魚符守，君司鳳詔文。", "他時談笑罷，今日死生分。", "怨涕翻滎浪，悲魂引鄭雲。", "山陽懷舊笛，腸斷不堪聞。"]'),
('8c8cffcc-da55-4025-8f84-fbcb91b0fc54','哭郭仲微三首  其三','宋祁','宋','宋诗','song-poetry','','[]','謝氏雖多女，中郎竟乏兒。',48,'全唐诗/poet.song.11000.json','["謝氏雖多女，中郎竟乏兒。", "人生忽至此，天道果無知。", "一代英才往，千篇故稿遺。", "生平同翰墨，不及鏤豐碑。"]'),
('7ad094b4-88d6-47b1-ab76-5b58fefd51ff','夕坐','宋祁','宋','宋诗','song-poetry','','[]','岸幘坐前楹，天圍極望青。',48,'全唐诗/poet.song.11000.json','["岸幘坐前楹，天圍極望青。", "日華開嶺霧，風影碎池星。", "重露驚棲鶴，幽叢带暗螢。", "塵機心久息，寧待據梧瞑。"]'),
('2128a502-4327-459d-824c-8edff08afc14','西樓夕望','宋祁','宋','宋诗','song-poetry','','[]','炎氛隨日入，岑寂坐遥帷。',48,'全唐诗/poet.song.11000.json','["炎氛隨日入，岑寂坐遥帷。", "倦鶩昏投浦，驚蟬夜去枝。", "桂華兼月破，槎影带星移。", "珍重窗風好，羲人即此時。"]'),
('460835d3-4090-4c4d-9410-916b9d1760dc','偶書','宋祁','宋','宋诗','song-poetry','','[]','悲秋葆髮生，倦客厭離身。',48,'全唐诗/poet.song.11000.json','["悲秋葆髮生，倦客厭離身。", "九奏莊禽眩，千鈞楚俗輕。", "媒勞傷偃蹇，歲晏恨崢嶸。", "誰訝游都久，方歸谷口耕。"]'),
('506b8f2c-ece4-4070-9ebe-6c9a827125ca','答書  其一','宋祁','宋','宋诗','song-poetry','','[]','欒欒餘病骨，踽踽本孤臣。',48,'全唐诗/poet.song.11000.json','["欒欒餘病骨，踽踽本孤臣。", "夷餓懷餐粟，軻居憶徙鄰。", "舊圍寬脅带，鑱刻暗書筠。", "親見揚雄者，容儀不動人。"]'),
('8d7a7565-e09f-43b4-8fd7-39ff34b4ab3b','答書  其二','宋祁','宋','宋诗','song-poetry','','[]','答書牛馬走，卜疏草茅人。',48,'全唐诗/poet.song.11000.json','["答書牛馬走，卜疏草茅人。", "久謝輪囷器，羞言阿堵神。", "觸籠摧勁翮，喣沫瀑窮鱗。", "尚欲求糟粕，心知老斲輪。"]'),
('b8efaa94-f731-4f71-af31-a2014e1995f4','和朱少府苦雨','宋祁','宋','宋诗','song-poetry','','[]','滯淹連春晦，層陰接夜分。',48,'全唐诗/poet.song.11000.json','["滯淹連春晦，層陰接夜分。", "驍壺惟發電，愁棟但生雲。", "里突居無爨，官蛙坐厭聞。", "遥知霖唱罷，客思轉相紛。"]'),
('c569d920-3c70-4ad1-a582-ebd27a73a6ae','歲除','宋祁','宋','宋诗','song-poetry','','[]','彫節真如借，良宵此向闌。',48,'全唐诗/poet.song.11000.json','["彫節真如借，良宵此向闌。", "家儲宿歲酒，鄉送大儺寒。", "舊卉回新物，來情續往歡。", "匆匆餘幾刻，催具五辛盤。"]'),
('ca760890-2dc6-4c04-817d-eeed695c53ba','詠酒壺','宋祁','宋','宋诗','song-poetry','','[]','刻像小蹁躚，無情是所憐。',48,'全唐诗/poet.song.11000.json','["刻像小蹁躚，無情是所憐。", "客歡迎指顧，觴冷寄回旋。", "屢轉疑投節，將休似取妍。", "勞君戢深意，醒者勿須傳。"]'),
('da854b69-89b4-4163-9b6e-1d4346a0bbce','答書','宋祁','宋','宋诗','song-poetry','','[]','經㰅摧無幾，書刀削未休。',48,'全唐诗/poet.song.11000.json','["經㰅摧無幾，書刀削未休。", "胡能反招隠，更欲傍牢愁。", "澌硯寒餘滴，窗燈明映篝。", "子威銷骨盡，何相得封侯。"]'),
('f10269e6-877b-4fb1-871c-8ef32dc3c62d','望仙亭晚眺','宋祁','宋','宋诗','song-poetry','','[]','日晏來憑檻，要知刀筆休。',48,'全唐诗/poet.song.11000.json','["日晏來憑檻，要知刀筆休。", "晚雲山曲岪，麤飯客稽留。", "未覺清言減，猶堪大白浮。", "狂歌誰擊節，只是自摇頭。"]'),
('55b27d54-a038-4fd8-a571-47fc816c9569','明月湖','宋祁','宋','宋诗','song-poetry','','[]','湖色淡無際，月華相與閒。',48,'全唐诗/poet.song.11000.json','["湖色淡無際，月華相與閒。", "臨波雙璧映，照浦一珠還。", "宿火汀洲外，橫烟桑柘間。", "不妨清思劇，舉國盡溪山。"]'),
('32dd9cfb-25e7-495e-86fa-8fd9d7bb3401','晚眺','宋祁','宋','宋诗','song-poetry','','[]','危欄真可倚，極目盡高原。',48,'全唐诗/poet.song.11000.json','["危欄真可倚，極目盡高原。", "雙堠驛邊道，孤烟山下村。", "高風生樹響，寒水落溪痕。", "坐見斜陽盡，歸鴉滿翅昏。"]'),
('8e462064-9694-4a38-9e6b-726b267d59dd','胡同年恢信州弋陽簿','宋祁','宋','宋诗','song-poetry','','[]','籠櫻沈醵宴，津鼓愴離羣。',48,'全唐诗/poet.song.11000.json','["籠櫻沈醵宴，津鼓愴離羣。", "道出東南水，心留西北雲。", "秫田供醖劑，練幅換書裙。", "熛闕方呼俊，歸來竚獻文。"]'),
('fa94c868-edd3-4055-b572-896ab9a83150','黄垍勾建昌簿','宋祁','宋','宋诗','song-poetry','','[]','靈風徹宴巵，十幅曙帆飛。',48,'全唐诗/poet.song.11000.json','["靈風徹宴巵，十幅曙帆飛。", "路入江山國，人兼綵繡衣。", "草堂空岫幌，偃室聽琴徽。", "誰識無雙譽，新從日下歸。"]'),
('3ed27fb1-3ca9-4e61-902e-aa87df6ba607','元處宗安化簿','宋祁','宋','宋诗','song-poetry','','[]','軍府沈千奏，邊城佐一同。',48,'全唐诗/poet.song.11000.json','["軍府沈千奏，邊城佐一同。", "鄉書黄耳遠，客爨扊扅空。", "怨曙羌笳月，嘶寒代馬風。", "未應期會急，平日廢談叢。"]'),
('4b452b8e-a3e6-4cd9-93ae-f747aeba891f','同年毛洵勾簿新建','宋祁','宋','宋诗','song-poetry','','[]','年衰冬集罷，鷁首曉帆催。',48,'全唐诗/poet.song.11000.json','["年衰冬集罷，鷁首曉帆催。", "枳棘非鸞處，膏腴得父才。", "澄江限天闊，孤鶩透霞來。", "此地留清賞，誰同耻宴罍。"]'),
('27a46d97-0317-41b1-88d0-8002d25b7f15','霜宇','宋祁','宋','宋诗','song-poetry','','[]','霜宇澹秋光，崢嶸歇歲芳。',48,'全唐诗/poet.song.11000.json','["霜宇澹秋光，崢嶸歇歲芳。", "地形侵楚庳，渠尾入淮長。", "廥集牛初下，羅稀鳥恣翔。", "病悰多感極，身託茂陵傍。"]'),
('92a6e79e-cb86-44a6-8a0a-1a68311a68e9','季秋十九日追還學士院回舟入都作二首  其一','宋祁','宋','宋诗','song-poetry','','[]','上恩留不遣，仍棹越船回。',48,'全唐诗/poet.song.11000.json','["上恩留不遣，仍棹越船回。", "人忝玉堂署，魚還符節臺。", "危心摧櫓罷，病眼刮雲開。", "讀徧淮南詔，慚非視草才。"]'),
('737eb72c-e439-44d1-8736-a4190992aa5d','季秋十九日追還學士院回舟入都作二首  其二','宋祁','宋','宋诗','song-poetry','','[]','得麾初出守，趨召遽言旋。',48,'全唐诗/poet.song.11000.json','["得麾初出守，趨召遽言旋。", "露藿元傾日，秋槎却上天。", "丹塗容蹇步，星弁許華顛。", "再奏皆聞罷，慚妨此路賢。"]'),
('29cc9f55-c27e-4902-a9e8-c8cb0443c741','古邑二首  其一','宋祁','宋','宋诗','song-poetry','','[]','古邑蓬池上，私居市道鄰。',48,'全唐诗/poet.song.11000.json','["古邑蓬池上，私居市道鄰。", "初拋三釜粟，來作一廛民。", "乞火黔薪突，繙經振隙塵。", "何從復何去，更欲問圓神。"]'),
('c83259ae-4d05-400b-8b4f-6d9b4efb6b41','古邑二首  其二','宋祁','宋','宋诗','song-poetry','','[]','墜雨離邦遠，編蓬僦廡卑。',48,'全唐诗/poet.song.11000.json','["墜雨離邦遠，編蓬僦廡卑。", "人非一國敵，家乏萬錢貲。", "江海嗟漂蕩，乾坤惜變衰。", "此時看落葉，寧翅長年悲。"]');
